: true, similarity: \\"dot_product\\" }, text: { type: \\"text\\" }, metadata: { properties: { id: { type: \\"keyword\\" }, doc_uri: { type: \\"keyword\\" }, doc_type: { type: \\"keyword\\" }, seq: { type: \\"integer\\" }, title: { type: \\"text\\" }, source: { type: \\"keyword\\" } } }, content: { type: \\"text\\" }, chunk_uri: { type: \\"keyword\\" }, doc_uri: { type: \\"keyword\\" }, doc_type: { type: \\"keyword\\" }, seq: { type: \\"integer\\" }, title: { type: \\"text\\" }, source: { type: \\"keyword\\" } } } }) }}","options":{"response":{"response":{"neverError":true}},"timeout":120000}},"id":"b000e9dd-cb1c-455d-9322-a5944abbc04b","name":"Create: ES Index","type":"n8n-nodes-base.httpRequest","typeVersion":4,"position":[8288,3024]},{"parameters":{"jsCode":"// Read Kaiser EOC markdown files from the staging mount.\\n// Parses bold-metadata header format (not YAML frontmatter):\\n//   **Document Type:** Evidence of Coverage\\n//   **Market:** Individual & Family\\n//   **State:** California\\n//   **Source:** https://...\\nconst fs   = require('fs');\\nconst path = require('path');\\nconst cfg  = $('Config').first().json;\\nconst root = cfg.stagingDir;\\n\\nfunction walk(dir) {\\n  let out = [];\\n  for (const e of fs.readdirSync(dir, { withFileTypes: true })) {\\n    const p = path.join(dir, e.name);\\n    if (e.isDirectory()) out = out.concat(walk(p));\\n    else if (e.name.toLowerCase().endsWith('.md')) out.push(p);\\n  }\\n  return out;\\n}\\n\\n// Parse Kaiser markdown: extract bold **Key:** value pairs and first # heading.\\n// Body starts after the first '---' separator line.\\nfunction parseFront(raw) {\\n  const lines = raw.split('\\\\n');\\n  const meta  = {};\\n  let bodyStart = 0;\\n  for (let i = 0; i < lines.length; i++) {\\n    const heading = lines[i].match(/^#\\\\s+(.+)$/);\\n    if (heading && !meta.title) meta.title = heading[1].trim();\\n    const kv = lines[i].match(/^\\\\*\\\\*([^*]+)\\\\*\\\\*:\\\\s*(.+?)\\\\s*$/);\\n    if (kv) meta[kv[1].trim().toLowerCase().replace(/\\\\s+/g, '_')] = kv[2].trim();\\n    if (lines[i].trim() === '---' && i > 2) { bodyStart = i + 1; break; }\\n  }\\n  return { meta, body: lines.slice(bodyStart).join('\\\\n') };\\n}\\n\\nfunction docType(typeStr) {\\n  const t = (typeStr || '').toLowerCase();\\n  if (t.includes('evidence of coverage')) return 'eoc';\\n  if (t.includes('summary of benefits'))  return 'sob';\\n  if (t.includes('formulary'))            return 'formulary';\\n  return 'document';\\n}\\n\\nconst items = [];\\nfor (const f of walk(root)) {\\n  const { meta, body } = parseFront(fs.readFileSync(f, 'utf-8'));\\n  const text = (body || '').trim();\\n  if (!text) continue;\\n  const sourceUrl = meta.source || '';\\n  const doc_uri   = sourceUrl || ('file://' + f);\\n  items.push({ json: {\\n    doc_uri,\\n    doc_type: docType(meta.document_type),\\n    title:    meta.title   || path.basename(f),\\n    source:   sourceUrl    || f,\\n    text,\\n  }});\\n}\\nif (!items.length) throw new Error('No .md documents found under ' + root);\\nreturn items;\\n"},"id":"c4d349f0-40b4-4afa-8ad3-f918497a3b5d","name":"Read: Source Docs","type":"n8n-nodes-base.code","typeVersion":2,"position":[8512,3024]},{"parameters":{"jsCode":"// Two-pass chunking matching the ECB/Chevron splitter, using REAL token counts\\n// via js-tiktoken (cl100k_base). Requires NODE_FUNCTION_ALLOW_EXTERNAL=js-tiktoken.\\nlet getEncoding;\\ntry { ({ getEncoding } = require('js-tiktoken')); }\\ncatch (e) { throw new Error('js-tiktoken not available in this n8n. Add NODE_FUNCTION_ALLOW_EXTERNAL=js-tiktoken and ensure the package is installed in the n8n image. Original: ' + e.message); }\\nconst enc = getEncoding('cl100k_base');\\n\\nconst cfg = $('Config').first().json;\\nconst TOK      = parseInt(cfg.chunkTokens || '512', 10);\\nconst OVL      = parseInt(cfg.chunkTokenOverlap || '100', 10);\\nconst MAXCHARS = parseInt(cfg.chunkMaxChars || '2048', 10);\\nconst SEPS = ['\\\\n\\\\n', '\\\\n', ' ', ''];\\nconst ntok = (s) => enc.encode(s).length;\\n\\n// Greedily pack pieces into <=TOK-token chunks, carrying ~OVL-token overlap.\\nfunction merge(pieces, joiner) {\\n  const jt = joiner ? ntok(joiner) : 0;\\n  const chunks = []; let cur = []; let curTok = 0;\\n  for (const pc of pieces) {\\n    const pt = ntok(pc);\\n    if (curTok && curTok + jt + pt > TOK) {\\n      chunks.push(cur.join(joiner));\\n      let keep = [], kt = 0;\\n      for (let i = cur.length - 1; i >= 0 && kt < OVL; i--) { keep.unshift(cur[i]); kt += ntok(cur[i]) + jt; }\\n      cur = keep; curTok = kt;\\n    }\\n    cur.push(pc); curTok += pt + (cur.length > 1 ? jt : 0);\\n  }\\n  if (cur.length) chunks.push(cur.join(joiner));\\n  return chunks;\\n}\\n\\n// Recursive separator split, measured in tokens (langchain from_tiktoken_encoder behavior).\\nfunction splitRec(text, seps) {\\n  if (ntok(text) <= TOK) return [text];\\n  const sep = seps[0];\\n  if (sep === '') {                 // last resort: slice the token stream directly\\n    const toks = enc.encode(text); const out = [];\\n    for (let s = 0; s < toks.length; s += (TOK - OVL)) {\\n      out.push(enc.decode(toks.slice(s, s + TOK)));\\n      if (s + TOK >= toks.length) break;\\n    }\\n    return out;\\n  }\\n  const expanded = [];\\n  for (const piece of text.split(sep)) {\\n    if (ntok(piece) > TOK) expanded.push(...splitRec(piece, seps.slice(1)));\\n    else expanded.push(piece);\\n  }\\n  return merge(expanded, sep);\\n}\\n\\n// Pass 2 — character safety cap (chars, not tokens) like Chevron's char_splitter.\\nfunction charCap(text) {\\n  if (text.length <= MAXCHARS) return [text];\\n  const out = []; let buf = '';\\n  for (const w of text.split(/(\\\\s+)/)) {\\n    if (buf && (buf + w).length > MAXCHARS) { out.push(buf.trim()); buf = ''; }\\n    buf += w;\\n  }\\n  if (buf.trim()) out.push(buf.trim());\\n  return out;\\n}\\n\\nconst out = [];\\nlet _docIdx = 0;\\nfor (const it of $input.all()) {\\n  // Yield to the event loop every 25 docs so the task-runner heartbeat can fire\\n  // during this CPU-bound tokenize pass (prevents \\"runner became unresponsive\\").\\n  if ((_docIdx++ % 25) === 0) await new Promise(r => setImmediate(r));\\n  const d = it.json;\\n  const pass1 = ntok(d.text) <= TOK ? [d.text] : splitRec(d.text, SEPS);\\n  const finalChunks = [];\\n  for (const c of pass1) finalChunks.push(...charCap(c));\\n  finalChunks.map(t => t.trim()).filter(t => t.length).forEach((t, seq) => {\\n    const chunk_uri = d.doc_uri.replace(/\\\\/+$/, '') + '/chunk/' + String(seq).padStart(4, '0');\\n    out.push({ json: {\\n      chunk_uri, doc_uri: d.doc_uri, doc_type: d.doc_type,\\n      title: d.title, source: d.source, seq, text: t,\\n    }});\\n  });\\n}\\nreturn out;\\n"},"id":"a560236c-1ad1-4797-a581-9e11c3ac9c4d","name":"Chunk","type":"n8n-nodes-base.code","typeVersion":2,"position":[8528,3360]},{"parameters":{"jsCode":"// Embed each chunk via AWS Bedrock Titan v2 (SigV4) and INDEX it to Elasticsearch\\n// in batches right here. The 1024-float vector is written to ES at this step and\\n// NOT returned as item data — only lightweight chunk metadata flows onward, so\\n// n8n's execution stays small. Runs \\"Once for All Items\\".\\n//\\n// No cross-run cache: every run re-embeds every chunk. An earlier version kept a\\n// vector cache file across runs to skip re-embedding on retry, but that file grew\\n// without bound as the corpus/rerun history grew and eventually exceeded V8's\\n// ~1.07B-char string limit (RangeError: Invalid string length) trying to persist\\n// it. Re-embedding is cheap relative to debugging that failure mode, so it's gone.\\n// Dedup below is scoped to THIS run only — identical text within one run (e.g.\\n// repeated document boilerplate) still only gets embedded once.\\nconst crypto = require('crypto');\\nconst https  = require('https');\\nconst cfg = $('Config').first().json;\\n\\nconst region  = cfg.embedRegion || 'us-west-2';\\nconst service = 'bedrock';        // SigV4 signing service is 'bedrock' (host is bedrock-runtime)\\nconst ak = cfg.awsAccessKeyId, sk = cfg.awsSecretAccessKey;\\nif (!ak || !sk) throw new Error('awsAccessKeyId / awsSecretAccessKey are empty in the Config node.');\\n\\nconst host        = `bedrock-runtime.${region}.amazonaws.com`;\\nconst modelId     = cfg.embedModelId;\\nconst dim         = Number(cfg.embedDim);\\nconst CONCURRENCY = Number(cfg.embedConcurrency) || 8;\\n\\nconst sha256hex = s => crypto.createHash('sha256').update(s, 'utf8').digest('hex');\\n// Key folds in model + dim so switching either never reuses a mismatched vector.\\nconst keyOf = text => sha256hex(`${modelId}|${dim}|${text}`);\\n\\n// One signed Bedrock embed HTTP call — no retry (see embedOne below).\\nasync function embedOnce(text) {\\n  const payload  = JSON.stringify({ inputText: text, dimensions: dim, normalize: true });\\n  // Bedrock SigV4: the wire path uses single-encoded model ID (%3A), but the\\n  // canonical string must double-encode it (%253A) because AWS re-encodes the\\n  // already-encoded wire path when verifying the signature.\\n  const modelEnc      = encodeURIComponent(modelId);                    // ':' -> '%3A' (wire path)\\n  const path          = `/model/${modelEnc}/invoke`;\\n  const canonicalPath = `/model/${encodeURIComponent(modelEnc)}/invoke`; // '%3A' -> '%253A' (SigV4)\\n  const hmac = (k, s) => crypto.createHmac('sha256', k).update(s, 'utf8').digest();\\n  const amzdate   = new Date().toISOString().replace(/[:-]|\\\\.\\\\d{3}/g, '');\\n  const datestamp = amzdate.slice(0, 8);\\n  const payloadHash = sha256hex(payload);\\n  const canonicalHeaders =\\n    `content-type:application/json\\\\nhost:${host}\\\\nx-amz-content-sha256:${payloadHash}\\\\nx-amz-date:${amzdate}\\\\n`;\\n  const signedHeaders = 'content-type;host;x-amz-content-sha256;x-amz-date';\\n  const canonicalRequest = ['POST', canonicalPath, '', canonicalHeaders, signedHeaders, payloadHash].join('\\\\n');\\n  const scope = `${datestamp}/${region}/${service}/aws4_request`;\\n  const stringToSign = ['AWS4-HMAC-SHA256', amzdate, scope, sha256hex(canonicalRequest)].join('\\\\n');\\n  let key = hmac('AWS4' + sk, datestamp);\\n  key = hmac(key, region); key = hmac(key, service); key = hmac(key, 'aws4_request');\\n  const signature = crypto.createHmac('sha256', key).update(stringToSign, 'utf8').digest('hex');\\n  const authorization =\\n    `AWS4-HMAC-SHA256 Credential=${ak}/${scope}, SignedHeaders=${signedHeaders}, Signature=${signature}`;\\n\\n  return await new Promise((resolve) => {\\n    const req = https.request({ host, path, method: 'POST', timeout: 20000, headers: {\\n      'Content-Type': 'application/json',\\n      'X-Amz-Date': amzdate,\\n      'X-Amz-Content-Sha256': payloadHash,\\n      'Authorization': authorization,\\n      'Content-Length': Buffer.byteLength(payload),\\n    }}, (res) => { let d = ''; res.on('data', c => d += c); res.on('end', () => resolve({ status: res.statusCode, body: d })); });\\n    req.on('timeout', () => req.destroy(new Error('socket timeout after 20s')));\\n    req.on('error', e => resolve({ status: 0, body: 'https.request: ' + e.message }));\\n    req.write(payload); req.end();\\n  });\\n}\\n\\n// Retryable Bedrock exceptions, by their documented HTTP status: 408\\n// (ModelTimeoutException), 424 (ModelErrorException — e.g. \\"The system\\n// encountered an unexpected error during processing. Try your request again.\\"),\\n// 429 (ThrottlingException/ModelNotReadyException), 5xx (InternalServerException/\\n// ServiceUnavailableException), or 0 for a network-level failure. All of these\\n// occur periodically under sustained load — AWS's own guidance (and, for 424,\\n// AWS's own error text) is to retry with backoff, not treat them as fatal. A\\n// genuine validation/auth/not-found error (400/403/404, etc.) is NOT retried and\\n// fails immediately.\\nconst RETRYABLE_STATUS = s => s === 0 || s === 408 || s === 424 || s === 429 || (s >= 500 && s < 600);\\nconst backoffMs = (attempt, base = 500, cap = 15000) => Math.min(cap, base * 2 ** (attempt - 1));\\nconst sleep = (ms) => new Promise(r => setTimeout(r, ms));\\n\\nasync function embedOne(text, maxAttempts = 6) {\\n  let lastErr;\\n  for (let attempt = 1; attempt <= maxAttempts; attempt++) {\\n    const result = await embedOnce(text);\\n    if (result.status >= 200 && result.status < 300) {\\n      const vector = JSON.parse(result.body).embedding;\\n      if (!Array.isArray(vector)) throw new Error('Bedrock returned no embedding array');\\n      return vector;\\n    }\\n    lastErr = new Error('Bedrock HTTP ' + result.status + ': ' + String(result.body).slice(0, 300));\\n    if (!RETRYABLE_STATUS(result.status) || attempt === maxAttempts) throw lastErr;\\n    const wait = backoffMs(attempt);\\n    console.log(`[embed] Bedrock HTTP ${result.status} (attempt ${attempt}/${maxAttempts}) — retrying in ${wait}ms`);\\n    await sleep(wait);\\n  }\\n  throw lastErr;\\n}\\n\\nconst chunks = $input.all().map(i => i.json);\\n\\n// Dedupe identical text WITHIN this run only, so repeated boilerplate (e.g. the\\n// same header/footer across many chunks) is embedded once instead of once per\\n// occurrence. Nothing here is persisted — it's gone once this execution ends.\\nconst textByKey = {};\\nfor (const c of chunks) { const k = keyOf(c.text); if (!(k in textByKey)) textByKey[k] = c.text; }\\nconst uniqueKeys = Object.keys(textByKey);\\nconst vectors = {};\\n\\nconsole.log(`[embed] ${chunks.length} chunks: ${chunks.length - uniqueKeys.length} duplicate (deduped this run), ${uniqueKeys.length} to embed (concurrency ${CONCURRENCY})`);\\n\\n// Bounded-concurrency embedding of the unique texts.\\nlet cursor = 0, done = 0;\\nasync function worker() {\\n  while (true) {\\n    const i = cursor++;\\n    if (i >= uniqueKeys.length) return;\\n    const k = uniqueKeys[i];\\n    vectors[k] = await embedOne(textByKey[k]);   // throws on hard error\\n    done++;\\n    if (done % 100 === 0) console.log(`[embed] ${done}/${uniqueKeys.length} embedded`);\\n  }\\n}\\nawait Promise.all(Array.from({ length: Math.min(CONCURRENCY, uniqueKeys.length) }, worker));\\n\\n// ── Index to Elasticsearch in batches — the vector is consumed HERE and never\\n//    leaves this node. Each bulk batch is a bounded string (no whole-corpus blob).\\nconst idx = cfg.esIndex;\\nconst esMod = cfg.esUrl.startsWith('https') ? https : require('http');\\nconst esHost = cfg.esUrl.replace(/^https?:\\\\/\\\\//, '').replace(/\\\\/.*$/, '');\\nconst [esHostname, esPort] = esHost.split(':');\\nconst ES_BATCH = Number(cfg.esBatchSize) || 500;\\nfunction postBulk(ndjson) {\\n  const body = Buffer.from(ndjson, 'utf-8');\\n  return new Promise((resolve) => {\\n    const req = esMod.request({\\n      hostname: esHostname, port: Number(esPort) || 9200, path: '/_bulk', method: 'POST',\\n      timeout: 120000, headers: { 'Content-Type': 'application/x-ndjson', 'Content-Length': body.length },\\n    }, (res) => { let d = ''; res.on('data', c => d += c); res.on('end', () => resolve({ status: res.statusCode, body: d })); });\\n    req.on('timeout', () => req.destroy(new Error('ES socket timeout after 120s')));\\n    req.on('error', e => resolve({ status: 0, body: 'request: ' + e.message }));\\n    req.write(body); req.end();\\n  });\\n}\\n\\nlet indexed = 0, esErrors = 0;\\nfor (let s = 0; s < chunks.length; s += ES_BATCH) {\\n  const slice = chunks.slice(s, s + ES_BATCH);\\n  let ndjson = '';\\n  for (const c of slice) {\\n    const vector = vectors[keyOf(c.text)];\\n    if (!Array.isArray(vector)) throw new Error('No vector resolved for ' + c.chunk_uri);\\n    ndjson += JSON.stringify({ index: { _index: idx, _id: c.chunk_uri } }) + '\\\\n';\\n    ndjson += JSON.stringify({\\n      embedding: vector, content: c.text, chunk_uri: c.chunk_uri,\\n      doc_uri: c.doc_uri, doc_type: c.doc_type, seq: c.seq, title: c.title, source: c.source,\\n      // engine-compatible fields (elasticsearch_native preset: text / metadata.id).\\n      text: c.text, metadata: { id: c.chunk_uri },\\n    }) + '\\\\n';\\n  }\\n  const r = await postBulk(ndjson);\\n  if (r.status < 200 || r.status >= 300) { esErrors++; console.log(`[es] batch HTTP ${r.status}: ${String(r.body).slice(0, 200)}`); }\\n  else { try { if (JSON.parse(r.body).errors) { esErrors++; console.log('[es] batch reported item errors'); } } catch (e) {} indexed += slice.length; }\\n  console.log(`[es] indexed ${Math.min(s + ES_BATCH, chunks.length)}/${chunks.length}`);\\n}\\nif (esErrors) throw new Error(`ES bulk had ${esErrors} batch error(s) — see node logs`);\\n\\n// Pass ONLY lightweight chunk metadata onward (NO vector) → the next node mirrors\\n// the chunks into GraphDB, and n8n's execution data stays small.\\nreturn chunks.map(c => ({ json: {\\n  chunk_uri: c.chunk_uri, doc_uri: c.doc_uri, doc_type: c.doc_type,\\n  seq: c.seq, title: c.title, source: c.source, text: c.text,\\n} }));"},"id":"3f8d7767-5d0d-4422-a8ca-e5c52372074b","name":"Embed + Index","type":"n8n-nodes-base.code","typeVersion":2,"position":[8800,3424]},{"parameters":{"jsCode":"// Build the GraphDB chunk Turtle from the lightweight chunk items (the vectors were\\n// already indexed to Elasticsearch by the Embed + Index node — the graph mirror\\n// needs none of them: kpkg:vectorId stores the chunk URI, i.e. the ES _id).\\nconst cfg   = $('Config').first().json;\\nconst items = $input.all().map(i => i.json);\\n\\nconst esc = s => String(s).replace(/\\\\\\\\/g, '\\\\\\\\\\\\\\\\').replace(/\\"/g, '\\\\\\\\\\"').replace(/\\\\r/g, '\\\\\\\\r').replace(/\\\\n/g, '\\\\\\\\n').replace(/\\\\t/g, '\\\\\\\\t');\\nlet ttl = (cfg.prefixes || '') + '\\\\n';\\nfor (const c of items) {\\n  ttl += `<${c.doc_uri}> kpkg:hasChunk <${c.chunk_uri}> .\\\\n`;\\n  ttl += `<${c.chunk_uri}> a kpkg:Chunk ; kpkg:fromDocument <${c.doc_uri}> ; ` +\\n         `kpkg:chunkSequence ${c.seq} ; kpkg:vectorId \\"${esc(c.chunk_uri)}\\" ; ` +\\n         `kpkg:chunkText \\"${esc(c.text)}\\" .\\\\n`;\\n}\\nreturn [{ json: { count: items.length, ttl } }];\\n"},"id":"41ad6e05-f220-4331-8155-3b51d2875c40","name":"Build: Chunk TTL","type":"n8n-nodes-base.code","typeVersion":2,"position":[9008,3264]},{"parameters":{"method":"POST","url":"={{ $('Config').first().json.graphdb }}","sendQuery":true,"queryParameters":{"parameters":[{"name":"context","value":"={{ '<' + $('Config').first().json.chunksGraph + '>' }}"}]},"sendHeaders":true,"headerParameters":{"parameters":[{"name":"Content-Type","value":"text/turtle"}]},"sendBody":true,"contentType":"raw","rawContentType":"text/turtle","body":"={{ $('Build: Chunk TTL').first().json.ttl }}","options":{"timeout":120000}},"id":"96a3d6fc-1032-4ce9-84ce-b3a80fc3e70c","name":"Load: Chunks → GraphDB","type":"n8n-nodes-base.httpRequest","typeVersion":4,"position":[9232,3424]},{"parameters":{"jsCode":"const cfg = $('Config').first().json;\\nreturn [{ json: {\\n  workflow: 'Unstructured Ingest',\\n  status: 'completed',\\n  batch_size: Number(cfg.batchSize) || 1000,\\n  elasticsearch_index: cfg.esIndex,\\n  graphdb_chunks_graph: cfg.chunksGraph,\\n  note: 'All chunks embedded and indexed to Elasticsearch in batches of ' + (cfg.batchSize || '1000') + '; chunk triples loaded into GraphDB in the same batches. Run the Extractor workflow to tag chunks with KP taxonomy concepts.',\\n} }];"},"id":"494a8990-d2d4-4a1a-80ec-ba217e85f71f","name":"Summary","type":"n8n-nodes-base.code","typeVersion":2,"position":[8944,3088]},{"parameters":{"batchSize":"={{ Number($('Config').first().json.batchSize) || 1000 }}","options":{}},"id":"b0140813-faaa-4634-8cb0-c966ffe0b9ef","name":"Split In Batches","type":"n8n-nodes-base.splitInBatches","typeVersion":3,"position":[8288,3280]}]	{"Start":{"main":[[{"node":"Config","type":"main","index":0}]]},"Config":{"main":[[{"node":"Create: ES Index","type":"main","index":0}]]},"Create: ES Index":{"main":[[{"node":"Read: Source Docs","type":"main","index":0}]]},"Read: Source Docs":{"main":[[{"node":"Split In Batches","type":"main","index":0}]]},"Chunk":{"main":[[{"node":"Embed + Index","type":"main","index":0}]]},"Split In Batches":{"main":[[{"node":"Summary","type":"main","index":0}],[{"node":"Chunk","type":"main","index":0}]]},"Embed + Index":{"main":[[{"node":"Build: Chunk TTL","type":"main","index":0}]]},"Build: Chunk TTL":{"main":[[{"node":"Load: Chunks → GraphDB","type":"main","index":0}]]},"Load: Chunks → GraphDB":{"main":[[{"node":"Split In Batches","type":"main","index":0}]]}}	2026-06-27 21:59:37.167+00	2026-07-08 04:53:08.852+00	{"executionOrder":"v1","binaryMode":"separate"}	\N	{}	b182d717-13c2-4048-980b-c5cae579ccdd	0	dRxdokaOb51ePOpf	\N	\N	f	107	\N	\N	[]
My workflow	f	[{"parameters":{"content":"## Backup Worflows & Credentials to Drive\\nConfigure \\"Init\\" node in 2 sections.\\n### Workflow Standard Configuration\\n```\\n// Admin email for notifications\\nconst N8N_ADMIN_EMAIL = $env.N8N_ADMIN_EMAIL || 'youremail@world.com';\\n   \\n// Workflow name (auto-detected)\\nconst WORKFLOW_NAME = $workflow.name;\\n   \\n// Projects root directory on your server (see file structure in node)\\nconst N8N_PROJECTS_DIR = $env.N8N_PROJECTS_DIR || '/files/n8n-projects-data';\\n   \\n// Project folder name for this backup workflow\\nconst PROJECT_FOLDER_NAME = \\"Workflow-backups\\";  // ⚠️ Your project folder name\\n```\\n### Workflow Custom Configuration\\n```\\n// Base backup path using your Docker and FTP volume configuration (folder must exist)\\nconst BACKUP_FOLDER = $env.N8N_BACKUP_FOLDER || '/files/n8n-backups'; // ⚠️ Change the default value for your n8n backup folder\\nconst FTP_BACKUP_FOLDER = $env.N8N_FTP_BACKUP_FOLDER || '/n8n-backups';\\nconst FTPName = 'Your FTP Server Name'; // FTP server name for logging (display purposes only)\\n \\nconst credentials_backup_folder = \\"n8n-credentials\\"; // Credentials backup path\\n```","height":528,"width":1264},"id":"98a571b5-d986-43fc-8903-605cb21bcedd","name":"Sticky Note","type":"n8n-nodes-base.stickyNote","position":[384,-240],"typeVersion":1},{"parameters":{"content":"## Initialisation","height":832,"width":624,"color":4},"id":"c012bc78-169d-48a8-9d81-fc3efa92f26d","name":"Sticky Note2","type":"n8n-nodes-base.stickyNote","position":[384,352],"typeVersion":1},{"parameters":{"content":"## Credentials’ backup & FTP upload","height":272,"width":1232,"color":3},"id":"84c9a482-0ee1-47a2-a5ea-496db44aa6d7","name":"Sticky Note3","type":"n8n-nodes-base.stickyNote","position":[1072,352],"typeVersion":1},{"parameters":{"content":"## Workflows’ backup & FTP upload","height":496,"width":1232,"color":5},"id":"588c64e7-7cd3-4a0e-a3f9-bc44ab1bfe79","name":"Sticky Note5","type":"n8n-nodes-base.stickyNote","position":[1072,688],"typeVersion":1},{"parameters":{"content":"## Finalisation","height":832,"width":816,"color":6},"id":"de893676-e8b8-4062-84d4-d212bec697f3","name":"Sticky Note6","type":"n8n-nodes-base.stickyNote","position":[2368,352],"typeVersion":1},{"parameters":{"jsCode":"// Generate backup summary and statistics with binary data for log file\\n// ✅ Enhanced to handle both credentials and workflows FTP upload results\\n// ✅ Adapted for Aggregate + Merge structure\\n// ✅ Handles disabled FTP nodes gracefully\\n\\n// ⚠️ CONFIGURE THIS NODE WITH:\\n// SETTINGS > ON ERROR > CONTINUE (USING ERROR OUTPUT)\\n\\nconst allItems = $input.all();\\nconst summaryDataInput = $(\\"Init\\").first().json;\\n\\nconsole.log('[Backup Summary] Total items received:', allItems.length);\\n\\n// Separate different data types from Merge\\nconst credentialsFtpItems = allItems.filter(item => \\n  item.json.credentialsFtpUpload !== undefined\\n);\\n\\nconst workflowsFtpItems = allItems.filter(item => \\n  item.json.workflowsFtpUpload !== undefined\\n);\\n\\nconst aggregatedWorkflowItems = allItems.filter(item => \\n  item.json.workflows !== undefined\\n);\\n\\nconsole.log('[Backup Summary] Credentials FTP items:', credentialsFtpItems.length);\\nconsole.log('[Backup Summary] Workflows FTP items:', workflowsFtpItems.length);\\nconsole.log('[Backup Summary] Aggregated workflow items:', aggregatedWorkflowItems.length);\\n\\n// Get credentials FTP upload data\\nconst credentialsFtpData = credentialsFtpItems.length > 0 ? \\n  credentialsFtpItems[0].json.credentialsFtpUpload : null;\\n\\n// Get workflows FTP upload data\\nconst workflowsFtpData = workflowsFtpItems.length > 0 ? \\n  workflowsFtpItems[0].json.workflowsFtpUpload : null;\\n\\n// Get aggregated workflows data\\nconst workflowsData = aggregatedWorkflowItems.length > 0 ? \\n  aggregatedWorkflowItems[0].json.workflows : [];\\n\\n// Get original workflow count from Fetch Workflows node\\nconst workflows = $(\\"Fetch Workflows\\").all();\\nconst totalWorkflows = workflows.length;\\n\\nconsole.log('[Backup Summary] Total workflows fetched:', totalWorkflows);\\nconsole.log('[Backup Summary] Aggregated workflows found:', workflowsData.length);\\nconsole.log('[Backup Summary] Credentials FTP data found:', credentialsFtpData !== null);\\nconsole.log('[Backup Summary] Workflows FTP data found:', workflowsFtpData !== null);\\n\\n// Get credentials export result directly from the Export Credentials node\\nconst credentialsResult = $(\\"Export Credentials\\").first()?.json || null;\\n\\n// Process workflow data from aggregated structure with binary data\\nconst successfulWrites = [];\\nconst failedWrites = [];\\nlet totalSize = 0;\\n\\n// Get aggregated item with binary data\\nconst aggregatedItem = aggregatedWorkflowItems[0];\\nconst binaryData = aggregatedItem?.binary || {};\\n\\n// Since we have aggregated data, we assume all workflows were written successfully\\n// (failed writes would have been caught by error handling in previous nodes)\\nworkflowsData.forEach((workflowFile, index) => {\\n  const fileName = workflowFile.fileName;\\n  const workflowName = fileName ? fileName.split('/').pop().replace('.json', '') : `workflow_${index + 1}`;\\n  \\n  // Try to match with original workflow data to get more details\\n  const originalWorkflow = workflows.find(w => {\\n    const cleanedName = workflowName.replace(/[^a-zA-Z0-9]/g, '_');\\n    return w.json.cleanedFileName === cleanedName || \\n           w.json.name === workflowName;\\n  });\\n  \\n  const nodesCount = originalWorkflow ? \\n    (originalWorkflow.json.nodes ? originalWorkflow.json.nodes.length : 0) : 0;\\n  \\n  // Get real file size from binary data\\n  let actualSize = 0;\\n  const binaryKey = `data_${index}` || `data${index + 1}` || Object.keys(binaryData)[index];\\n  \\n  if (binaryData[binaryKey] && binaryData[binaryKey].data) {\\n    // Calculate size from base64 data (base64 is ~33% larger than original)\\n    const base64Data = binaryData[binaryKey].data;\\n    actualSize = Math.floor(base64Data.length * 0.75); // Convert base64 length to actual bytes\\n  }\\n  \\n  console.log(`[Backup Summary] Workflow ${workflowName}: ${actualSize} bytes`);\\n  \\n  successfulWrites.push({\\n    fileName: fileName,\\n    workflowName: workflowName,\\n    filePath: fileName,\\n    contentSize: actualSize,\\n    nodesCount: nodesCount\\n  });\\n  \\n  totalSize += actualSize;\\n});\\n\\nconsole.log(`[Backup Summary] Processed ${successfulWrites.length} successful workflow writes`);\\n\\n// Use time data from Init node instead of recalculating\\nconst initTimeData = summaryDataInput.timeData;\\nconst endTime = new Date();\\nconst startTime = new Date(initTimeData.startTime);\\nconst durationSeconds = Math.round((endTime.getTime() - startTime.getTime()) / 1000);\\n\\n// Process credentials export result\\nconst credentialsExportSuccess = credentialsResult && \\n  credentialsResult.exitCode !== undefined && \\n  credentialsResult.exitCode === 0;\\n\\nconst credentialsExport = {\\n  attempted: credentialsResult !== null,\\n  success: credentialsExportSuccess,\\n  exitCode: credentialsResult?.exitCode,\\n  message: credentialsExportSuccess ? \\n    'Credentials exported successfully' : \\n    `Credentials export failed with exit code ${credentialsResult?.exitCode}`,\\n  stdout: credentialsResult?.stdout || '',\\n  stderr: credentialsResult?.stderr || ''\\n};\\n\\n// Process credentials FTP upload results with disabled node detection\\nconst credentialsFtpSuccess = credentialsFtpData && \\n  credentialsFtpData.summary && \\n  credentialsFtpData.summary.overallSuccess;\\n\\nconst credentialsFtpUpload = {\\n  attempted: credentialsFtpData !== null,\\n  disabled: credentialsFtpData === null,\\n  success: credentialsFtpSuccess,\\n  totalFiles: credentialsFtpData?.totalFiles || 0,\\n  successfulUploads: credentialsFtpData?.successfulUploads || 0,\\n  failedUploads: credentialsFtpData?.failedUploads || 0,\\n  message: credentialsFtpData === null ? \\n    '⚠️ Warning: no FTP data received (node likely disabled)' :\\n    (credentialsFtpSuccess ? \\n      credentialsFtpData.summary.summary :\\n      credentialsFtpData?.summary?.summary || 'Credentials FTP upload failed')\\n};\\n\\n// Process workflows FTP upload results with disabled node detection\\nconst workflowsFtpSuccess = workflowsFtpData && \\n  workflowsFtpData.summary && \\n  workflowsFtpData.summary.overallSuccess;\\n\\nconst workflowsFtpUpload = {\\n  attempted: workflowsFtpData !== null,\\n  disabled: workflowsFtpData === null,\\n  success: workflowsFtpSuccess,\\n  totalFiles: workflowsFtpData?.totalFiles || 0,\\n  successfulUploads: workflowsFtpData?.successfulUploads || 0,\\n  failedUploads: workflowsFtpData?.failedUploads || 0,\\n  message: workflowsFtpData === null ? \\n    '⚠️ Warning: no FTP data received (node likely disabled)' :\\n    (workflowsFtpSuccess ? \\n      workflowsFtpData.summary.summary :\\n      workflowsFtpData?.summary?.summary || 'Workflows FTP upload failed')\\n};\\n\\nconsole.log('[Backup Summary] Credentials export status:', credentialsExport.success ? '✅ Success' : '❌ Failed');\\nconsole.log('[Backup Summary] Credentials FTP status:', credentialsFtpUpload.disabled ? '⚠️ Disabled' : (credentialsFtpUpload.success ? '✅ Success' : '❌ Failed'));\\nconsole.log('[Backup Summary] Workflows FTP status:', workflowsFtpUpload.disabled ? '⚠️ Disabled' : (workflowsFtpUpload.success ? '✅ Success' : '❌ Failed'));\\nconsole.log(`[Backup Summary] Final counts - Successful: ${successfulWrites.length}, Failed: ${failedWrites.length}`);\\n\\n// Create a backupSummary structure\\nconst backupSummary = {\\n  totalWorkflows: totalWorkflows,\\n  errorCount: failedWrites.length,\\n  errors: failedWrites.map(fail => ({\\n    workflowName: fail.workflowName,\\n    error: fail.error\\n  }))\\n};\\n\\n// Determine FTP folder status icon\\nconst ftpFolderStatusIcon = (credentialsFtpUpload.disabled || workflowsFtpUpload.disabled) ? \\n  '⚠️' : \\n  ((credentialsFtpUpload.success && workflowsFtpUpload.success) ? '✅' : '❌');\\n\\n// Create comprehensive backup log using Init variables\\nconst backupLog = {\\n  timestamp: endTime.toISOString(),\\n  localTimestamp: endTime.toLocaleString('en-GB', { timeZone: initTimeData.localTimezone }),\\n  localTimezone: initTimeData.localTimezone,\\n  backupFolder: summaryDataInput.customConfig.backupFolder,\\n  dateFolder: initTimeData.datePrefix,\\n  duration: {\\n    seconds: durationSeconds,\\n    formatted: `${Math.floor(durationSeconds / 60)}m ${durationSeconds % 60}s`,\\n    startTime: initTimeData.startTime,\\n    endTime: endTime.toISOString()\\n  },\\n  statistics: {\\n    totalWorkflows: backupSummary.totalWorkflows,\\n    successfulBackups: successfulWrites.length,\\n    failedBackups: failedWrites.length,\\n    preparationErrors: backupSummary.errorCount,\\n    credentialsExported: credentialsExport.success,\\n    credentialsFtpUploaded: credentialsFtpUpload.success,\\n    credentialsFtpDisabled: credentialsFtpUpload.disabled,\\n    credentialsFtpFiles: credentialsFtpUpload.totalFiles,\\n    workflowsFtpUploaded: workflowsFtpUpload.success,\\n    workflowsFtpDisabled: workflowsFtpUpload.disabled,\\n    workflowsFtpFiles: workflowsFtpUpload.totalFiles,\\n    totalSizeMB: Math.round(totalSize / 1024 / 1024 * 100) / 100,\\n    averageSizeKB: successfulWrites.length > 0 ? Math.round(totalSize / successfulWrites.length / 1024) : 0\\n  },\\n  credentialsExport,\\n  credentialsFtpUpload,\\n  workflowsFtpUpload,\\n  successfulFiles: successfulWrites.map(file => ({\\n    fileName: file.fileName,\\n    workflowName: file.workflowName,\\n    contentSize: file.contentSize,\\n    nodesCount: file.nodesCount\\n  })),\\n  failedFiles: failedWrites.map(file => ({\\n    fileName: file.fileName,\\n    workflowName: file.workflowName,\\n    error: file.error\\n  })),\\n  preparationErrors: backupSummary.errors || [],\\n  status: failedWrites.length === 0 && \\n          backupSummary.errorCount === 0 && \\n          credentialsExport.success && \\n          (!credentialsFtpUpload.attempted || credentialsFtpUpload.success) &&\\n          (!workflowsFtpUpload.attempted || workflowsFtpUpload.success) ? \\n    'success' : 'partial_success',\\n  configuration: {\\n    backupConfig: summaryDataInput.customConfig.backupConfig,\\n    workflowName: summaryDataInput.workflowConfig.WORKFLOW_NAME,\\n    adminEmail: summaryDataInput.workflowConfig.N8N_ADMIN_EMAIL\\n  },\\n  debug: {\\n    totalItemsReceived: allItems.length,\\n    credentialsFtpItemsFound: credentialsFtpItems.length,\\n    workflowsFtpItemsFound: workflowsFtpItems.length,\\n    aggregatedWorkflowItemsFound: aggregatedWorkflowItems.length,\\n    workflowsInAggregate: workflowsData.length,\\n    totalWorkflowsFetched: totalWorkflows,\\n    credentialsResultFound: credentialsResult !== null\\n  }\\n};\\n\\n// Convert backup log to binary data for Write Files from Disk node\\nconst logJsonContent = JSON.stringify(backupLog, null, 2);\\nconst logBinaryData = Buffer.from(logJsonContent, 'utf8').toString('base64');\\n\\n// Create console & email output lines array using Init variables\\nconst startTimeLocal = new Date(initTimeData.startTime).toLocaleString('sv-SE', { timeZone: initTimeData.localTimezone });\\nconst endTimeLocal = endTime.toLocaleString('sv-SE', { timeZone: initTimeData.localTimezone });\\n\\n// Determine status text for FTP uploads\\nconst credentialsFtpStatus = credentialsFtpUpload.disabled ? '⚠️ Disabled' : \\n  (credentialsFtpUpload.success ? '✅ Yes' : '❌ Failed');\\n\\nconst workflowsFtpStatus = workflowsFtpUpload.disabled ? '⚠️ Disabled' : \\n  (workflowsFtpUpload.success ? '✅ Yes' : '❌ Failed');\\n\\nconst consoleLines = [\\n  '=================================',\\n  '📁 N8N WORKFLOWS BACKUP SUMMARY',\\n  '=================================',\\n  `📅 Date: ${initTimeData.localTimeFormatted}`,\\n  `🌍 Timezone: ${initTimeData.localTimezone}`,\\n  `⏱️ Duration: ${backupLog.duration.formatted}`,\\n  `   • Start time (local): ${startTimeLocal}`,\\n  `   • End time (local): ${endTimeLocal}`,\\n  `📂 Backup folder: ${summaryDataInput.customConfig.backupFolder}/${initTimeData.datePrefix} ${successfulWrites.length > 0 ? '✅' : '❌'}`,\\n  `📤 FTP folder (${summaryDataInput.customConfig.FTPName || 'FTP Server'}): ${summaryDataInput.customConfig.FTP_BACKUP_FOLDER}/${initTimeData.datePrefix} ${ftpFolderStatusIcon}`,\\n  `📊 Workflows found: ${backupLog.statistics.totalWorkflows}`,\\n  `✅ Successfully backed up: ${backupLog.statistics.successfulBackups}`,\\n  `❌ Failed backups: ${backupLog.statistics.failedBackups}`,\\n  `⚠️ Preparation errors: ${backupLog.statistics.preparationErrors}`,\\n  `🔐 Credentials exported: ${credentialsExport.success ? '✅ Yes' : '❌ Failed'}`,\\n  `📤 Credentials FTP uploaded: ${credentialsFtpStatus}`,\\n  `📤 Workflows FTP uploaded: ${workflowsFtpStatus}`,\\n  `💾 Total size: ${backupLog.statistics.totalSizeMB} MB`,\\n  `📈 Status: ${backupLog.status.toUpperCase()}`,\\n  '================================='\\n];\\n\\n// Console summary - display all lines\\nconsoleLines.forEach(line => console.log(line));\\n\\n// Add error details to console lines if any\\nif (failedWrites.length > 0) {\\n  console.log('❌ Failed files:');\\n  consoleLines.push('❌ Failed files:');\\n  failedWrites.forEach(fail => {\\n    const errorLine = `  - ${fail.fileName}: ${fail.error}`;\\n    console.log(errorLine);\\n    consoleLines.push(errorLine);\\n  });\\n}\\n\\n// Add credentials export details - only show errors, not success details\\nif (!credentialsExport.success) {\\n  console.log('🔐 Credentials export error:');\\n  consoleLines.push('🔐 Credentials export error:');\\n  consoleLines.push(`  - Exit code: ${credentialsExport.exitCode}`);\\n  if (credentialsExport.stderr) {\\n    consoleLines.push(`  - Error: ${credentialsExport.stderr}`);\\n  }\\n}\\n\\n// Add credentials FTP upload details\\nif (credentialsFtpUpload.disabled) {\\n  console.log('Credentials FTP upload disabled:');\\n  consoleLines.push('⚠️ Credentials FTP upload:');\\n  consoleLines.push(`  - Warning: no FTP data received (node likely disabled)`);\\n} else if (!credentialsFtpUpload.success && credentialsFtpUpload.attempted) {\\n  console.log('Credentials FTP upload errors:');\\n  consoleLines.push('❌ Credentials FTP upload errors:');\\n  consoleLines.push(`  - ${credentialsFtpUpload.message}`);\\n  \\n  if (credentialsFtpData && credentialsFtpData.uploads) {\\n    const failedUploads = credentialsFtpData.uploads.filter(upload => !upload.success);\\n    failedUploads.forEach(upload => {\\n      const errorLine = `    • ${upload.fileName}: ${upload.error || 'Upload failed'}`;\\n      console.log(errorLine);\\n      consoleLines.push(errorLine);\\n    });\\n  }\\n}\\n\\n// Add workflows FTP upload details\\nif (workflowsFtpUpload.disabled) {\\n  console.log('Workflows FTP upload disabled:');\\n  consoleLines.push('⚠️ Workflows FTP upload:');\\n  consoleLines.push(`  - Warning: no FTP data received (node likely disabled)`);\\n} else if (!workflowsFtpUpload.success && workflowsFtpUpload.attempted) {\\n  console.log('Workflows FTP upload errors:');\\n  consoleLines.push('❌ Workflows FTP upload errors:');\\n  consoleLines.push(`  - ${workflowsFtpUpload.message}`);\\n  \\n  if (workflowsFtpData && workflowsFtpData.uploads) {\\n    const failedUploads = workflowsFtpData.uploads.filter(upload => !upload.success);\\n    failedUploads.forEach(upload => {\\n      const errorLine = `    • ${upload.fileName || upload.workflowName}: ${upload.error || 'Upload failed'}`;\\n      console.log(errorLine);\\n      consoleLines.push(errorLine);\\n    });\\n  }\\n}\\n\\n// Create email log file content as plain text\\nconst emailLogText = consoleLines.join('\\\\n');\\n\\n// Convert execution log to binary data as plain text\\nconst emailLogBinaryData = Buffer.from(emailLogText, 'utf8').toString('base64'); \\n\\n// Create execution log file name using Init variables\\nconst emailLogFileName = `${initTimeData.localDateTime}_exec_log.txt`;\\nconst emailLogFilePath = `${summaryDataInput.workflowConfig.LOGS_PATH}/${emailLogFileName}`;\\n\\nconst emailLog = {\\n  data: emailLogBinaryData,\\n  mimeType: 'text/plain', \\n  fileName: emailLogFileName,\\n  fileExtension: 'txt'\\n}\\n\\nconst summaryData = {\\n  backupLog,\\n  emailLogText,\\n  logPathFile: summaryDataInput.workflowConfig.logPathFileName,\\n  emailLogPath: emailLogFilePath,\\n  emailLogFileName: emailLogFileName,\\n  backupCompleted: true,\\n  workflowStep: 'completed'\\n};\\n\\n// Return with binary data for BOTH log files\\nreturn [{\\n  json: summaryData,\\n  binary: {\\n    data: {\\n      data: logBinaryData,\\n      mimeType: 'application/json',\\n      fileName: summaryDataInput.workflowConfig.logFileName,\\n      fileExtension: 'json'\\n    },\\n    emailLog\\n  }\\n}];"},"id":"1e9eb8bf-b9b7-497b-815a-7c7af0aaf73c","name":"Backup Summary","type":"n8n-nodes-base.code","position":[2608,624],"typeVersion":2,"onError":"continueErrorOutput"},{"parameters":{"operation":"write","fileName":"={{ $json.logPathFile }}","options":{}},"id":"6de7026b-5aee-4c17-95c6-95e7e08c7f2a","name":"Write Backup Log","type":"n8n-nodes-base.readWriteFile","position":[2816,608],"typeVersion":1},{"parameters":{"fromEmail":"admin <admin@example.com>","toEmail":"={{ $env.N8N_ADMIN_EMAIL }}","subject":"=n8n SUCCESS: {{ $workflow.name }}","emailFormat":"text","text":"=Workflow:  {{ $workflow.name }}\\nWorkflow has executed sucessfully.\\n\\n{{ $json.emailLogText }}\\n\\nFind the exported Workflow JSON files attached to this email.","options":{"appendAttribution":false,"attachments":"data"}},"id":"bbcb7ddb-406c-4492-9687-0aa691099e64","name":"Send email","type":"n8n-nodes-base.emailSend","position":[3024,608],"webhookId":"baa9c40c-7574-48d9-8ef0-ca63d3431f74","typeVersion":2.1},{"parameters":{"operation":"write","fileName":"={{ $json.emailLogPath }}","dataPropertyName":"emailLog","options":{}},"id":"37669c7f-7f16-4f3c-8fa2-8f0d3c323910","name":"Write Email Log","type":"n8n-nodes-base.readWriteFile","position":[2816,416],"typeVersion":1},{"parameters":{"command":"=mkdir -p \\"{{ $json.customConfig.backupFolder }}/{{ $json.customConfig.datePrefix }}\\""},"id":"f542c03c-b28a-418b-97cc-f4749508cef3","name":"Create Date Folder","type":"n8n-nodes-base.executeCommand","position":[864,608],"typeVersion":1},{"parameters":{"jsCode":"// Init Workflow Variables - Local timezone version\\n// ✅ All dates/times handled in local timezone\\n\\n// YOUR_AWS_SECRET_KEY_HERE==\\n// 📅 LOCAL DATE/TIME INITIALIZATION\\n// YOUR_AWS_SECRET_KEY_HERE==\\n\\nconst now = new Date();\\n\\n// YOUR_AWS_SECRET_KEY_HERE==\\n// 🌍 USER-DEFINED TIMEZONE CONFIGURATION\\n// YOUR_AWS_SECRET_KEY_HERE==\\n// ⚠️  IMPORTANT: This code runs on the n8n SERVER, not in your browser!\\n// ⚠️  Configure the timezone where you want executions to be scheduled,\\n// ⚠️  regardless of where your n8n server is physically located.\\n//\\n// 📍 Common timezone examples:\\n// - 'Europe/Paris'       → Central European Time (CET/CEST)\\n// - 'America/New_York'   → Eastern Time (EST/EDT)\\n// - 'America/Chicago'    → Central Time (CST/CDT)\\n// - 'America/Los_Angeles'→ Pacific Time (PST/PDT)\\n// - 'Asia/Tokyo'         → Japan Standard Time (JST)\\n// - 'Asia/Shanghai'      → China Standard Time (CST)\\n// - 'Australia/Sydney'   → Australian Eastern Time (AET)\\n// - 'UTC'                → Coordinated Universal Time\\n//\\n// 🔧 TO CONFIGURE FOR YOUR USE CASE:\\n// 1. Uncomment and edit the line below with your desired timezone\\n// 2. Comment out the automatic detection line\\n//\\n// To use user-defined timezone instead, UNCOMMENT these lines:\\n// const USER_TIMEZONE = 'Europe/Paris';  // 👈 EDIT THIS for your location\\n// const LOCAL_TIMEZONE = USER_TIMEZONE;  // 👈 EDIT THIS for your location\\n//\\n// For automatic detection (uses server timezone or environment variable):\\nconst LOCAL_TIMEZONE = $env.TZ || 'Europe/Paris';  // 🟢 Default fallback\\n// To use user-defined timezone instead, comment out the above line\\n\\n// Local date in YYYY-MM-DD format\\nconst localDate = now.toLocaleDateString('sv-SE', { timeZone: LOCAL_TIMEZONE });\\n\\n// Local datetime in YYYY-MM-DD_HH-MM-SS format\\nconst localDateTime = now.toLocaleString('sv-SE', { \\n  timeZone: LOCAL_TIMEZONE,\\n  year: 'numeric',\\n  month: '2-digit',\\n  day: '2-digit',\\n  hour: '2-digit',\\n  minute: '2-digit',\\n  second: '2-digit'\\n}).replace(' ', '_').replace(/:/g, '-');\\n\\n// Local formatted time for display\\nconst localTimeFormatted = now.toLocaleString('en-GB', { \\n  timeZone: LOCAL_TIMEZONE,\\n  year: 'numeric',\\n  month: '2-digit',\\n  day: '2-digit',\\n  hour: '2-digit',\\n  minute: '2-digit',\\n  second: '2-digit'\\n});\\n\\nconst timestampUTC = now.toISOString().replace(/[:.]/g, '-').slice(0, 19); // 2025-01-20T09-30-45\\n\\nconsole.log('🚀 USER-DEFINE TIMEZONE VARIABLES INITIALISED (Local timezone):');\\nconsole.log(`   🌍 Timezone: ${LOCAL_TIMEZONE}`);\\nconsole.log(`   📅 Local date: ${localDate}`);\\nconsole.log(`   📅 Local date/time: ${localDateTime}`);\\nconsole.log(`   🕐 Local time: ${localTimeFormatted}`);\\n\\n// Create structure for time data output\\nconst timeData = {\\n  nowUTC: now.toISOString(),        // UTC for calculations\\n  localDate: localDate,             // YYYY-MM-DD format\\n  localDateTime: localDateTime,     // YYY-MM-DD_HH-MM-SS format\\n  localTimeFormatted: localTimeFormatted, // Human readable\\n  localTimezone: LOCAL_TIMEZONE,         // For reference\\n  datePrefix: localDate,\\n  timestampUTC,\\n  startTime: now.toISOString()\\n}\\n\\n// YOUR_AWS_SECRET_KEY_HERE==\\n// 📝 WORKFLOW STANDARD CONFIGURATION\\n// YOUR_AWS_SECRET_KEY_HERE==\\n\\nconst N8N_ADMIN_EMAIL = $env.N8N_ADMIN_EMAIL || 'user@example.com';\\nconst WORKFLOW_NAME = $workflow.name;\\nconst N8N_PROJECTS_DIR = $env.N8N_PROJECTS_DIR || '/files/n8n-projects-data'; // ⚠️ Your projects’ ROOT folder here\\n// projects-root-folder/\\n//   └── Your-project-folder-name/\\n//       ├── logs/\\n//       ├── reports/\\n//       ├── ...\\n//       └── [other project files]\\nconst PROJECT_FOLDER_NAME = \\"Workflow-backups\\"; // ⚠️ Your project folder name\\nconst PROJECT_ROOT_PATH = `${N8N_PROJECTS_DIR}/${PROJECT_FOLDER_NAME}`;\\n// const N8N_MEDIA_ROOT_PATH = $env.N8N_MEDIA_SHARED || '/files/n8n-media-shared'; // ⚠️ Your public folder, accessible from inet\\n// const mediaOutputFolder = \\"/output\\";\\n// const mediaTempFolder = \\"/temp\\";\\n// const N8N_FILE_SERVER_PURL = $env.N8N_FILE_SERVER_PURL || 'https://files.example.com'; // File serve public url\\n\\nconst LOGS_PATH = `${PROJECT_ROOT_PATH}/logs`;\\n// const logFileName = `${localDateTime2}-${WORKFLOW_NAME.replace(/[^a-zA-Z0-9]/g, '_')}_logs.json`;  // ⚠️ Your log file name\\nconst logFileName = `${localDateTime}-backup_logs.json`;  // ⚠️ Your log file name\\nconst logPathFileName = `${LOGS_PATH}/${logFileName}`;\\n\\n// Configuration for report generation\\nconst REPORTS_PATH = `${PROJECT_ROOT_PATH}/reports`;\\nconst reportFileName = `${localDateTime}-report.txt`;\\nconst reportPathFileName = `${REPORTS_PATH}/${reportFileName}`;\\n\\n// Console output\\nconsole.log('🧾 STANDARD WORKFLOW VARIABLES INITIALISED:');\\nconsole.log(`   📁 Admin email: ${N8N_ADMIN_EMAIL}`);\\nconsole.log(`   📁 Workflow name: ${WORKFLOW_NAME}`);\\nconsole.log(`   📁 Projects folder: ${N8N_PROJECTS_DIR}`);\\nconsole.log(`   📁 Project folder name: ${PROJECT_FOLDER_NAME}`);\\nconsole.log(`   📁 Project root path: ${PROJECT_ROOT_PATH}`);\\n// console.log(`   📁 Media root path: ${N8N_MEDIA_ROOT_PATH}`);\\n// console.log(`   📁 File server public URL: ${N8N_FILE_SERVER_PURL}`);\\nconsole.log(`   📁 Log path: ${LOGS_PATH}`);\\nconsole.log(`   📁 Log file name: ${logFileName}`);\\nconsole.log(`   📁 Log file path: ${logPathFileName}`);\\nconsole.log(`   📁 Reports path: ${REPORTS_PATH}`);\\nconsole.log(`   📁 Report file name: ${reportFileName}`);\\nconsole.log(`   📁 Report file path: ${reportPathFileName}`);\\n\\n// Create structure for workflow configuration output\\nconst workflowConfig = {\\n  workflowStep: 'init',\\n  N8N_ADMIN_EMAIL,\\n  WORKFLOW_NAME,\\n  N8N_PROJECTS_DIR,\\n  PROJECT_FOLDER_NAME,\\n  PROJECT_ROOT_PATH,\\n  // N8N_MEDIA_ROOT_PATH,\\n  // mediaOutputFolder,\\n  // mediaTempFolder,\\n  // N8N_FILE_SERVER_PURL,\\n  LOGS_PATH,\\n  logFileName,\\n  logPathFileName,\\n  REPORTS_PATH,\\n  reportFileName,\\n  reportPathFileName\\n}\\n\\n// YOUR_AWS_SECRET_KEY_HERE==\\n// 📝 WORKFLOW CUSTOM CONFIGURATION\\n// YOUR_AWS_SECRET_KEY_HERE==\\n// ⚠️  INSERT HERE: your workflow custom configuration variables\\n\\n// Base backup path using your Docker and FTP volume configuration (folder must exist)\\nconst BACKUP_FOLDER = $env.N8N_BACKUP_FOLDER || '/files/n8n-backups'; // ⚠️ Change the default value for your n8n backup folder\\nconst FTP_BACKUP_FOLDER = $env.N8N_FTP_BACKUP_FOLDER || '/n8n-backups';\\nconst FTPName = 'Your FTP Server Name'; // FTP server name for logging (display purposes only)\\n\\nconst credentials_backup_folder = \\"n8n-credentials\\"; // Credentials backup path\\n\\n// Configuration for the backup process\\nconst backupConfig = {\\n  datePrefix: localDate, // Prefix for all backup files\\n  fileNaming: 'name_only', // Options: 'name_only', 'id_only', 'name_and_id'\\n  maxRetries: 3,\\n  timeout: 30000,\\n  includeCredentials: false, // Security: Don't export credential data\\n  compression: false // Future enhancement\\n};\\n\\n// Console output\\nconsole.log('🧾 CUSTOM WORKFLOW VARIABLES INITIALISED:');\\nconsole.log(`   💾 Backup folder: ${BACKUP_FOLDER}`);\\nconsole.log('      File prefix:', localDate);\\nconsole.log('      Timestamp (UTC):', timestampUTC);\\n\\nconst customConfig = {\\n  backupFolder: BACKUP_FOLDER,\\n  FTP_BACKUP_FOLDER,\\n  FTPName,\\n  credentials: credentials_backup_folder,\\n  ...backupConfig\\n}\\n\\n// YOUR_AWS_SECRET_KEY_HERE==\\n// 📊 OUTPUT DATA\\n// YOUR_AWS_SECRET_KEY_HERE==\\n\\nconst initData = {\\n  timeData,\\n  workflowConfig,\\n  customConfig\\n};\\n\\nreturn [{ json: initData }];"},"id":"f6297204-c684-4b19-89e2-ac337810823e","name":"Init","type":"n8n-nodes-base.code","position":[656,608],"typeVersion":2},{"parameters":{"rule":{"interval":[{"triggerAtHour":4}]}},"id":"f0e6a1e4-9abf-426d-9799-367024a0f023","name":"Daily Backup","type":"n8n-nodes-base.scheduleTrigger","position":[448,608],"typeVersion":1.2},{"parameters":{"operation":"toJson","mode":"each","binaryPropertyName":"=data","options":{"format":true,"fileName":"={{ $json.name }}"}},"id":"3f5b58e1-bf0d-473a-8d2b-5d729fc90e2c","name":"Convert to File","type":"n8n-nodes-base.convertToFile","position":[1536,832],"typeVersion":1.1},{"parameters":{"filters":{},"requestOptions":{}},"id":"ca99b7a3-9aba-4f34-a31f-843358a7190e","name":"Fetch Workflows","type":"n8n-nodes-base.n8n","position":[1120,832],"typeVersion":1},{"parameters":{"jsCode":"// YOUR_AWS_SECRET_KEY_HERE==\\n// 🧹 FLEXIBLE FILENAME CLEANER\\n// YOUR_AWS_SECRET_KEY_HERE==\\n// Purpose: Clean filename for cross-platform compatibility\\n// Usage: Can work with current input OR reference another node\\n//\\n// Recommended Configuration:\\n// **Node Settings**:\\n// * ☑️ **On Error**: Continue (using error output)\\n// * ☑️ **Error Workflow**: Your notification workflow\\n// The node stops at the first error and immediately triggers your notification system! 🚨\\n\\n// ⚙️ CONFIGURATION\\nconst SOURCE_FIELD = 'name';           // Field containing the filename\\nconst SOURCE_NODE = 'Fetch Workflows';              // Set to node name like 'Fetch Workflows' OR null to use current input\\n                                       // Examples: 'Fetch Workflows', 'HTTP Request', 'Set'\\n\\n// Get input items\\nconst inputItems = $input.all();\\nconst itemCount = inputItems.length;\\n\\nconsole.log(`Flexible Filename Cleaner: Processing ${itemCount} item(s)`);\\nconsole.log(`Configuration: SOURCE_FIELD=\\"${SOURCE_FIELD}\\", SOURCE_NODE=${SOURCE_NODE || 'current input'}`);\\n\\nif (itemCount === 0) {\\n  console.error('No items to process');\\n  throw new Error('No items to process');\\n}\\n\\nconst outputItems = [];\\n\\ninputItems.forEach((item, index) => {\\n  try {\\n    let originalFileName;\\n    let sourceDescription;\\n    \\n    // Determine where to get the filename from\\n    if (SOURCE_NODE) {\\n      // Get from specified node\\n      try {\\n        // Use the corresponding item from the source node (same index)\\n        const sourceItems = $(SOURCE_NODE).all();\\n        if (sourceItems[index]) {\\n          originalFileName = sourceItems[index].json[SOURCE_FIELD];\\n          sourceDescription = `${SOURCE_NODE}[${index}].${SOURCE_FIELD}`;\\n        } else {\\n          // Fallback to first item if index doesn't exist\\n          originalFileName = $(SOURCE_NODE).first().json[SOURCE_FIELD];\\n          sourceDescription = `${SOURCE_NODE}[0].${SOURCE_FIELD} (fallback)`;\\n        }\\n      } catch (nodeError) {\\n        const errorMsg = `Cannot access node '${SOURCE_NODE}': ${nodeError.message}`;\\n        console.error(errorMsg);\\n        throw new Error(errorMsg);\\n      }\\n    } else {\\n      // Get from current input item\\n      originalFileName = item.json[SOURCE_FIELD];\\n      sourceDescription = `current_input[${index}].${SOURCE_FIELD}`;\\n    }\\n    \\n    if (!originalFileName) {\\n      const errorMsg = `No filename found in ${sourceDescription}`;\\n      console.error(errorMsg);\\n      throw new Error(errorMsg);\\n    }\\n    \\n    console.log(`Item ${index + 1}/${itemCount}: \\"${originalFileName}\\" from ${sourceDescription}`);\\n    \\n    // Clean filename for cross-platform compatibility\\n    const cleanedFileName = originalFileName\\n      // Remove forbidden characters for Windows/Linux\\n      .replace(/[<>:\\"/\\\\\\\\|?*\\\\x00-\\\\x1F\\\\x7F]/g, '_')\\n      // Replace multiple spaces/dots with single underscore\\n      .replace(/[\\\\s.]+/g, '_')\\n      // Remove consecutive underscores\\n      .replace(/_+/g, '_')\\n      // Remove leading/trailing underscores\\n      .replace(/^_+|_+$/g, '')\\n      // Limit length to 180 chars\\n      .substring(0, 180);\\n    \\n    // Fallback if name becomes empty after cleaning\\n    const finalCleanedFileName = cleanedFileName || `file_${index + 1}`;\\n    \\n    console.log(`✅ Cleaned: \\"${finalCleanedFileName}\\"`);\\n    \\n    // Pass through all original data + add cleaned filename\\n    outputItems.push({\\n      json: {\\n        ...item.json,\\n        cleanedFileName: finalCleanedFileName\\n      },\\n      binary: item.binary || {}\\n    });\\n    \\n  } catch (error) {\\n    console.error(`❌ Error processing item ${index + 1}:`, error.message);\\n    \\n    // Log error and re-throw to trigger error workflow\\n    throw new Error(`Failed to process item ${index + 1}: ${error.message}`);\\n  }\\n});\\n\\nconsole.log(`✅ Successfully processed ${outputItems.length} item(s)`);\\nreturn outputItems;"},"id":"0d300c29-d438-4aea-92fc-689b8cc462ce","name":"Clean Filename","type":"n8n-nodes-base.code","position":[1328,832],"typeVersion":2,"onError":"continueErrorOutput"},{"parameters":{"operation":"write","fileName":"={{ $('Init').first().json.customConfig.backupFolder }}/{{ $('Init').first().json.customConfig.datePrefix }}/{{ $('Clean Filename').all()[$itemIndex].json.cleanedFileName }}.json","options":{"append":false}},"id":"5e7266eb-ea33-4b8a-aa40-47228142f230","name":"Write Each Workflow To Disk","type":"n8n-nodes-base.readWriteFile","position":[1760,928],"typeVersion":1},{"parameters":{"errorMessage":"={{ $json.error }}"},"id":"a34a5c19-61e0-4f6f-ae63-542b37acc0e6","name":"ERROR: Backup Summary","type":"n8n-nodes-base.stopAndError","position":[2832,800],"typeVersion":1},{"parameters":{"errorMessage":"={{ $json.error }}"},"id":"b053b8d8-a97f-40a5-9af4-5fafd083b63f","name":"ERROR: Clean Filename","type":"n8n-nodes-base.stopAndError","position":[1536,1024],"typeVersion":1},{"parameters":{"fileSelector":"={{ $json.localPath }}","options":{}},"id":"5213db20-cf54-49a1-bee7-fc3375e2bdbc","name":"Read/Write Files from Disk","type":"n8n-nodes-base.readWriteFile","position":[1744,432],"typeVersion":1},{"parameters":{"command":"=# List all JSON files in credentials backup folder\\n# Command for Execute Command node\\n\\nls -1 \\"{{ $('Init').first().json.customConfig.backupFolder }}/{{ $('Init').first().json.customConfig.datePrefix }}/{{ $('Init').first().json.customConfig.credentials }}\\"/*.json 2>/dev/null || echo \\"No JSON files found\\""},"id":"8ae5eec6-5d45-4994-ab35-b180ce6b3a50","name":"List Credential Files","type":"n8n-nodes-base.executeCommand","position":[1328,432],"typeVersion":1},{"parameters":{"jsCode":"// Process file list from Execute Command and create items for each file\\n// ✅ Converts file list into individual items for Read Files node\\n\\n// ⚠️ CONFIGURE THIS NODE WITH:\\n// SETTINGS > ON ERROR > CONTINUE (USING ERROR OUTPUT)\\n\\nconst initData = $('Init').first().json;\\nconst commandResult = $input.first().json;\\nconst exportResult = $('Export Credentials').first().json;\\n\\nconsole.log('[Process File List] Command result:', commandResult);\\nconsole.log('[Process File List] Command stdout:', commandResult.stdout);\\n\\n// Check if command was successful\\nif (commandResult.exitCode !== 0) {\\n  const errorMsg = `List files command failed with exit code ${commandResult.exitCode}`;\\n  console.error(`[Process File List] ${errorMsg}`);\\n  console.error(`[Process File List] Command stderr:`, commandResult.stderr);\\n  throw new Error(errorMsg);\\n}\\n\\n// Parse the file list from stdout\\nconst stdout = commandResult.stdout.trim();\\n\\nif (!stdout || stdout === \\"No JSON files found\\") {\\n  console.log('[Process File List] No credentials files found');\\n  return [{ json: { workflowStep: 'no_credentials_files', message: 'No credentials files found' } }];\\n}\\n\\n// Split file paths and filter out empty lines\\nconst filePaths = stdout.split('\\\\n').filter(path => path.trim().length > 0);\\n\\nconsole.log(`[Process File List] Found ${filePaths.length} credentials file(s)`);\\n\\nconst outputItems = filePaths.map((fullPath, index) => {\\n  // Extract filename from full path\\n  const fileName = fullPath.split('/').pop();\\n  \\n  // Build FTP remote path\\n  const ftpPath = `${initData.customConfig.FTP_BACKUP_FOLDER}/${initData.customConfig.datePrefix}/${initData.customConfig.credentials}/${fileName}`;\\n  \\n  console.log(`[Process File List] File ${index + 1}: ${fileName}`);\\n  console.log(`  Local path: ${fullPath}`);\\n  console.log(`  FTP path: ${ftpPath}`);\\n  \\n  return {\\n    json: {\\n      fileName: fileName,\\n      localPath: fullPath,\\n      ftpPath: ftpPath,\\n      fileType: 'credentials_file',\\n      workflowStep: 'credentials_file_read',\\n      fileIndex: index + 1,\\n      totalFiles: filePaths.length,\\n      exportResult: {\\n        exitCode: exportResult.exitCode,\\n        stdout: exportResult.stdout,\\n        stderr: exportResult.stderr\\n      }\\n    }\\n  };\\n});\\n\\nconsole.log(`[Process File List] ✅ Created ${outputItems.length} items for file reading`);\\n\\nreturn outputItems;"},"id":"6bd717c3-9db0-4450-b839-45fb96e7a5a4","name":"Output Credential Items","type":"n8n-nodes-base.code","position":[1536,432],"typeVersion":2},{"parameters":{"aggregate":"aggregateAllItemData","destinationFieldName":"workflows","options":{"includeBinaries":true}},"id":"9e8420cb-b6c5-406b-b0cd-231d0ec1f3d6","name":"Aggregate","type":"n8n-nodes-base.aggregate","position":[1968,928],"typeVersion":1},{"parameters":{"numberInputs":3},"id":"85d2d744-60a0-42f6-a4ce-936490b1bc48","name":"Merge","type":"n8n-nodes-base.merge","position":[2416,608],"typeVersion":3.2},{"parameters":{"operation":"upload","path":"={{ $('Output Credential Items').item.json.ftpPath }}","options":{}},"id":"8acd2ea4-109b-4d06-a515-5dd482982ccd","name":"Upload Credentials To FTP","type":"n8n-nodes-base.ftp","position":[1952,432],"typeVersion":1,"disabled":true,"onError":"continueRegularOutput"},{"parameters":{"jsCode":"// FTP Upload Results Logger for Credentials Files\\n// ✅ Processes FTP upload results from individual credentials files and creates comprehensive logging data\\n// ✅ Enhanced error handling for FTP connection timeouts and server errors\\n\\n// ⚠️ CONFIGURE THIS NODE WITH:\\n// SETTINGS > ON ERROR > CONTINUE (USING ERROR OUTPUT)\\n\\nconst allFtpResults = $input.all();\\nconst initData = $('Init').first().json;\\n\\nconsole.log('[FTP Logger] Processing FTP upload results for credentials files...');\\nconsole.log(`[FTP Logger] Received ${allFtpResults.length} FTP result item(s)`);\\n\\nconst ftpUploadResults = {\\n  timestamp: new Date().toISOString(),\\n  localTimestamp: new Date().toLocaleString('en-GB', { timeZone: initData.timeData.timezone }),\\n  totalFiles: allFtpResults.length,\\n  successfulUploads: 0,\\n  failedUploads: 0,\\n  uploads: []\\n};\\n\\n// Process each FTP result\\nallFtpResults.forEach((result, index) => {\\n  try {\\n    // Handle different result structures (success vs error outputs)\\n    let uploadData;\\n    let isConnectionError = false;\\n    let connectionErrorMessage = null;\\n    \\n    // Check if this is an error result from FTP node\\n    if (result.error) {\\n      // This comes from the error output of FTP node\\n      isConnectionError = true;\\n      connectionErrorMessage = result.error;\\n      uploadData = result.json || {};\\n      console.log(`[FTP Logger] FTP node error detected: ${connectionErrorMessage}`);\\n    } else if (result.json && result.json.error) {\\n      // Error embedded in JSON response\\n      isConnectionError = true;\\n      connectionErrorMessage = result.json.error;\\n      uploadData = result.json;\\n      console.log(`[FTP Logger] FTP JSON error detected: ${connectionErrorMessage}`);\\n    } else {\\n      // Normal success/failure response\\n      uploadData = result.json || {};\\n    }\\n    \\n    // Determine if upload was successful\\n    const isSuccess = !isConnectionError && !uploadData.error && uploadData.success !== false;\\n    \\n    // Extract file information with fallbacks\\n    const fileName = uploadData.fileName || uploadData.path || `credentials_file_${index + 1}`;\\n    const ftpPath = uploadData.ftpPath || uploadData.path || 'unknown';\\n    \\n    const uploadLog = {\\n      fileName: fileName,\\n      fileType: uploadData.fileType || 'credentials_file',\\n      localPath: uploadData.localPath || 'unknown',\\n      ftpPath: ftpPath,\\n      success: isSuccess,\\n      uploadTime: new Date().toISOString(),\\n      error: connectionErrorMessage || uploadData.error || null,\\n      ftpResponse: uploadData.response || null,\\n      fileSize: uploadData.fileSize || null,\\n      fileIndex: uploadData.fileIndex || index + 1,\\n      connectionError: isConnectionError\\n    };\\n    \\n    if (isSuccess) {\\n      ftpUploadResults.successfulUploads++;\\n      console.log(`[FTP Logger] ✅ Successfully uploaded: ${uploadLog.fileName} (${uploadLog.fileIndex}/${uploadData.totalFiles || ftpUploadResults.totalFiles})`);\\n    } else {\\n      ftpUploadResults.failedUploads++;\\n      if (isConnectionError) {\\n        console.error(`[FTP Logger] 🔌 Connection error for: ${uploadLog.fileName} - ${connectionErrorMessage}`);\\n      } else {\\n        console.error(`[FTP Logger] ❌ Failed to upload: ${uploadLog.fileName} (${uploadLog.fileIndex}/${uploadData.totalFiles || ftpUploadResults.totalFiles})`);\\n      }\\n      if (uploadLog.error) {\\n        console.error(`[FTP Logger] Error details: ${uploadLog.error}`);\\n      }\\n    }\\n    \\n    ftpUploadResults.uploads.push(uploadLog);\\n    \\n  } catch (error) {\\n    console.error(`[FTP Logger] Error processing result ${index + 1}:`, error.message);\\n    \\n    // Add error entry for processing failures\\n    ftpUploadResults.uploads.push({\\n      fileName: `unknown_file_${index + 1}`,\\n      fileType: 'credentials_file',\\n      localPath: 'unknown',\\n      ftpPath: 'unknown',\\n      success: false,\\n      error: `Processing error: ${error.message}`,\\n      uploadTime: new Date().toISOString(),\\n      fileIndex: index + 1,\\n      connectionError: false\\n    });\\n    \\n    ftpUploadResults.failedUploads++;\\n  }\\n});\\n\\n// Create simplified summary\\nconst connectionErrors = ftpUploadResults.uploads.filter(upload => upload.connectionError);\\nconst hasConnectionErrors = connectionErrors.length > 0;\\n\\n// Create simplified summary\\nconst ftpSummary = {\\n  overallSuccess: ftpUploadResults.failedUploads === 0,\\n  summary: hasConnectionErrors ? \\n    `FTP server connection failed - credentials files could not be uploaded due to server connectivity issues` :\\n    `${ftpUploadResults.successfulUploads}/${ftpUploadResults.totalFiles} credentials files uploaded successfully`\\n};\\n\\nconsole.log('[FTP Logger] Credentials Upload Summary:');\\nconsole.log(`  Total credentials files: ${ftpUploadResults.totalFiles}`);\\nconsole.log(`  Successful uploads: ${ftpUploadResults.successfulUploads}`);\\nconsole.log(`  Failed uploads: ${ftpUploadResults.failedUploads}`);\\n\\nif (hasConnectionErrors) {\\n  console.log('[FTP Logger] 🔌 FTP server connection failed');\\n}\\n\\n// Add summary to results\\nftpUploadResults.summary = ftpSummary;\\n\\n// Create output data that will be merged with Backup Summary\\nconst credentialsFtpLog = {\\n  credentialsFtpUpload: ftpUploadResults\\n};\\n\\nconsole.log('[FTP Logger] ✅ Credentials FTP upload logging completed');\\n\\nreturn [{ json: credentialsFtpLog }];"},"id":"e626d522-c257-4520-b3fd-5b48ae365b77","name":"FTP Logger (credentials)","type":"n8n-nodes-base.code","position":[2160,432],"typeVersion":2,"disabled":true},{"parameters":{"jsCode":"// FTP Upload Results Logger for Workflow Files\\n// ✅ Processes FTP upload results from workflow files and creates summary for Backup Summary\\n// ✅ Enhanced error handling for FTP connection timeouts and server errors\\n\\n// ⚠️ CONFIGURE THIS NODE WITH:\\n// SETTINGS > ON ERROR > CONTINUE (USING ERROR OUTPUT)\\n\\nconst allFtpResults = $input.all();\\nconst initData = $('Init').first().json;\\n\\nconsole.log('[FTP Workflow Logger] Processing FTP upload results for workflow files...');\\nconsole.log(`[FTP Workflow Logger] Received ${allFtpResults.length} FTP result item(s)`);\\n\\nconst ftpUploadResults = {\\n  timestamp: new Date().toISOString(),\\n  localTimestamp: new Date().toLocaleString('en-GB', { timeZone: initData.timeData.localTimezone }),\\n  totalFiles: allFtpResults.length,\\n  successfulUploads: 0,\\n  failedUploads: 0,\\n  uploads: []\\n};\\n\\n// Process each FTP result\\nallFtpResults.forEach((result, index) => {\\n  try {\\n    // Handle different result structures (success vs error outputs)\\n    let uploadData;\\n    let isConnectionError = false;\\n    let connectionErrorMessage = null;\\n    \\n    // Check if this is an error result from FTP node\\n    if (result.error) {\\n      // This comes from the error output of FTP node\\n      isConnectionError = true;\\n      connectionErrorMessage = result.error;\\n      uploadData = result.json || {};\\n      console.log(`[FTP Workflow Logger] FTP node error detected: ${connectionErrorMessage}`);\\n    } else if (result.json && result.json.error) {\\n      // Error embedded in JSON response\\n      isConnectionError = true;\\n      connectionErrorMessage = result.json.error;\\n      uploadData = result.json;\\n      console.log(`[FTP Workflow Logger] FTP JSON error detected: ${connectionErrorMessage}`);\\n    } else {\\n      // Normal success/failure response\\n      uploadData = result.json || {};\\n    }\\n    \\n    // Determine if upload was successful\\n    const isSuccess = !isConnectionError && !uploadData.error && uploadData.success !== false;\\n    \\n    // Extract file information with fallbacks\\n    // For workflows, try to get the filename from Clean Filename node (which has both name and cleanedFileName)\\n    let originalWorkflowName = `workflow_${index + 1}`;\\n    let cleanedFileName = `workflow_${index + 1}`;\\n    \\n    try {\\n      const cleanFilenameItems = $('Clean Filename').all();\\n      if (cleanFilenameItems[index]) {\\n        originalWorkflowName = cleanFilenameItems[index].json.name || `workflow_${index + 1}`;\\n        cleanedFileName = cleanFilenameItems[index].json.cleanedFileName || `workflow_${index + 1}`;\\n      }\\n    } catch (error) {\\n      console.log(`[FTP Workflow Logger] Could not access Clean Filename node for item ${index + 1}, using fallback`);\\n    }\\n    \\n    const fileName = uploadData.fileName || uploadData.path || `${cleanedFileName}.json`;\\n    const ftpPath = uploadData.ftpPath || uploadData.path || 'unknown';\\n    \\n    const uploadLog = {\\n      fileName: fileName,\\n      workflowName: originalWorkflowName,\\n      cleanedFileName: cleanedFileName,\\n      fileType: 'workflow_file',\\n      localPath: uploadData.localPath || 'unknown',\\n      ftpPath: ftpPath,\\n      success: isSuccess,\\n      uploadTime: new Date().toISOString(),\\n      error: connectionErrorMessage || uploadData.error || null,\\n      ftpResponse: uploadData.response || null,\\n      fileSize: uploadData.fileSize || null,\\n      fileIndex: uploadData.fileIndex || index + 1,\\n      connectionError: isConnectionError\\n    };\\n    \\n    if (isSuccess) {\\n      ftpUploadResults.successfulUploads++;\\n      console.log(`[FTP Workflow Logger] ✅ Successfully uploaded: ${originalWorkflowName} (${uploadLog.fileIndex}/${ftpUploadResults.totalFiles})`);\\n    } else {\\n      ftpUploadResults.failedUploads++;\\n      if (isConnectionError) {\\n        console.error(`[FTP Workflow Logger] 🔌 Connection error for: ${originalWorkflowName} - ${connectionErrorMessage}`);\\n      } else {\\n        console.error(`[FTP Workflow Logger] ❌ Failed to upload: ${originalWorkflowName} (${uploadLog.fileIndex}/${ftpUploadResults.totalFiles})`);\\n      }\\n      if (uploadLog.error) {\\n        console.error(`[FTP Workflow Logger] Error details: ${uploadLog.error}`);\\n      }\\n    }\\n    \\n    ftpUploadResults.uploads.push(uploadLog);\\n    \\n  } catch (error) {\\n    console.error(`[FTP Workflow Logger] Error processing result ${index + 1}:`, error.message);\\n    \\n    // Add error entry for processing failures\\n    ftpUploadResults.uploads.push({\\n      fileName: `unknown_workflow_${index + 1}`,\\n      workflowName: `unknown_workflow_${index + 1}`,\\n      fileType: 'workflow_file',\\n      localPath: 'unknown',\\n      ftpPath: 'unknown',\\n      success: false,\\n      error: `Processing error: ${error.message}`,\\n      uploadTime: new Date().toISOString(),\\n      fileIndex: index + 1,\\n      connectionError: false\\n    });\\n    \\n    ftpUploadResults.failedUploads++;\\n  }\\n});\\n\\n// Check for connection errors specifically\\nconst connectionErrors = ftpUploadResults.uploads.filter(upload => upload.connectionError);\\nconst hasConnectionErrors = connectionErrors.length > 0;\\n\\n// Create simplified summary\\nconst ftpSummary = {\\n  overallSuccess: ftpUploadResults.failedUploads === 0,\\n  summary: hasConnectionErrors ? \\n    `FTP server connection failed - workflow files could not be uploaded due to server connectivity issues` :\\n    `${ftpUploadResults.successfulUploads}/${ftpUploadResults.totalFiles} workflow files uploaded successfully`\\n};\\n\\nconsole.log('[FTP Workflow Logger] Workflow Upload Summary:');\\nconsole.log(`  Total workflow files: ${ftpUploadResults.totalFiles}`);\\nconsole.log(`  Successful uploads: ${ftpUploadResults.successfulUploads}`);\\nconsole.log(`  Failed uploads: ${ftpUploadResults.failedUploads}`);\\n\\nif (hasConnectionErrors) {\\n  console.log('[FTP Workflow Logger] 🔌 FTP server connection failed');\\n}\\n\\n// Add summary to results\\nftpUploadResults.summary = ftpSummary;\\n\\n// Create output data that will be merged with Backup Summary\\nconst workflowsFtpLog = {\\n  workflowsFtpUpload: ftpUploadResults\\n};\\n\\nconsole.log('[FTP Workflow Logger] ✅ Workflow FTP upload logging completed');\\n\\nreturn [{ json: workflowsFtpLog }];"},"id":"5f80fe6b-b392-4c46-ac1d-91feaf0b7b37","name":"FTP Logger (workflows)","type":"n8n-nodes-base.code","position":[1968,736],"typeVersion":2,"disabled":true},{"parameters":{"command":"=# Export des credentials avec backup automatique\\nn8n export:credentials --backup --output={{ $('Init').item.json.customConfig.backupFolder }}/{{ $('Init').item.json.customConfig.datePrefix }}/{{ $('Init').item.json.customConfig.credentials }}"},"id":"08072e67-97f7-478b-bde2-13f4f8edf0f9","name":"Export Credentials","type":"n8n-nodes-base.executeCommand","position":[1120,432],"typeVersion":1},{"parameters":{"operation":"upload","path":"={{ $('Init').first().json.customConfig.FTP_BACKUP_FOLDER }}/{{ $('Init').first().json.customConfig.datePrefix }}/{{ $('Clean Filename').all()[$itemIndex].json.cleanedFileName }}.json","options":{}},"id":"b8fda36a-2cd4-47f4-8ce7-a61758be26b2","name":"Upload Workflows To FTP","type":"n8n-nodes-base.ftp","position":[1760,736],"typeVersion":1,"disabled":true,"onError":"continueRegularOutput"}]	{"Merge":{"main":[[{"node":"Backup Summary","type":"main","index":0}]]},"Aggregate":{"main":[[{"node":"Merge","type":"main","index":2}]]},"Daily Backup":{"main":[[{"node":"Init","type":"main","index":0}]]},"Backup Summary":{"main":[[{"node":"Write Backup Log","type":"main","index":0},{"node":"Write Email Log","type":"main","index":0}],[{"node":"ERROR: Backup Summary","type":"main","index":0}]]},"Clean Filename":{"main":[[{"node":"Convert to File","type":"main","index":0}],[{"node":"ERROR: Clean Filename","type":"main","index":0}]]},"Convert to File":{"main":[[{"node":"Upload Workflows To FTP","type":"main","index":0},{"node":"Write Each Workflow To Disk","type":"main","index":0}]]},"Fetch Workflows":{"main":[[{"node":"Clean Filename","type":"main","index":0}]]},"Write Backup Log":{"main":[[{"node":"Send email","type":"main","index":0}]]},"FTP Logger (workflows)":{"main":[[{"node":"Merge","type":"main","index":1}]]},"Output Credential Items":{"main":[[{"node":"Read/Write Files from Disk","type":"main","index":0}]]},"Upload Workflows To FTP":{"main":[[{"node":"FTP Logger (workflows)","type":"main","index":0}]]},"FTP Logger (credentials)":{"main":[[{"node":"Merge","type":"main","index":0}]]},"Upload Credentials To FTP":{"main":[[{"node":"FTP Logger (credentials)","type":"main","index":0}]]},"Read/Write Files from Disk":{"main":[[{"node":"Upload Credentials To FTP","type":"main","index":0}]]},"Write Each Workflow To Disk":{"main":[[{"node":"Aggregate","type":"main","index":0}]]}}	2026-06-30 20:43:50.817+00	2026-06-30 20:45:29.228+00	{"executionOrder":"v1","binaryMode":"separate"}	\N	{}	36bbd85e-8221-4315-aa3c-75400a83020a	0	LoIFVbHSVU6URPJH	\N	\N	t	1	\N	\N	[]
Structured Ingest	f	[{"parameters":{},"id":"33a69445-1f55-4279-b8f8-afc041f228b9","name":"Start","type":"n8n-nodes-base.manualTrigger","typeVersion":1,"position":[0,0]},{"parameters":{"fields":{"values":[{"name":"graphdb","stringValue":"https://graphdb-projects.va-benefits.gw-pse.com/repositories/va-benefits/statements"},{"name":"poolparty","stringValue":"https://poolparty.va-benefits.gw-pse.com/extractor/api/tag"},{"name":"csvDir","stringValue":"/data/staging/output/csv"},{"name":"rdfDir","stringValue":"/data/staging/output/rdf"},{"name":"prefixes","stringValue":"@prefix vak:   <https://va-benefits.example/kg/ontology#> .\\n@prefix va:    <https://va-benefits.example/taxonomy/> .\\n@prefix skos:  <http://www.w3.org/2004/02/skos/core#> .\\n@prefix dct:   <http://purl.org/dc/terms/> .\\n@prefix xsd:   <http://www.w3.org/2001/XMLSchema#> .\\n@prefix vakdc: <https://va-benefits.example/kg/data/dc/> .\\n@prefix vakrc: <https://va-benefits.example/kg/data/rc/> .\\n@prefix vakpc: <https://va-benefits.example/kg/data/pc/> .\\n@prefix vakm:  <https://va-benefits.example/kg/data/m21/> .\\n@prefix vakf:  <https://va-benefits.example/kg/data/cfr/> .\\n\\n"},{"name":"extractorProjectId","stringValue":"={{ $env.EXTRACTOR_PROJECT_ID }}"},{"name":"extractorAuth","stringValue":"={{ $env.EXTRACTOR_AUTH }}"},{"name":"annotationGraph","stringValue":"https://va-benefits.example/kg/annotations/"}]},"options":{}},"id":"77a0e0e4-a988-4809-853e-40b0279e443c","name":"Config","type":"n8n-nodes-base.set","typeVersion":3,"position":[224,0]},{"parameters":{"jsCode":"\\nconst fs  = require('fs');\\nconst cfg = $('Config').first().json;\\n\\nfunction parseCsv(content) {\\n  const lines = content.trim().split('\\\\n');\\n  const headers = lines[0].split(',').map(h => h.trim().replace(/^\\"|\\"$/g, ''));\\n  return lines.slice(1).map(line => {\\n    const values = []; let cur = '', inQ = false;\\n    for (const ch of line) {\\n      if (ch === '\\"') { inQ = !inQ; }\\n      else if (ch === ',' && !inQ) { values.push(cur.trim()); cur = ''; }\\n      else { cur += ch; }\\n    }\\n    values.push(cur.trim());\\n    const row = {};\\n    headers.forEach((h, i) => { row[h] = (values[i] || '').replace(/^\\"|\\"$/g, ''); });\\n    return row;\\n  });\\n}\\n\\nfunction ttl(s) {\\n  return (s || '').replace(/\\\\\\\\/g, '\\\\\\\\\\\\\\\\').replace(/\\"/g, '\\\\\\\\\\"').replace(/\\\\n/g, '\\\\\\\\n').trim();\\n}\\n\\nconst dcRows = parseCsv(fs.readFileSync(`${cfg.csvDir}/diagnostic_codes.csv`, 'utf8'));\\nconst dcMap  = parseCsv(fs.readFileSync(`${cfg.csvDir}/dc_taxonomy_mapping.csv`, 'utf8'));\\n\\nconst dcConcepts = {};\\nfor (const row of dcMap) {\\n  const dc = row.diagnostic_code;\\n  if (!dcConcepts[dc]) dcConcepts[dc] = [];\\n  if (row.taxonomy_concept && !dcConcepts[dc].includes(row.taxonomy_concept))\\n    dcConcepts[dc].push(row.taxonomy_concept);\\n}\\n\\nconst triples = [];\\nfor (const row of dcRows) {\\n  const dc      = (row.diagnostic_code || '').trim();\\n  // vakdc: = <https://va-benefits.example/kg/data/dc/> — local part is just the DC code (no slash)\\n  const nodeUri = `vakdc:${dc}`;\\n  // vakf: = <https://va-benefits.example/kg/data/cfr/>\\n  const secSlug = (row.cfr_section || '').replace('§ ', '').replace(/\\\\./g, '-');\\n  const cfrUri  = `vakf:${secSlug}`;\\n\\n  triples.push(\\n    `${nodeUri}\\\\n    a vak:DiagnosticCode ;\\\\n` +\\n    `    vak:dcCode \\"${ttl(dc)}\\" ;\\\\n` +\\n    `    vak:conditionName \\"${ttl(row.description)}\\" ;\\\\n` +\\n    `    vak:cfr38Section \\"${ttl(row.cfr_section)}\\" ;\\\\n` +\\n    `    vak:sourceUrl \\"${ttl(row.url)}\\" .`\\n  );\\n  for (const c of (dcConcepts[dc] || []))\\n    triples.push(`${nodeUri} vak:HAS_CONCEPT ${c} .`);\\n  triples.push(`${nodeUri} vak:GOVERNED_BY ${cfrUri} .`);\\n}\\n\\nconst ttlContent = cfg.prefixes + triples.join('\\\\n');\\nfs.writeFileSync(`${cfg.rdfDir}/diagnostic_codes.ttl`, ttlContent);\\nreturn [{ json: { file: 'diagnostic_codes.ttl', triples: triples.length, ttl: ttlContent } }];\\n"},"id":"8091003d-9398-4744-9f45-e4fea1daf042","name":"Generate: Diagnostic Codes TTL","type":"n8n-nodes-base.code","typeVersion":2,"position":[592,192]},{"parameters":{"method":"POST","url":"={{ $('Config').first().json.graphdb }}","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Content-Type","value":"text/turtle"}]},"sendBody":true,"contentType":"raw","rawContentType":"text/turtle","body":"={{ $json.ttl }}","options":{"timeout":120000}},"id":"05eb3e52-1aef-4388-8847-aa16150071fa","name":"Load: Diagnostic Codes → GraphDB","type":"n8n-nodes-base.httpRequest","typeVersion":4,"position":[816,192]},{"parameters":{"jsCode":"\\nconst fs  = require('fs');\\nconst cfg = $('Config').first().json;\\n\\nfunction parseCsv(content) {\\n  const lines = content.trim().split('\\\\n');\\n  const headers = lines[0].split(',').map(h => h.trim().replace(/^\\"|\\"$/g, ''));\\n  return lines.slice(1).map(line => {\\n    const values = []; let cur = '', inQ = false;\\n    for (const ch of line) {\\n      if (ch === '\\"') { inQ = !inQ; }\\n      else if (ch === ',' && !inQ) { values.push(cur.trim()); cur = ''; }\\n      else { cur += ch; }\\n    }\\n    values.push(cur.trim());\\n    const row = {};\\n    headers.forEach((h, i) => { row[h] = (values[i] || '').replace(/^\\"|\\"$/g, ''); });\\n    return row;\\n  });\\n}\\n\\nfunction ttl(s) {\\n  return (s || '').replace(/\\\\\\\\/g, '\\\\\\\\\\\\\\\\').replace(/\\"/g, '\\\\\\\\\\"').replace(/\\\\n/g, '\\\\\\\\n').trim();\\n}\\n\\nconst critRows = parseCsv(fs.readFileSync(`${cfg.csvDir}/rating_criteria.csv`, 'utf8'));\\nconst critMap  = parseCsv(fs.readFileSync(`${cfg.csvDir}/criteria_taxonomy_mapping.csv`, 'utf8'));\\n\\nconst critConcepts = {};\\nfor (const row of critMap) {\\n  const dc = row.diagnostic_code;\\n  if (!critConcepts[dc]) critConcepts[dc] = [];\\n  for (const c of [row.body_system_concept, row.rating_concept])\\n    if (c && !critConcepts[dc].includes(c)) critConcepts[dc].push(c);\\n}\\n\\nconst seenCounter = {};\\nconst triples = [];\\nfor (const row of critRows) {\\n  const dc  = (row.diagnostic_code || '').trim();\\n  const pct = (row.rating_percent  || '').trim();\\n  const key = `${dc}-${pct}`;\\n  seenCounter[key] = (seenCounter[key] || 0) + 1;\\n  // vakrc: = <https://va-benefits.example/kg/data/rc/> — local part uses - not /\\n  const nodeUri = `vakrc:${dc}-${pct}pct-${seenCounter[key]}`;\\n  const dcUri   = `vakdc:${dc}`;\\n\\n  triples.push(\\n    `${nodeUri}\\\\n    a vak:RatingCriterion ;\\\\n` +\\n    `    vak:dcCode \\"${ttl(dc)}\\" ;\\\\n` +\\n    `    vak:conditionName \\"${ttl(row.condition_name)}\\" ;\\\\n` +\\n    `    vak:criteriaText \\"${ttl(row.criteria)}\\" ;\\\\n` +\\n    `    vak:ratingPercentage ${pct} ;\\\\n` +\\n    `    vak:cfr38Section \\"${ttl(row.cfr_section)}\\" ;\\\\n` +\\n    `    vak:CRITERION_FOR ${dcUri} .`\\n  );\\n  triples.push(`${dcUri} vak:HAS_CRITERION ${nodeUri} .`);\\n  for (const c of (critConcepts[dc] || []))\\n    triples.push(`${nodeUri} vak:HAS_CONCEPT ${c} .`);\\n}\\n\\nconst ttlContent = cfg.prefixes + triples.join('\\\\n');\\nfs.writeFileSync(`${cfg.rdfDir}/rating_criteria.ttl`, ttlContent);\\nreturn [{ json: { file: 'rating_criteria.ttl', triples: triples.length, ttl: ttlContent } }];\\n"},"id":"946d46e7-b4bb-4b39-bf8f-1d12189ab618","name":"Generate: Rating Criteria TTL","type":"n8n-nodes-base.code","typeVersion":2,"position":[1040,192]},{"parameters":{"method":"POST","url":"={{ $('Config').first().json.graphdb }}","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Content-Type","value":"text/turtle"}]},"sendBody":true,"contentType":"raw","rawContentType":"text/turtle","body":"={{ $json.ttl }}","options":{"timeout":300000}},"id":"d050950b-0bdb-4482-8a36-0a5f3b93683b","name":"Load: Rating Criteria → GraphDB","type":"n8n-nodes-base.httpRequest","typeVersion":4,"position":[1264,192]},{"parameters":{"jsCode":"\\nconst fs  = require('fs');\\nconst cfg = $('Config').first().json;\\n\\nfunction parseCsv(content) {\\n  const lines = content.trim().split('\\\\n');\\n  const headers = lines[0].split(',').map(h => h.trim().replace(/^\\"|\\"$/g, ''));\\n  return lines.slice(1).map(line => {\\n    const values = []; let cur = '', inQ = false;\\n    for (const ch of line) {\\n      if (ch === '\\"') { inQ = !inQ; }\\n      else if (ch === ',' && !inQ) { values.push(cur.trim()); cur = ''; }\\n      else { cur += ch; }\\n    }\\n    values.push(cur.trim());\\n    const row = {};\\n    headers.forEach((h, i) => { row[h] = (values[i] || '').replace(/^\\"|\\"$/g, ''); });\\n    return row;\\n  });\\n}\\n\\nfunction ttl(s) { return (s || '').replace(/\\\\\\\\/g,'\\\\\\\\\\\\\\\\').replace(/\\"/g,'\\\\\\\\\\"').replace(/\\\\n/g,'\\\\\\\\n').trim(); }\\nfunction slug(t, n=60) { return (t||'').toLowerCase().trim().replace(/[^a-z0-9]+/g,'-').replace(/^-+|-+$/g,'').slice(0,n); }\\n\\nconst cfrRows = parseCsv(fs.readFileSync(`${cfg.csvDir}/presumptive_conditions.csv`, 'utf8'));\\nconst pdfRows = parseCsv(fs.readFileSync(`${cfg.csvDir}/va_presumptive_conditions.csv`, 'utf8'));\\nconst presMap = parseCsv(fs.readFileSync(`${cfg.csvDir}/presumptive_taxonomy_mapping.csv`, 'utf8'));\\n\\nconst presConcepts = {};\\nfor (const row of presMap)\\n  presConcepts[row.condition.toLowerCase()] = { primary: row.taxonomy_concept||'', secondary: row.secondary_concept||'' };\\n\\nconst allPres = [\\n  ...cfrRows.map(r => ({ condition: r.condition, category: r.presumption_type, citation: r.cfr_citation, source: '38 CFR § 3.309' })),\\n  ...pdfRows.map(r => ({ condition: r.condition, category: r.exposure_category, citation: '', source: 'VA Presumptive Guide' }))\\n];\\n\\nconst seenUris = new Set();\\nconst triples = [];\\nfor (const row of allPres) {\\n  const cond    = (row.condition||'').trim();\\n  const s       = slug(cond);\\n  // vakpc: = <https://va-benefits.example/kg/data/pc/> — local part is slug (hyphens, no slashes)\\n  const nodeUri = `vakpc:${s}`;\\n\\n  if (!seenUris.has(nodeUri)) {\\n    seenUris.add(nodeUri);\\n    let t = `${nodeUri}\\\\n    a vak:PresumptiveCondition ;\\\\n    vak:conditionName \\"${ttl(cond)}\\" ;\\\\n    vak:presumptionType \\"${ttl(row.category)}\\" ;\\\\n    dct:source \\"${ttl(row.source)}\\" `;\\n    if (row.citation) t += `;\\\\n    vak:cfr38Section \\"${ttl(row.citation)}\\" `;\\n    t += '.';\\n    triples.push(t);\\n  }\\n  const c = presConcepts[cond.toLowerCase()] || {};\\n  if (c.primary) {\\n    triples.push(`${nodeUri} vak:HAS_CONCEPT ${c.primary} .`);\\n    triples.push(`${nodeUri} vak:LISTED_UNDER ${c.primary} .`);\\n  }\\n  if (c.secondary && c.secondary !== c.primary)\\n    triples.push(`${nodeUri} vak:HAS_CONCEPT ${c.secondary} .`);\\n}\\n\\nconst ttlContent = cfg.prefixes + triples.join('\\\\n');\\nfs.writeFileSync(`${cfg.rdfDir}/presumptive_conditions.ttl`, ttlContent);\\nreturn [{ json: { file: 'presumptive_conditions.ttl', triples: triples.length, ttl: ttlContent } }];\\n"},"id":"ac00e5b0-2b0b-4932-b121-99a840ed2c2f","name":"Generate: Presumptive Conditions TTL","type":"n8n-nodes-base.code","typeVersion":2,"position":[592,448]},{"parameters":{"method":"POST","url":"={{ $('Config').first().json.graphdb }}","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Content-Type","value":"text/turtle"}]},"sendBody":true,"contentType":"raw","rawContentType":"text/turtle","body":"={{ $json.ttl }}","options":{"timeout":60000}},"id":"d1c68d34-fc0c-4da1-9ffa-77d1786d0d71","name":"Load: Presumptive Conditions → GraphDB","type":"n8n-nodes-base.httpRequest","typeVersion":4,"position":[816,448]},{"parameters":{"jsCode":"\\nconst fs  = require('fs');\\nconst cfg = $('Config').first().json;\\n\\nfunction parseCsv(content) {\\n  const lines = content.trim().split('\\\\n');\\n  const headers = lines[0].split(',').map(h => h.trim().replace(/^\\"|\\"$/g, ''));\\n  return lines.slice(1).map(line => {\\n    const values = []; let cur = '', inQ = false;\\n    for (const ch of line) {\\n      if (ch === '\\"') { inQ = !inQ; }\\n      else if (ch === ',' && !inQ) { values.push(cur.trim()); cur = ''; }\\n      else { cur += ch; }\\n    }\\n    values.push(cur.trim());\\n    const row = {};\\n    headers.forEach((h, i) => { row[h] = (values[i] || '').replace(/^\\"|\\"$/g, ''); });\\n    return row;\\n  });\\n}\\n\\nfunction ttl(s) { return (s || '').replace(/\\\\\\\\/g,'\\\\\\\\\\\\\\\\').replace(/\\"/g,'\\\\\\\\\\"').replace(/\\\\n/g,'\\\\\\\\n').trim(); }\\n\\nconst m21Rows = parseCsv(fs.readFileSync(`${cfg.csvDir}/m21_article_manifest.csv`, 'utf8'));\\nconst m21Map  = parseCsv(fs.readFileSync(`${cfg.csvDir}/m21_taxonomy_mapping.csv`, 'utf8'));\\nconst m21Concepts = {};\\nfor (const row of m21Map) m21Concepts[row.article_id] = row.primary_concept || '';\\n\\nconst triples = [];\\nfor (const row of m21Rows) {\\n  const id = (row.article_id||'').trim();\\n  if (!id) continue;\\n  // vakm: = <https://va-benefits.example/kg/data/m21/> — local part is numeric article ID\\n  const nodeUri = `vakm:${id}`;\\n  let t = `${nodeUri}\\\\n    a vak:M21Article ;\\\\n    vak:articleId \\"${ttl(id)}\\" `;\\n  if (row.part)    t += `;\\\\n    vak:m21Part \\"${ttl(row.part)}\\" `;\\n  if (row.subpart) t += `;\\\\n    vak:m21Subpart \\"${ttl(row.subpart)}\\" `;\\n  if (row.chapter) t += `;\\\\n    vak:m21Chapter \\"${ttl(row.chapter)}\\" `;\\n  if (row.url)     t += `;\\\\n    vak:sourceUrl \\"${ttl(row.url)}\\" `;\\n  t += '.';\\n  triples.push(t);\\n  const c = m21Concepts[id];\\n  if (c) triples.push(`${nodeUri} vak:HAS_CONCEPT ${c} .`);\\n}\\n\\nconst ttlContent = cfg.prefixes + triples.join('\\\\n');\\nfs.writeFileSync(`${cfg.rdfDir}/m21_articles.ttl`, ttlContent);\\nreturn [{ json: { file: 'm21_articles.ttl', triples: triples.length, ttl: ttlContent } }];\\n"},"id":"25f327fe-9724-4341-8ce3-98217e4db8aa","name":"Generate: M21 Articles TTL","type":"n8n-nodes-base.code","typeVersion":2,"position":[1040,448]},{"parameters":{"method":"POST","url":"={{ $('Config').first().json.graphdb }}","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Content-Type","value":"text/turtle"}]},"sendBody":true,"contentType":"raw","rawContentType":"text/turtle","body":"={{ $json.ttl }}","options":{"timeout":300000}},"id":"94a8b56f-4549-42d2-9d31-16ed30dbb8db","name":"Load: M21 Articles → GraphDB","type":"n8n-nodes-base.httpRequest","typeVersion":4,"position":[1264,448]},{"parameters":{"jsCode":"// Verify Phase 1 — includes diagnostics to catch silent load failures\\n\\nconst graphdb = $('Config').first().json.graphdb.replace('/statements', '');\\nconst rdfDir  = $('Config').first().json.rdfDir;\\nconst fs      = require('fs');\\nconst PREFIX  = 'PREFIX vak: <https://va-benefits.example/kg/ontology#>\\\\n';\\n\\n// ── SPARQL helper: require('https') + regex URL parsing ──────────────────\\nasync function sparql(query) {\\n  const m = graphdb.match(/^https:\\\\/\\\\/([^\\\\/]+)(.*)/);\\n  if (!m) return { error: true, status: 0, body: 'Cannot parse: ' + graphdb };\\n  const hostname = m[1];\\n  const path     = m[2] + '?query=' + encodeURIComponent(query);\\n  return new Promise((resolve) => {\\n    const https = require('https');\\n    const req   = https.get(\\n      { hostname, path, headers: { Accept: 'application/sparql-results+json' } },\\n      (res) => {\\n        let data = '';\\n        res.on('data', chunk => data += chunk);\\n        res.on('end', () => {\\n          if (res.statusCode >= 200 && res.statusCode < 300) {\\n            try   { resolve({ data: JSON.parse(data) }); }\\n            catch { resolve({ error: true, status: res.statusCode, body: 'Non-JSON: ' + data.slice(0,200) }); }\\n          } else {\\n            resolve({ error: true, status: res.statusCode, body: data.slice(0, 300) });\\n          }\\n        });\\n      }\\n    );\\n    req.on('error', e => resolve({ error: true, status: 0, body: 'https.get: ' + e.message }));\\n    req.end();\\n  });\\n}\\n\\n// ── Diagnostic 1: total triple count (are we hitting the right repo?) ────\\nconst totalResult = await sparql('SELECT (COUNT(*) AS ?c) WHERE { ?s ?p ?o }');\\nconst totalTriples = totalResult.data\\n  ? parseInt(totalResult.data.results.bindings[0]?.c?.value || '0') : -1;\\nconst totalError   = totalResult.error ? `HTTP ${totalResult.status}: ${totalResult.body}` : null;\\n\\n// ── Diagnostic 2: check TTL files exist on disk ──────────────────────────\\nconst ttlFiles = ['diagnostic_codes.ttl','rating_criteria.ttl','presumptive_conditions.ttl','m21_articles.ttl'];\\nconst fileStatus = {};\\nfor (const f of ttlFiles) {\\n  try {\\n    const stat = fs.statSync(`${rdfDir}/${f}`);\\n    fileStatus[f] = `${Math.round(stat.size / 1024)} KB`;\\n  } catch(e) {\\n    fileStatus[f] = 'MISSING';\\n  }\\n}\\n\\n// ── Main checks ───────────────────────────────────────────────────────────\\nconst checks = [\\n  { label: 'DiagnosticCode nodes',   query: `${PREFIX}SELECT (COUNT(?n) AS ?c) WHERE { ?n a vak:DiagnosticCode }`,     min: 720  },\\n  { label: 'RatingCriterion nodes',  query: `${PREFIX}SELECT (COUNT(?n) AS ?c) WHERE { ?n a vak:RatingCriterion }`,    min: 1331 },\\n  { label: 'PresumptiveCondition',   query: `${PREFIX}SELECT (COUNT(?n) AS ?c) WHERE { ?n a vak:PresumptiveCondition }`,min: 200  },\\n  { label: 'M21Article nodes',       query: `${PREFIX}SELECT (COUNT(?n) AS ?c) WHERE { ?n a vak:M21Article }`,         min: 871  },\\n  { label: 'CRITERION_FOR edges',    query: `${PREFIX}SELECT (COUNT(*) AS ?c) WHERE { ?rc vak:CRITERION_FOR ?dc }`,    min: 1331 },\\n  { label: 'Structural HAS_CONCEPT', query: `${PREFIX}SELECT (COUNT(*) AS ?c) WHERE { ?n vak:HAS_CONCEPT ?x }`,       min: 3000 },\\n];\\n\\nconst results = [];\\nlet allPass = true;\\nfor (const check of checks) {\\n  const result = await sparql(check.query);\\n  let actual = -1, errorInfo = null;\\n  if (result.error) {\\n    errorInfo = `HTTP ${result.status}: ${result.body}`;\\n  } else {\\n    actual = result.data ? parseInt(result.data.results.bindings[0]?.c?.value || '0') : -1;\\n  }\\n  const pass = actual >= check.min;\\n  if (!pass) allPass = false;\\n  results.push({ label: check.label, actual, expected_min: check.min, pass, error: errorInfo });\\n}\\n\\nreturn [{ json: {\\n  allPass,\\n  results,\\n  phase:           'Phase 1 — Base Data Load',\\n  graphdbEndpoint: graphdb,\\n  totalTriplesInRepo: totalTriples,\\n  totalTriplesError:  totalError,\\n  ttlFilesOnDisk:  fileStatus,\\n} }];"},"id":"b1ded9b0-2627-496a-92e1-39e981f90e6a","name":"Verify: SPARQL Counts","type":"n8n-nodes-base.code","typeVersion":2,"position":[1824,640]},{"parameters":{"jsCode":"const v = $input.first().json;\\n\\n// Build a clean check line per result\\nconst checkLines = v.results.map(r =>\\n  `${r.pass ? '✓' : '✗'}  ${r.label.padEnd(28)} ${String(r.actual).padStart(6)}  (≥ ${r.expected_min})${r.error ? '  ← ' + r.error : ''}`\\n);\\n\\n// Log with real newlines to the execution log\\nconsole.log([\\n  v.phase + ' — Complete',\\n  '',\\n  ...checkLines,\\n  '',\\n  v.allPass\\n    ? 'ALL CHECKS PASSED — base data loaded. Run Phase 2 to annotate.'\\n    : 'SOME CHECKS FAILED — review load steps above.',\\n].join('\\\\n'));\\n\\n// Return structured output — each field renders cleanly in n8n output panel\\nreturn [{ json: {\\n  status:          v.allPass ? '✓ ALL CHECKS PASSED' : '✗ SOME CHECKS FAILED',\\n  phase:           v.phase,\\n  checks:          checkLines,\\n  graphdbEndpoint: v.graphdbEndpoint,\\n  totalTriples:    v.totalTriplesInRepo ?? null,\\n  ttlFiles:        v.ttlFilesOnDisk    ?? null,\\n  message:         v.allPass\\n                     ? 'Base data loaded. Run Phase 2 to annotate.'\\n                     : 'Review load steps. Check Load node responses for HTTP errors.',\\n} }];"},"id":"8e5a21a6-ea77-43f5-a047-91be066694b8","name":"Format Summary","type":"n8n-nodes-base.code","typeVersion":2,"position":[2048,640]},{"parameters":{"jsCode":"// Load umls_condition_concepts.ttl into the UMLS named graph in GraphDB.\\n// This file contains condition-level UMLS CUI nodes with skos:broader →\\n// VA body-system concepts, enabling PoolParty to traverse condition → body-system.\\n\\nconst fs  = require('fs');\\nconst cfg = $('Config').first().json;\\nconst https = require('https');\\n\\nconst ttlPath = `${cfg.rdfDir}/../umls/umls_condition_concepts.ttl`;\\n\\nlet ttlContent;\\ntry {\\n  ttlContent = fs.readFileSync(ttlPath, 'utf8');\\n} catch(e) {\\n  return [{ json: { error: 'Cannot read umls_condition_concepts.ttl: ' + e.message,\\n    path: ttlPath } }];\\n}\\n\\n// POST into named graph <https://uts.nlm.nih.gov/metathesaurus/>\\nconst UMLS_GRAPH = 'https://uts.nlm.nih.gov/metathesaurus/';\\nconst graphdbBase = cfg.graphdb;\\nconst url = `${graphdbBase}?context=${encodeURIComponent('<' + UMLS_GRAPH + '>')}`;\\nconst m = url.match(/^https:\\\\/\\\\/([^\\\\/]+)(.*)/);\\nconst bodyBuf = Buffer.from(ttlContent, 'utf-8');\\n\\nconst result = await new Promise((resolve) => {\\n  const req = https.request(\\n    {\\n      hostname: m[1],\\n      path:     m[2],\\n      method:   'POST',\\n      headers: {\\n        'Content-Type':   'text/turtle',\\n        'Content-Length': bodyBuf.length\\n      }\\n    },\\n    (res) => {\\n      let data = '';\\n      res.on('data', chunk => data += chunk);\\n      res.on('end', () => resolve({ status: res.statusCode, body: data.slice(0, 200) }));\\n    }\\n  );\\n  req.on('error', e => resolve({ status: 0, body: e.message }));\\n  req.write(bodyBuf);\\n  req.end();\\n});\\n\\nconst ok = result.status >= 200 && result.status < 300;\\nconsole.log(`UMLS condition concepts → GraphDB: HTTP ${result.status}`);\\nreturn [{ json: {\\n  file:   'umls_condition_concepts.ttl',\\n  status: result.status,\\n  ok,\\n  bytes:  bodyBuf.length,\\n  graph:  UMLS_GRAPH\\n} }];"},"id":"f15958cd-d063-4019-b44e-50e42b2c7edf","name":"Load: UMLS Condition Concepts → GraphDB","type":"n8n-nodes-base.code","typeVersion":2,"position":[1600,640]}]	{"Start":{"main":[[{"node":"Config","type":"main","index":0}]]},"Config":{"main":[[{"node":"Generate: Diagnostic Codes TTL","type":"main","index":0}]]},"Generate: Diagnostic Codes TTL":{"main":[[{"node":"Load: Diagnostic Codes → GraphDB","type":"main","index":0}]]},"Load: Diagnostic Codes → GraphDB":{"main":[[{"node":"Generate: Rating Criteria TTL","type":"main","index":0}]]},"Generate: Rating Criteria TTL":{"main":[[{"node":"Load: Rating Criteria → GraphDB","type":"main","index":0}]]},"Load: Rating Criteria → GraphDB":{"main":[[{"node":"Generate: Presumptive Conditions TTL","type":"main","index":0}]]},"Generate: Presumptive Conditions TTL":{"main":[[{"node":"Load: Presumptive Conditions → GraphDB","type":"main","index":0}]]},"Load: Presumptive Conditions → GraphDB":{"main":[[{"node":"Generate: M21 Articles TTL","type":"main","index":0}]]},"Generate: M21 Articles TTL":{"main":[[{"node":"Load: M21 Articles → GraphDB","type":"main","index":0}]]},"Load: M21 Articles → GraphDB":{"main":[[{"node":"Load: UMLS Condition Concepts → GraphDB","type":"main","index":0}]]},"Verify: SPARQL Counts":{"main":[[{"node":"Format Summary","type":"main","index":0}]]},"Load: UMLS Condition Concepts → GraphDB":{"main":[[{"node":"Verify: SPARQL Counts","type":"main","index":0}]]}}	2026-06-27 21:59:26.205+00	2026-07-06 00:47:21.281+00	{"executionOrder":"v1","binaryMode":"separate"}	\N	{}	78e1237d-1720-4f7e-9b3f-ba07ac407d03	0	Exefs29UIIRWraS4	\N	\N	f	8	\N	\N	[]
