Utils - Compress short memory	t	[{"typeVersion":1.3,"name":"Call 'Configuration (sub-workflow)'","position":[-416,16],"id":"bea4d889-020d-4bee-ab0c-1cbcdb0f71e2","type":"n8n-nodes-base.executeWorkflow","parameters":{"workflowInputs":{"schema":[],"attemptToConvertTypes":false,"matchingColumns":[],"convertFieldsToString":true,"mappingMode":"defineBelow","value":{}},"options":{},"workflowId":{"mode":"list","cachedResultUrl":"/n8n/workflow/HJcJwMTssnY79HWw","__rl":true,"cachedResultName":"Configuration","value":"HJcJwMTssnY79HWw"}}},{"typeVersion":2,"name":"Parse response","position":[336,0],"id":"d725d342-c7d7-4086-b704-67cce92d6233","type":"n8n-nodes-base.code","parameters":{"jsCode":"var resp = $input.first().json.output;\\n\\nif( typeof resp === 'string'){\\n  return {\\n    \\"output\\" : resp\\n  }\\n}else{\\n  return {\\n    \\"output\\": $input.first().json.output[1].text\\n  }\\n}\\n"}},{"typeVersion":2,"name":"JavaScript code","position":[544,0],"id":"3db5e571-07f5-48e7-8ca5-624b6f643c81","type":"n8n-nodes-base.code","parameters":{"jsCode":"return {\\n  \\"compressedString\\": $input.first().json.output,\\n  \\"executionId\\": $('LLM call').first().json.executionId\\n}"}},{"typeVersion":1.1,"name":"When executed by another workflow","position":[-688,16],"id":"4ab8ea87-e7bd-4974-ac1d-96cf4d77cf5d","type":"n8n-nodes-base.executeWorkflowTrigger","parameters":{"workflowInputs":{"values":[{"name":"qaBlock"},{"name":"question"}]}}},{"typeVersion":2,"name":"Prepare data for LLM call","position":[-224,16],"id":"1e6db4a6-309f-4f21-9bcb-b06540ecde46","type":"n8n-nodes-base.code","parameters":{"jsCode":"var systemMessageTemplate = `You are an AI assistant that compress conversations without compromising quality of data.\\n\\nHere is a lengthy conversation, consisting of question and answer pairs:\\n{{ qaBlock }}\\n\\nPlease provide a compressed summary of this conversation so that the most important findings for answering the question '{{ Question }}' are preserved. \\nIdentify any specific data point, entity, or subject explicitly referenced or requested by the question (for example, if the question mentions \\"the first notable example,\\") and such data point is mentioned in the 'q&a pairs'' identify it. If there are identifiable data points in more than one q&a block, use only the last q&a pair data points. \\nProvide the compressed output in a single paragraph\\nIMPORTANT - Provide the compressed output in the following format:\\nconversationContext: {YOUR COMPRESSED SUMMARY HERE}\\ncurrentQuestion: {{ Question }}\\nidentifiedEntity: {THE DATA POINT OR SUBJECT THAT THE QUESTION REFERS TO, IF ANY}`\\n\\nconst qaBlock = $('When executed by another workflow').first().json.qaBlock;\\nconst question = $('When executed by another workflow').first().json.question;\\n\\nsystemMessageTemplate = systemMessageTemplate.replace('{{ qaBlock }}', qaBlock);\\n\\nsystemMessageTemplate = systemMessageTemplate.replace('{{ Question }}', question);\\n\\n\\nconst structuredOutputParserJsonSchema = {\\n  \\"$schema\\": \\"http://json-schema.org/draft-07/schema#\\",\\n  \\"type\\": \\"object\\",\\n  \\"properties\\": {\\n    \\"output\\": {\\n      \\"type\\": \\"string\\"\\n    }\\n  },\\n  \\"required\\": [\\n    \\"output\\"\\n  ],\\n     \\"additionalProperties\\": false\\n}\\n\\nreturn { \\"systemMessageTemplate\\" : systemMessageTemplate,\\n         \\"structuredOutputParserJsonSchema\\" : structuredOutputParserJsonSchema\\n       }\\n"}},{"typeVersion":1.3,"onError":"continueErrorOutput","name":"LLM call","position":[48,16],"id":"f10b10d7-66f0-4e4d-a171-833edcf03805","type":"n8n-nodes-base.executeWorkflow","parameters":{"workflowInputs":{"schema":[{"defaultMatch":false,"canBeUsedToMatch":true,"displayName":"prompt","display":true,"id":"prompt","type":"string","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"displayName":"primaryLLMModel","display":true,"id":"primaryLLMModel","type":"string","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"displayName":"secondaryLLMModel","display":true,"id":"secondaryLLMModel","type":"string","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"displayName":"structuredOutputParserJsonSchema","display":true,"id":"structuredOutputParserJsonSchema","type":"object","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"displayName":"systemMessage","display":true,"id":"systemMessage","type":"string","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"displayName":"maxNumberTokens","display":true,"id":"maxNumberTokens","type":"number","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"displayName":"samplingTemperature","display":true,"id":"samplingTemperature","type":"number","required":false}],"attemptToConvertTypes":false,"matchingColumns":[],"convertFieldsToString":true,"mappingMode":"defineBelow","value":{"systemMessage":"={{ $json.systemMessageTemplate }}","structuredOutputParserJsonSchema":"={{ $json.structuredOutputParserJsonSchema }}","maxNumberTokens":2000,"samplingTemperature":0,"prompt":"Please provide a compressed summary of this conversation","secondaryLLMModel":"={{ $('Call \\\\'Configuration (sub-workflow)\\\\'').item.json.secondaryLLMModel }}","primaryLLMModel":"={{ $('Call \\\\'Configuration (sub-workflow)\\\\'').item.json.primaryLLMModel }}"}},"options":{},"workflowId":{"mode":"list","cachedResultUrl":"/n8n/workflow/icEaxOxBisUj5nUb","__rl":true,"cachedResultName":"LLM call","value":"icEaxOxBisUj5nUb"}}}]	{"Parse response":{"main":[[{"node":"JavaScript code","index":0,"type":"main"}]]},"Call 'Configuration (sub-workflow)'":{"main":[[{"node":"Prepare data for LLM call","index":0,"type":"main"}]]},"LLM call":{"main":[[{"node":"Parse response","index":0,"type":"main"}]]},"When executed by another workflow":{"main":[[{"node":"Call 'Configuration (sub-workflow)'","index":0,"type":"main"}]]},"Prepare data for LLM call":{"main":[[{"node":"LLM call","index":0,"type":"main"}]]}}	2026-03-27 08:43:56.482+00	2026-03-27 08:43:56.482+00	{"executionOrder":"v1"}	\N	{"When executed by another workflow":[{"json":{"question":"What are it's alternatives?","qaBlock":"Question:What is PoolParty?,\\nAnswer:**1. Main topic/theme**  \\nPoolParty is a Java‑based semantic suite that provides a unified environment for creating, managing, and publishing taxonomies, thesauri, and ontologies. It serves as a container for one or more concept schemes and offers tools for automatic tagging, content classification, and integration with other systems such as SharePoint.\\n\\n**2. Key points**  \\n- **Project container** – Holds taxonomy/thesaurus data, top concepts, and multiple concept schemes.  \\n- **Core architecture** – Built on Apache Tomcat, with a JavaScript frontend, an embedded graph database (GraphDB or RDF4J), Apache Solr for indexing, and Apache Spark for machine‑learning tasks.  \\n- **Collaboration & administration** – Supports language and user‑group settings, autosave, and snapshotting of projects.  \\n- **Security** – Implements industry‑standard authentication (password, SSO, MFA, OAuth 2.0) and data‑protection measures (PBKDF2 hashing, AES encryption).  \\n- **Integration** – Provides out‑of‑the‑box integration with SharePoint Online for automatic tagging and taxonomy synchronization.  \\n\\n**3. Important details or findings**  \\n- A PoolParty project can contain any number of concept schemes and is configurable for new or existing thesauri.  \\n- Autosave and regular snapshots help prevent data loss without user intervention.  \\n- The system’s built‑in graph database stores taxonomy and ontology data, while Solr builds entity‑extraction models and search indices.  \\n- Spark is used for semantic classification of documents, enabling advanced text‑mining capabilities.  \\n- SharePoint integration enables faceted search, auto‑complete, and semantic search based on the synchronized taxonomies.  \\n\\n**4. Conclusions or recommendations**  \\nPoolParty offers a comprehensive, secure, and extensible platform for organizations needing robust semantic management and automatic content enrichment. Its modular architecture and integration options make it suitable for enterprises looking to centralize vocabulary management and enhance information retrieval across various applications.  \\n\\n**References:**  \\ns3://graphwisekh/helpTxt96_flattened/6575a5cd38__poolparty-project.html.txt  \\ns3://graphwisekh/helpTxt96_flattened/130b22f5b3__poolparty-system-architecture.html.txt  \\ns3://graphwisekh/helpTxt96_flattened/f3e05c9ee3__is-there-a-sharepoint-integration-with-poolparty-.html.txt  \\ns3://graphwisekh/helpTxt96_flattened/e086d6995d__information-security-practices-and-procedures.html.txt;\\nQuestion:What are it's alternatives?,\\nAnswer:;\\n"}}]}	92a61a08-9682-473b-ad37-23bb93e6491e	0	b8kENTFolf5BFo89	{"instanceId":"982a83c4fa14b8860ea8391b8f766ad449d7431aac64126d0b9fc936877b58be"}	\N	f	3	\N	92a61a08-9682-473b-ad37-23bb93e6491e	[]
Configuration	t	[{"parameters":{"content":"## What to use this workflow for\\n- Configuration of environment-based values","height":128,"width":368},"typeVersion":1,"name":"Sticky Note","position":[-448,-224],"id":"7a72f3fa-500c-4f63-a303-175bc152e6b8","type":"n8n-nodes-base.stickyNote"},{"parameters":{"content":"## Output\\n- **backendUrl**: string - The base URL of the conversation service\\n- **backendSseMessageUrl**: string - The URL of endpoint in the conversation service accepting and persisting SSE messages","height":176,"width":368},"typeVersion":1,"name":"Sticky Note1","position":[-48,-224],"id":"377c280c-c7fd-4092-8993-9a6933624a98","type":"n8n-nodes-base.stickyNote"},{"parameters":{"jsCode":"// GraphRAG chatbot `Configuration` node — body for the seed's `Main` workflow.\\n// Filled for THIS deployment (stack: *.va-benefits.semantic-demo.com, Elasticsearch + Bedrock).\\n// Values changed from the seed template are flagged inline.\\n\\nconst backendUrl = \\"http://graphrag-conversation:8080\\";          // VERIFIED svc (graphrag ns, ClusterIP :8080); seed's `conversation-service` does not exist → was the ENOTFOUND\\nconst graphRagComponentsUrl = \\"http://graphrag-components:8080\\"; // VERIFIED svc (graphrag ns, ClusterIP :8080)\\n\\nreturn {\\n  // GraphRAG backend (REST + SSE)\\n  backendUrl,\\n  backendSseMessageUrl: `${backendUrl}/sse/message`,\\n\\n  // GraphDB MCP endpoint (SSE). Public HTTPS ingress answers on 443 — no :7200\\n  // (probed live: /mcp/sse -> 406, repo -> 200). Internal alt: the in-cluster\\n  // graphdb svc on :7200, but that's plaintext.\\n  graphDBMcpUrl: \\"https://graphdb-projects.kaiser.gw-pse.com/mcp\\",\\n\\n  // main repo in GraphDB, used on [Step - GraphDB MCP - Async] workflow\\n  graphDBMcpRepository: \\"coverage\\",\\n  // name of the graph holding the ontology, used on [Step - GraphDB MCP - Async].\\n  // Step 1 loads ontology.ttl into the DEFAULT graph, so this is empty (empty = default graph).\\n  graphDBMcpOntologyGraph: \\"\\",\\n  // max triples returned by fts-search, used on [Step - GraphDB MCP - Async]\\n  graphDBMcpFtsSearchTriplesLimit: 100,\\n\\n  // n8n internal URL (service-to-service, not a browser URL)\\n  internalN8nUrl: \\"http://graphrag-workflows:5678\\",            // VERIFIED svc (graphrag ns, ClusterIP :5678)\\n\\n  // Keycloak — verifies the provided JWT token.\\n  // LEFT AT SEED DEFAULT on purpose: exec #23 ran deep (post-processing) before failing\\n  // ONLY on backendUrl, so JWT verification is NOT blocking this flow — don't introduce an\\n  // untested change here. If a JWT/auth error ever appears, the in-cluster Keycloak is\\n  // `http://graphwise-keycloak-service.keycloak:8080` (:8080 = http; :9000 is the mgmt port).\\n  keycloakUrl: \\"https://auth.kaiser.gw-pse.com\\",\\n  keycloakRealm: \\"graphrag\\",\\n\\n  // LLM models — Bedrock only (the filled `aws` credential). IDs must be enabled in\\n  // your Bedrock account/region; upgrade to the latest Claude you have access to\\n  // (e.g. anthropic.claude-opus-4-8) for best answer quality.\\n  mcpLLMModel: \\"us.anthropic.claude-sonnet-4-6\\",        // GraphDB-MCP / tool-calling LLM\\n  primaryLLMModel: \\"us.anthropic.claude-sonnet-4-6\\",    // main answer LLM\\n  secondaryLLMModel: \\"us.anthropic.claude-haiku-4-5-20251001-v1:0\\",    // utility calls (guardrails, follow-ups)\\n\\n  // PoolParty (the Graph Modeling extractor)\\n  poolPartyServerUrl: \\"https://poolparty.kaiser.gw-pse.com\\",\\n  poolPartyProjectId: \\"20670b0b-0ae0-42b1-ae0e-cf11c01ffac3\\",     // literal (same project as the Extractor); NOT $env — this node may not have env access enabled, which would throw\\n\\n  // Vector search endpoint (internal service)\\n  vectorSearchUrl: `${graphRagComponentsUrl}/vector/search`,\\n\\n  /**\\n   * The mappings preset to use for the vector store, possible values are:\\n   * - \\"bedrock_knowledgebase\\"\\n   * - \\"elasticsearch_native\\"\\n   * - \\"opensearch_native\\"\\n   * - \\"pinecone\\"\\n   * - \\"qdrant\\"\\n   * - \\"weaviate\\"\\n   * - \\"custom\\" -> requires setting the mappings manually in property \\"vectorStoreCustomMappins\\"\\n   */\\n  \\"vectorStorePreset\\": \\"elasticsearch_native\\",                   // was opensearch_native\\n\\n  /**\\n   * Vector store mappings to use in case the preset is set to \\"custom\\".\\n   * e.g.:\\n   * {\\n   *   \\"payload\\": \\"metadata.content\\",\\n   *   \\"source\\": \\"metadata.source_link\\",\\n   *   \\"score\\": \\"score\\",\\n   *   \\"id\\": \\"id\\"\\n   * }\\n   */\\n  \\"vectorStoreCustomMappins\\": {},\\n\\n  // Whether to pass through the metadata from the vector store results or not.\\n  \\"vectorStoreMetadataPassthrough\\": true,\\n  // Array of properties to exclude (set to null) from the passed through metadata, e.g. [\\"source_link\\", \\"content\\"]\\n  \\"vectorStoreMetadataExclude\\": [],\\n\\n  // Index name. (The doc-comment below is the seed's; on this build graphrag-components\\n  // has no INDEX env, so the ES index name must be set here.)\\n  \\"vectorIndex\\": \\"doc-chunks\\",                                // was \\"\\" — the Unstructured Ingest index\\n  \\"embeddingsProvider\\": \\"aws\\",                                   // \\"aws\\" or \\"openai\\"\\n  \\"embeddingsModelId\\": \\"amazon.titan-embed-text-v2:0\\",           // MUST byte-match the corpus model (Unstructured Ingest used amazon.titan-embed-text-v2:0) or kNN breaks; was cohere.embed-english-v3\\n\\n  /**\\n   * Concept Enrichment - Which properties should be fetched for each of the concepts extracted from the asked question and generated answer? (used as context and in the UI)\\n   * Possible values are SKOS properties (e.g. \\"skos:prefLabel\\", \\"skos:narrower\\", ...) or any full URI of a custom property (e.g. https://example.com/MyScheme/MyRelation).\\n   */\\n  \\"conceptProperties\\": [\\"skos:prefLabel\\", \\"skos:altLabel\\", \\"skos:definition\\", \\"skos:scopeNote\\", \\"skos:example\\", \\"skos:broader\\", \\"skos:narrower\\", \\"skos:related\\"],\\n\\n  // Memory / Limits\\n  shortMemoryMaxUncompressedSizeInTokens: 300,\\n\\n  // Timeout in seconds for first batch of parallel steps. Usually: Max(timeouts of parallel steps) + small_value, small_value in [1,5]\\n  parallelStepsMaxTiemout: 65\\n};\\n"},"typeVersion":2,"name":"Configuration","position":[-32,16],"id":"b8a924ff-4f59-497d-9ca2-0f28b86e455d","type":"n8n-nodes-base.code"},{"parameters":{"inputSource":"passthrough"},"typeVersion":1.1,"name":"When executed by another workflow","position":[-224,16],"id":"044a6b03-bfb3-44ff-8253-eeebfa86e32a","type":"n8n-nodes-base.executeWorkflowTrigger"}]	{"When executed by another workflow":{"main":[[{"node":"Configuration","index":0,"type":"main"}]]}}	2026-03-27 08:43:56.482+00	2026-07-06 21:07:42.647+00	{"executionOrder":"v1","binaryMode":"separate"}	\N	{}	6ac8f25a-e07c-41f2-9be4-eb92eda58f4a	0	HJcJwMTssnY79HWw	{"instanceId":"982a83c4fa14b8860ea8391b8f766ad449d7431aac64126d0b9fc936877b58be"}	\N	f	47	\N	6ac8f25a-e07c-41f2-9be4-eb92eda58f4a	[]
Check for timeouts	t	[{"typeVersion":1.1,"name":"Execute workflow","position":[-352,0],"id":"2afe5662-71dc-42fb-8e2a-cd0b3528a0e8","type":"n8n-nodes-base.executeWorkflowTrigger","parameters":{"workflowInputs":{"values":[{"name":"activeFlags","type":"object"},{"name":"executionId"},{"name":"questionId"},{"name":"conversationId"},{"name":"userId"},{"name":"backendSseMessageUrl"}]}}},{"typeVersion":1.1,"name":"Get all rows for the executionId","position":[-144,0],"id":"d3b10bc7-c127-420f-a5ae-6605b7b58c04","type":"n8n-nodes-base.dataTable","parameters":{"matchType":"=anyCondition","dataTableId":{"mode":"list","cachedResultUrl":"/projects/GOpLcxWJaB3HU9kV/datatables/Pw5o6pE18gKIpnNT","__rl":true,"cachedResultName":"PARALLEL_SYNC_DATA","value":"VQol99zJXwRSl6hz"},"filters":{"conditions":[{"keyValue":"={{ $json.executionId }}","keyName":"executionId"}]},"operation":"get"},"alwaysOutputData":true},{"typeVersion":1,"name":"Sticky Note29","position":[224,-48],"id":"fb27a167-ac87-44ad-b74f-dc8f1c426374","type":"n8n-nodes-base.stickyNote","parameters":{"color":5,"width":448,"content":"Explainability message","height":240}},{"typeVersion":2,"name":"Find missing steps","position":[64,0],"id":"35d0904e-7461-4a38-8161-21fe826fb6df","type":"n8n-nodes-base.code","parameters":{"jsCode":"// n8n Code node\\n// Returns missing active steps as items: [{ json: { stepTag, message } }]\\n\\n\\nconst stepItems = $('Get all rows for the executionId').all().map(item => item.json);\\nconst activeFlagsContainer = $('Execute workflow').first().json;\\n\\n// Validate activeFlags input\\nconst activeFlags = activeFlagsContainer?.activeFlags || {};\\n\\n// ------------------------------------------------------------\\n// 3) Build a set of existing step names from the first input array\\n// ------------------------------------------------------------\\nconst existingSteps = new Set(\\n  stepItems\\n    .map(x => x.step)\\n    .filter(step => typeof step === \\"string\\" && step.length > 0)\\n);\\n\\n// Collect missing active steps\\nconst missing = Object.values(activeFlags)\\n  .filter(flag => flag?.isActive === true && flag?.stepTag)\\n  .filter(flag => !existingSteps.has(flag.stepTag))\\n  .map(flag => ({\\n    stepName: flag.stepName,\\n    message: flag.message || `Step \\"${flag.stepTag}\\" is missing`,\\n  }));\\n\\nreturn missing.map(item => ({ json: item }));"}},{"typeVersion":2,"name":"Build Ex message - Step has timed out","position":[288,0],"id":"b3ac79c6-aac6-4321-9e5f-1512c56eb434","type":"n8n-nodes-base.code","parameters":{"mode":"runOnceForEachItem","jsCode":"return {     \\n  \\"questionId\\": $('Execute workflow').first().json.questionId,\\n  \\"conversationId\\": $('Execute workflow').first().json.conversationId,\\n  \\"userId\\": $('Execute workflow').first().json.userId,\\n  \\"messageType\\": \\"EXPLAINABILITY\\",\\n  \\"payload\\":{\\n    \\"stepName\\": $json.stepName,\\n    \\"description\\": $json.message,\\n    \\"noticeType\\": \\"ERROR\\"\\n  }\\n};"}},{"typeVersion":4.2,"notesInFlow":false,"name":"Send Ex message - Step has timed out","position":[480,0],"id":"8d8a6780-6c61-4529-a22f-34a0185af3bb","type":"n8n-nodes-base.httpRequest","parameters":{"sendQuery":true,"method":"POST","queryParameters":{"parameters":[{"name":"questionId","value":"={{ $('Execute workflow').first().json.questionId }}"}]},"headerParameters":{"parameters":[{"name":"Accept","value":"application/json"}]},"sendBody":true,"options":{},"body":"={{ JSON.stringify( $json ) }}","sendHeaders":true,"contentType":"raw","url":"={{ $('Execute workflow').first().json.backendSseMessageUrl }}","rawContentType":"application/json"}}]	{"Execute workflow":{"main":[[{"node":"Get all rows for the executionId","index":0,"type":"main"}]]},"Find missing steps":{"main":[[{"node":"Build Ex message - Step has timed out","index":0,"type":"main"}]]},"Build Ex message - Step has timed out":{"main":[[{"node":"Send Ex message - Step has timed out","index":0,"type":"main"}]]},"Get all rows for the executionId":{"main":[[{"node":"Find missing steps","index":0,"type":"main"}]]}}	2026-03-27 08:43:56.482+00	2026-03-27 08:43:56.482+00	{"availableInMCP":false,"executionOrder":"v1"}	\N	{}	9509593a-71ec-40aa-9a48-3c70b97cff06	0	hGEZ9J9UJcOKiqC2qWJoa	{"instanceId":"982a83c4fa14b8860ea8391b8f766ad449d7431aac64126d0b9fc936877b58be"}	\N	f	3	\N	9509593a-71ec-40aa-9a48-3c70b97cff06	[]
N8N Prune Database	f	[{"parameters":{"jsCode":"const executionsToKeep = $input.first().json.executionsToKeep ?? 10;\\n\\n// Filtrar ejecuciones válidas (con workflowId y startedAt)\\nconst validExecutions = items.filter(item =>\\n  item.json.workflowId && item.json.startedAt\\n);\\n\\n// Agrupar por workflowId\\nconst grouped = {};\\nfor (const item of validExecutions) {\\n  const wfId = item.json.workflowId;\\n  if (!grouped[wfId]) grouped[wfId] = [];\\n  grouped[wfId].push(item);\\n}\\n\\n// Ordenar por startedAt descendente (más reciente primero)\\nfor (const wfId in grouped) {\\n  grouped[wfId].sort((a, b) =>\\n    new Date(b.json.startedAt) - new Date(a.json.startedAt)\\n  );\\n}\\n\\n// Obtener ejecuciones a eliminar\\nlet toDelete = [];\\nfor (const wfId in grouped) {\\n  const executions = grouped[wfId];\\n  if (executions.length > executionsToKeep) {\\n    toDelete = toDelete.concat(executions.slice(executionsToKeep));\\n  }\\n}\\n\\nreturn toDelete;\\n"},"id":"69de7938-3bf9-4623-858b-421840644078","name":"Code","type":"n8n-nodes-base.code","position":[1616,1904],"typeVersion":2},{"parameters":{"resource":"execution","operation":"delete","executionId":"={{ $json.id }}","requestOptions":{}},"id":"fa096efe-78ed-4f9c-8f6d-6c2bfd47b808","name":"Delete an execution","type":"n8n-nodes-base.n8n","position":[1840,1904],"typeVersion":1,"credentials":{"n8nApi":{"id":"d8V1TgO9ZOjyzOsp","name":"n8n Internals"}}},{"parameters":{"assignments":{"assignments":[{"id":"a7f3a2de-0606-434c-8a81-4bf64e766899","name":"executionsToKeep","type":"number","value":0}]},"includeOtherFields":true,"options":{}},"id":"5b00d83c-c3e6-4687-b471-cb12189b2ea6","name":"Set Executions to Keep","type":"n8n-nodes-base.set","position":[1392,1904],"typeVersion":3.4},{"parameters":{},"type":"n8n-nodes-base.manualTrigger","typeVersion":1,"position":[944,1904],"id":"463fd00e-b7bb-4a43-8572-a3a03bdede67","name":"When clicking ‘Execute workflow’"},{"parameters":{"resource":"execution","returnAll":true,"filters":{},"options":{},"requestOptions":{}},"type":"n8n-nodes-base.n8n","typeVersion":1,"position":[1168,1904],"id":"90daabb8-643f-44a4-86ca-6e38d38e181c","name":"Get many executions","credentials":{"n8nApi":{"id":"d8V1TgO9ZOjyzOsp","name":"n8n Internals"}}}]	{"Code":{"main":[[{"node":"Delete an execution","type":"main","index":0}]]},"Set Executions to Keep":{"main":[[{"node":"Code","type":"main","index":0}]]},"When clicking ‘Execute workflow’":{"main":[[{"node":"Get many executions","type":"main","index":0}]]},"Get many executions":{"main":[[{"node":"Set Executions to Keep","type":"main","index":0}]]}}	2026-06-29 19:42:04.923+00	2026-07-06 04:42:39.078+00	{"executionOrder":"v1","binaryMode":"separate"}	{"node:Schedule Trigger":{"recurrenceRules":[]}}	{}	30e2063e-cfd2-4cef-b50e-236d07aaae3a	1	2xMSrzcUyicneaFc	{"templateCredsSetupCompleted":true}	\N	f	34	\N	\N	[]
Extractor	f	[{"parameters":{},"id":"ee3fc154-9c58-4adb-9c3c-395756cd674c","name":"Start","type":"n8n-nodes-base.manualTrigger","typeVersion":1,"position":[10560,5456]},{"parameters":{"fields":{"values":[{"name":"graphdb","stringValue":"https://graphdb-projects.kaiser.gw-pse.com/repositories/coverage/statements"},{"name":"poolparty","stringValue":"https://poolparty.kaiser.gw-pse.com/extractor/api/tag"},{"name":"csvDir","stringValue":"/data/staging/output"},{"name":"rdfDir","stringValue":"/data/staging/output"},{"name":"prefixes","stringValue":"@prefix kpkg: <https://kp.poolparty.biz/kg/ontology#> .\\n@prefix rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#> .\\n@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .\\n@prefix skos: <http://www.w3.org/2004/02/skos/core#> .\\n@prefix skosxl: <http://www.w3.org/2008/05/skos-xl#> .\\n@prefix owl: <http://www.w3.org/2002/07/owl#> .\\n@prefix dc: <http://purl.org/dc/elements/1.1/> .\\n@prefix dcterms: <http://purl.org/dc/terms/> .\\n@prefix csw: <http://semantic-web.at/ontologies/csw.owl#> .\\n@prefix ctag: <http://commontag.org/ns#> .\\n@prefix opencyc: <http://sw.opencyc.org/concept/> .\\n@prefix freebase: <http://rdf.freebase.com/ns/> .\\n@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .\\n@prefix tags: <http://www.holygoat.co.uk/owl/redwood/0.1/tags/> .\\n@prefix foaf: <http://xmlns.com/foaf/0.1/> .\\n@prefix cyc: <http://sw.cyc.com/concept/> .\\n@prefix cycAnnot: <http://sw.cyc.com/CycAnnotations_v1#> .\\n@prefix dbpedia: <http://dbpedia.org/resource/> .\\n\\n"},{"name":"extractorProjectId","stringValue":"={{ $env.EXTRACTOR_PROJECT_ID }}"},{"name":"extractorAuth","stringValue":"={{ $env.EXTRACTOR_AUTH }}"},{"name":"annotationGraph","stringValue":"https://kp.poolparty.biz/kg/annotations/"},{"name":"chunkAnnotationGraph","stringValue":"https://kp.poolparty.biz/kg/chunk-annotations/"},{"name":"chunksGraph","stringValue":"https://kp.poolparty.biz/kg/chunks/"},{"name":"extractorConcurrency","stringValue":"16"},{"name":"extractorBatchSize","stringValue":"64"}]},"options":{}},"id":"235e1dc5-788b-46d9-a8dc-7244016f32ad","name":"Config","type":"n8n-nodes-base.set","typeVersion":3,"position":[10752,5456]},{"parameters":{"url":"https://poolparty.kaiser.gw-pse.com/extractor/api/heartbeat","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Accept","value":"application/json"},{"name":"Authorization","value":"={{ $('Config').first().json.extractorAuth }}"}]},"options":{}},"id":"0f65f25b-0cfc-4e27-ab46-1f03329f1ed6","name":"Test: PoolParty Heartbeat","type":"n8n-nodes-base.httpRequest","typeVersion":4,"position":[11104,5664]},{"parameters":{"url":"={{ $('Config').first().json.poolparty.replace('api/tag', 'api/projects/') + $('Config').first().json.extractorProjectId }}","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Accept","value":"application/json"},{"name":"Authorization","value":"={{ $('Config').first().json.extractorAuth }}"}]},"options":{}},"id":"327c7820-2f96-4fcd-86b6-9946b93f376f","name":"Test: PoolParty Project","type":"n8n-nodes-base.httpRequest","typeVersion":4,"position":[11296,5664]},{"parameters":{"url":"={{ $('Config').first().json.graphdb.replace('/statements', '') }}","sendQuery":true,"queryParameters":{"parameters":[{"name":"query","value":"={{ \\"SELECT ?node ?text ?nodeType\\\\nWHERE {\\\\n  ?node <https://kp.poolparty.biz/kg/ontology#chunkText> ?text .\\\\n  FILTER(CONTAINS(STR(?node), \\\\\\"/chunk/\\\\\\"))\\\\n  BIND(\\\\\\"Chunk\\\\\\" AS ?nodeType)\\\\n}\\\\nORDER BY ?node\\\\nLIMIT \\" + $json.pageSize + \\"\\\\nOFFSET \\" + $json.offset }}"}]},"sendHeaders":true,"headerParameters":{"parameters":[{"name":"Accept","value":"application/sparql-results+json"}]},"options":{"response":{"response":{"neverError":true}},"timeout":60000}},"id":"93ac3802-2786-4ea0-bf00-ba24fd87a32f","name":"Query: All Text Nodes","type":"n8n-nodes-base.httpRequest","typeVersion":4,"position":[11056,5984]},{"parameters":{"jsCode":"// Parse the SPARQL SELECT results from GraphDB into individual items.\\n// Each item becomes one call to the PoolParty Extractor.\\n//\\n// The n8n HTTP Request node sometimes wraps the response body in a\\n// { data: \\"<json-string>\\" } envelope. We unwrap it before parsing.\\n//\\n// Paginated: this runs once per GraphDB page (see Page: Init/Next and the\\n// LIMIT/OFFSET added to Query: All Text Nodes). After each page, records in\\n// workflow static data whether more pages remain (a short page -- fewer\\n// bindings than the requested page size -- means we've reached the end) and\\n// advances the offset for the next page.\\n\\nlet data = $json;\\n\\n// Unwrap { data: \\"<json-string>\\" } or { data: {object} }\\nif (data && data.data !== undefined) {\\n  if (typeof data.data === 'string') {\\n    try { data = JSON.parse(data.data); } catch(e) {}\\n  } else if (typeof data.data === 'object') {\\n    data = data.data;\\n  }\\n}\\n\\nconst cfg      = $('Config').first().json;\\nconst pageSize = Number(cfg.extractorBatchSize) || 500;\\nconst sd       = $getWorkflowStaticData('global');\\n\\nif (!data || !data.results || !Array.isArray(data.results.bindings)) {\\n  console.log('No results from GraphDB SPARQL query -- treating as last page');\\n  sd.extractorIsLastPage = true;\\n  return [{ json: { error: 'No results', raw: JSON.stringify($json).slice(0, 400) } }];\\n}\\n\\nconst bindings = data.results.bindings;\\nconst isLastPage = bindings.length < pageSize;\\nsd.extractorIsLastPage = isLastPage;\\nsd.extractorOffset     = (sd.extractorOffset || 0) + pageSize;\\nsd.extractorPageNum    = (sd.extractorPageNum || 0) + 1;\\nconsole.log(`SPARQL page ${sd.extractorPageNum}: ${bindings.length} text nodes${isLastPage ? ' (last page)' : ''}`);\\n\\n// De-duplicate by node URI (a node may appear if it has multiple text values)\\nconst seen = new Set();\\nconst items = [];\\nfor (const b of bindings) {\\n  const nodeUri  = b.node?.value  || '';\\n  const text     = b.text?.value  || '';\\n  const nodeType = b.nodeType?.value || '';\\n  if (!nodeUri || !text || seen.has(nodeUri)) continue;\\n  seen.add(nodeUri);\\n  items.push({ json: { nodeUri, text, nodeType } });\\n}\\n\\nconsole.log(`${items.length} unique nodes to annotate this page`);\\nreturn items;\\n"},"id":"1d49e8fa-f280-476b-86cc-440c6aa835ca","name":"Parse: SPARQL Results → Items","type":"n8n-nodes-base.code","typeVersion":2,"position":[11328,5904]},{"parameters":{"method":"POST","url":"={{ $('Config').first().json.graphdb }}","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Content-Type","value":"application/sparql-update"}]},"sendBody":true,"contentType":"raw","rawContentType":"application/sparql-update","body":"DROP SILENT GRAPH <https://kp.poolparty.biz/kg/annotations/> ; DROP SILENT GRAPH <https://kp.poolparty.biz/kg/chunk-annotations/>","options":{"response":{"response":{"neverError":true}},"timeout":30000}},"id":"4d15220e-c06c-4505-83b2-5ffa6705d824","name":"Drop: Both Annotation Graphs","type":"n8n-nodes-base.httpRequest","typeVersion":4,"position":[11488,5664]},{"parameters":{"jsCode":"// Verify both annotation graphs: tags present and every concept resolves to skos:Concept.\\nconst graphdb = $('Config').first().json.graphdb.replace('/statements', '');\\nconst P = 'PREFIX kpkg: <https://kp.poolparty.biz/kg/ontology#> PREFIX skos: <http://www.w3.org/2004/02/skos/core#> ';\\nconst GRAPHS = {\\n  structured: 'https://kp.poolparty.biz/kg/annotations/',\\n  chunks:     'https://kp.poolparty.biz/kg/chunk-annotations/',\\n};\\n\\nasync function sparql(query) {\\n  const m = graphdb.match(/^https:\\\\/\\\\/([^\\\\/]+)(.*)/);\\n  const path = m[2] + '?query=' + encodeURIComponent(query);\\n  return new Promise((resolve) => {\\n    const https = require('https');\\n    https.get({ hostname: m[1], path, headers: { Accept: 'application/sparql-results+json' } }, (res) => {\\n      let d = ''; res.on('data', c => d += c);\\n      res.on('end', () => { try { resolve(JSON.parse(d)); } catch { resolve(null); } });\\n    }).on('error', () => resolve(null));\\n  });\\n}\\nconst count = (r) => r ? parseInt(r.results.bindings[0]?.c?.value || '0') : -1;\\n\\nconst out = {};\\nlet allPass = true;\\nfor (const [name, g] of Object.entries(GRAPHS)) {\\n  const tags = count(await sparql(`${P}SELECT (COUNT(*) AS ?c) WHERE { GRAPH <${g}> { ?n kpkg:hasConcept ?k } }`));\\n  const dangling = count(await sparql(`${P}SELECT (COUNT(DISTINCT ?k) AS ?c) WHERE { GRAPH <${g}> { ?n kpkg:hasConcept ?k } FILTER NOT EXISTS { ?k a skos:Concept } }`));\\n  const pass = tags > 0 && dangling === 0;\\n  if (!pass) allPass = false;\\n  out[name] = { graph: g, tags, dangling, pass };\\n}\\nconsole.log('EXTRACTOR VERIFY');\\nfor (const [name, r] of Object.entries(out))\\n  console.log(`  ${r.pass ? '✓' : '✗'} ${name.padEnd(11)} tags=${r.tags} dangling=${r.dangling}`);\\nconsole.log(allPass ? 'ALL CHECKS PASSED' : 'SOME CHECKS FAILED');\\nreturn [{ json: { allPass, graphs: out } }];\\n"},"id":"c1747bf8-0453-4c64-a8a0-8277e9735530","name":"Verify: Annotation Counts","type":"n8n-nodes-base.code","typeVersion":2,"position":[12416,5760]},{"parameters":{"jsCode":"const v = $input.first().json;\\nconst graphs = v.graphs || {};\\n\\nconst checkLines = Object.entries(graphs).map(([name, r]) =>\\n  `${r.pass ? '✓' : '✗'}  ${name.padEnd(11)}  tags=${String(r.tags).padStart(6)}  dangling=${r.dangling}  ${r.graph}`\\n);\\n\\nconsole.log([\\n  'Extractor — Verify Complete',\\n  '',\\n  ...checkLines,\\n  '',\\n  v.allPass\\n    ? 'ALL CHECKS PASSED — annotations loaded into both named graphs.'\\n    : 'SOME CHECKS FAILED — review Extractor and load steps.',\\n  '',\\n  'Re-run this workflow any time the taxonomy changes.',\\n  'Base data (Phase 1) does NOT need to be re-run.',\\n].join('\\\\n'));\\n\\nreturn [{ json: {\\n  status:  v.allPass ? '✓ ALL CHECKS PASSED' : '✗ SOME CHECKS FAILED',\\n  checks:  checkLines,\\n  graphs:  v.graphs,\\n} }];"},"id":"302917c5-64c7-4037-b0ed-61f78d974944","name":"Format Summary","type":"n8n-nodes-base.code","typeVersion":2,"position":[12640,5760]},{"parameters":{"jsCode":"// Runs exactly once per workflow execution -- this node sits outside every\\n// loop, right after Config, and is never a loop-back target. Resets\\n// pagination bookkeeping in workflow static data, which otherwise PERSISTS\\n// across separate manual runs and would make a fresh execution wrongly\\n// resume from a previous run's leftover offset instead of starting over.\\nconst sd = $getWorkflowStaticData('global');\\nsd.extractorOffset = 0;\\nsd.extractorIsLastPage = false;\\nsd.extractorPageNum = 0;\\nconsole.log('[extractor] pagination state reset for this run');\\nreturn $input.all();"},"id":"0a987290-9ec2-4257-ad76-66ecc228d2b8","name":"Reset: Pagination State","type":"n8n-nodes-base.code","typeVersion":2,"position":[10928,5568]},{"parameters":{"jsCode":"// Entry point for each GraphDB page fetch -- reached both on the first page\\n// (from Test: PoolParty Project) and on every later page (via Page: More?'s\\n// loop-back edge). Reads the current offset from workflow static data\\n// (written by Parse: SPARQL Results after the PREVIOUS page) and passes it\\n// downstream to Query: All Text Nodes.\\nconst cfg = $('Config').first().json;\\nconst pageSize = Number(cfg.extractorBatchSize) || 500;\\nconst sd = $getWorkflowStaticData('global');\\nif (sd.extractorOffset === undefined) sd.extractorOffset = 0;\\nconsole.log(`[extractor] fetching page ${(sd.extractorPageNum || 0) + 1} at offset=${sd.extractorOffset}, pageSize=${pageSize}`);\\nreturn [{ json: { offset: sd.extractorOffset, pageSize } }];\\n"},"id":"da47cf63-a4eb-4fda-9cd4-fb093bff6803","name":"Page: Init/Next","type":"n8n-nodes-base.code","typeVersion":2,"position":[10800,5904]},{"parameters":{"conditions":{"options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":1},"conditions":[{"id":"extractor-last-page","leftValue":"={{ $getWorkflowStaticData('global').extractorIsLastPage }}","rightValue":true,"operator":{"type":"boolean","operation":"equals"}}],"combinator":"and"},"options":{}},"id":"91519ffe-b61b-43b8-ae62-3f3c59f1ac1a","name":"Page: More?","type":"n8n-nodes-base.if","typeVersion":2,"position":[12032,5984]},{"parameters":{"jsCode":"// Extracts PoolParty annotations for this page's chunks and writes the\\n// resulting triples DIRECTLY to GraphDB's chunk-annotations graph, per\\n// sub-batch, as soon as they're produced -- no local TTL file, no separate\\n// Split In Batches loop.\\n//\\n// Replaces: Loop: Chunks, Call Extractor, Aggregate: All Annotation Triples,\\n// and Load: Chunks -> chunk-annotations. Those existed as four separate n8n\\n// nodes relying on Split In Batches' loop-back semantics, which turned out to\\n// be unreliable here -- items from earlier passes kept reappearing on later\\n// passes, duplicating triples into chunk_annotations.ttl on every iteration.\\n// Doing the sub-batching as a plain JS loop inside one node removes that\\n// dependency entirely. Writing directly to GraphDB also means duplicate work\\n// is harmless: RDF graphs are sets, so inserting the same triple twice is a\\n// no-op, unlike appending to a file.\\n//\\n// (Structured annotations are not used in this deployment -- see the removed,\\n// disabled \\"Load: Structured -> annotations\\" node -- so this only writes to\\n// the chunk-annotations graph.)\\n\\nconst https = require('https');\\nconst cfg   = $('Config').first().json;\\nconst CONCURRENCY = Number(cfg.extractorConcurrency) || 8;\\nconst SUBBATCH    = Number(cfg.extractorBatchSize)   || 50;\\n\\nconst KP_BASE   = 'https://kpd.poolparty.biz/';\\nconst UMLS_BASE = 'https://uts.nlm.nih.gov/metathesaurus/';\\n\\n// Annotate one chunk via the PoolParty extractor.\\nasync function extract(d) {\\n  const nodeUri = String(d.nodeUri || '');\\n  const text    = String(d.text    || '');\\n  if (!nodeUri || !text) return { skipped: true, reason: 'missing nodeUri or text' };\\n\\n  const boundary = '----PoolPartyBoundary' + Date.now() + Math.random().toString(16).slice(2);\\n  const CRLF     = '\\\\r\\\\n';\\n  const params = JSON.stringify({\\n    projectId:                    [cfg.extractorProjectId],\\n    language:                     'en',\\n    numberOfConcepts:             25,\\n    useTransitiveBroaderConcepts: true\\n  });\\n  const body = [\\n    `--${boundary}`,\\n    'Content-Disposition: form-data; name=\\"params\\"',\\n    'Content-Type: application/json',\\n    '',\\n    params,\\n    `--${boundary}`,\\n    'Content-Disposition: form-data; name=\\"data\\"',\\n    'Content-Type: text/plain; charset=utf-8',\\n    '',\\n    text,\\n    `--${boundary}--`,\\n    ''\\n  ].join(CRLF);\\n  const bodyBuf = Buffer.from(body, 'utf-8');\\n\\n  const m = cfg.poolparty.match(/^https:\\\\/\\\\/([^\\\\/]+)(.*)/);\\n  if (!m) return { nodeUri, skipped: false, triples: null,\\n    extractorError: 'Cannot parse poolparty URL: ' + cfg.poolparty };\\n\\n  const result = await new Promise((resolve) => {\\n    const req = https.request(\\n      {\\n        hostname: m[1],\\n        path:     m[2],\\n        method:   'POST',\\n        headers: {\\n          'Content-Type':   `multipart/form-data; boundary=${boundary}`,\\n          'Content-Length': bodyBuf.length,\\n          'Accept':         'application/json',\\n          'Authorization':  cfg.extractorAuth\\n        }\\n      },\\n      (res) => {\\n        let data = '';\\n        res.on('data', chunk => data += chunk);\\n        res.on('end', () => {\\n          if (res.statusCode >= 200 && res.statusCode < 300) {\\n            try   { resolve({ ok: true,  body: JSON.parse(data) }); }\\n            catch { resolve({ ok: false, status: res.statusCode,\\n              body: 'Non-JSON: ' + data.slice(0, 300) }); }\\n          } else {\\n            resolve({ ok: false, status: res.statusCode, body: data.slice(0, 300) });\\n          }\\n        });\\n      }\\n    );\\n    req.on('error', e => resolve({ ok: false, status: 0, body: 'https.request: ' + e.message }));\\n    req.write(bodyBuf);\\n    req.end();\\n  });\\n\\n  if (!result.ok) {\\n    console.log(`Extractor error for ${nodeUri}: HTTP ${result.status} — ${result.body}`);\\n    return { nodeUri, skipped: false, triples: null,\\n      extractorError: `HTTP ${result.status}: ${String(result.body)}` };\\n  }\\n\\n  const response = result.body;\\n  let concepts = [];\\n  if (Array.isArray(response) && response[0]?.documentId !== undefined) {\\n    for (const doc of response) if (Array.isArray(doc.concepts)) concepts.push(...doc.concepts);\\n  } else if (Array.isArray(response))         { concepts = response; }\\n  else if (Array.isArray(response?.concepts)) { concepts = response.concepts; }\\n\\n  if (concepts.length === 0) return { nodeUri, skipped: false, triples: null, conceptCount: 0 };\\n\\n  // Collect KP taxonomy URIs: direct matches + UMLS CUIs resolved via broader.\\n  const uriSet = new Set();\\n  for (const concept of concepts) {\\n    const uri = concept.uri || '';\\n    if (uri.startsWith(KP_BASE)) {\\n      uriSet.add(uri);\\n    } else if (uri.startsWith(UMLS_BASE)) {\\n      for (const b of (concept.broaderConcepts || []))\\n        if (typeof b === 'string' && b.startsWith(KP_BASE)) uriSet.add(b);\\n      for (const b of (concept.transitiveBroaderConcepts || []))\\n        if (typeof b === 'string' && b.startsWith(KP_BASE)) uriSet.add(b);\\n    }\\n  }\\n\\n  const conceptUris = [...uriSet];\\n  if (conceptUris.length === 0) return { nodeUri, skipped: false, triples: null, conceptCount: 0,\\n    rawConceptSample: JSON.stringify(concepts[0]).slice(0, 400) };\\n\\n  const lines = conceptUris.map(u => `    <https://kp.poolparty.biz/kg/ontology#hasConcept> <${u}> ;`);\\n  lines[lines.length - 1] = lines[lines.length - 1].replace(' ;', ' .');\\n  const triples = `<${nodeUri}>\\\\n${lines.join('\\\\n')}`;\\n  return { nodeUri, skipped: false, triples, conceptCount: conceptUris.length };\\n}\\n\\n// POST a sub-batch's triples straight to GraphDB's chunk-annotations graph.\\nfunction loadToGraphDB(triples) {\\n  if (triples.length === 0) return Promise.resolve({ ok: true, skipped: true });\\n  const bodyBuf = Buffer.from(triples.join('\\\\n'), 'utf-8');\\n  const ctx = encodeURIComponent('<https://kp.poolparty.biz/kg/chunk-annotations/>');\\n  const url = `${cfg.graphdb}?context=${ctx}`;\\n  const m = url.match(/^https:\\\\/\\\\/([^\\\\/]+)(.*)/);\\n  return new Promise((resolve) => {\\n    const req = https.request(\\n      { hostname: m[1], path: m[2], method: 'POST',\\n        headers: { 'Content-Type': 'text/turtle', 'Content-Length': bodyBuf.length } },\\n      (res) => { let d = ''; res.on('data', c => d += c);\\n        res.on('end', () => resolve({ ok: res.statusCode >= 200 && res.statusCode < 300, status: res.statusCode, body: d.slice(0, 300) })); }\\n    );\\n    req.on('error', e => resolve({ ok: false, status: 0, body: 'https.request: ' + e.message }));\\n    req.write(bodyBuf);\\n    req.end();\\n  });\\n}\\n\\nconst allItems = $input.all().map(i => i.json);\\nlet annotated = 0, noMatch = 0, skipped = 0, errors = 0;\\n\\nfor (let s = 0; s < allItems.length; s += SUBBATCH) {\\n  const slice = allItems.slice(s, s + SUBBATCH);\\n  const out = new Array(slice.length);\\n  let cursor = 0;\\n  async function worker() {\\n    while (true) {\\n      const i = cursor++;\\n      if (i >= slice.length) return;\\n      out[i] = await extract(slice[i]);\\n    }\\n  }\\n  await Promise.all(Array.from({ length: Math.min(CONCURRENCY, slice.length) }, worker));\\n\\n  const triples = [];\\n  for (const d of out) {\\n    if (d.skipped)        { skipped++; continue; }\\n    if (d.extractorError) { errors++;  if (errors <= 3) console.log(`Extractor error: ${d.nodeUri} — ${d.extractorError}`); continue; }\\n    if (!d.triples)       { noMatch++; continue; }\\n    triples.push(d.triples);\\n    annotated++;\\n  }\\n\\n  const loadResult = await loadToGraphDB(triples);\\n  if (!loadResult.ok && !loadResult.skipped) {\\n    throw new Error(`GraphDB load failed for sub-batch at offset ${s}: HTTP ${loadResult.status} ${loadResult.body}`);\\n  }\\n  console.log(`[extract] sub-batch ${Math.floor(s / SUBBATCH) + 1}/${Math.ceil(allItems.length / SUBBATCH)}: ${slice.length} chunks, ${triples.length} triples loaded`);\\n}\\n\\nconsole.log(`[extract] page complete: annotated=${annotated} noMatch=${noMatch} skipped=${skipped} errors=${errors}`);\\nreturn [{ json: { annotated, noMatch, skipped, errors } }];"},"id":"3eb1d09a-215d-42c2-8728-c5fd2f11b66e","name":"Extract + Load: Chunks","type":"n8n-nodes-base.code","typeVersion":2,"position":[11680,5984]}]	{"Start":{"main":[[{"node":"Config","type":"main","index":0}]]},"Config":{"main":[[{"node":"Reset: Pagination State","type":"main","index":0}]]},"Test: PoolParty Heartbeat":{"main":[[{"node":"Test: PoolParty Project","type":"main","index":0}]]},"Test: PoolParty Project":{"main":[[{"node":"Drop: Both Annotation Graphs","type":"main","index":0}]]},"Query: All Text Nodes":{"main":[[{"node":"Parse: SPARQL Results → Items","type":"main","index":0}]]},"Parse: SPARQL Results → Items":{"main":[[{"node":"Extract + Load: Chunks","type":"main","index":0}]]},"Drop: Both Annotation Graphs":{"main":[[{"node":"Page: Init/Next","type":"main","index":0}]]},"Verify: Annotation Counts":{"main":[[{"node":"Format Summary","type":"main","index":0}]]},"Reset: Pagination State":{"main":[[{"node":"Test: PoolParty Heartbeat","type":"main","index":0}]]},"Page: Init/Next":{"main":[[{"node":"Query: All Text Nodes","type":"main","index":0}]]},"Page: More?":{"main":[[{"node":"Verify: Annotation Counts","type":"main","index":0}],[{"node":"Page: Init/Next","type":"main","index":0}]]},"Extract + Load: Chunks":{"main":[[{"node":"Page: More?","type":"main","index":0}]]}}	2026-07-07 18:41:02.297+00	2026-07-08 22:08:04.204+00	{"executionOrder":"v1","binaryMode":"separate"}	\N	{}	636bfd5a-bbbf-445b-9a5e-6cb52a316e20	0	YDeyTROouysdUvx5	\N	\