ulate(usage) {\\n\\tif (\\n\\t\\ttypeof usage.completionTokens === 'number' &&\\n\\t\\ttypeof usage.promptTokens === 'number' &&\\n\\t\\ttypeof usage.totalTokens === 'number'\\n\\t) {\\n\\t\\ttotals.completionTokens += usage.completionTokens;\\n\\t\\ttotals.promptTokens += usage.promptTokens;\\n\\t\\ttotals.totalTokens += usage.totalTokens;\\n\\n\\t\\tdetailedUsages.push({\\n\\t\\t\\tusage: { ...usage },\\n\\t\\t});\\n\\t}\\n}\\n\\nfunction findTokenUsageRecursively(obj) {\\n\\tif (typeof obj !== 'object' || obj === null) return;\\n\\n\\tif (\\n\\t\\ttypeof obj.completionTokens === 'number' &&\\n\\t\\ttypeof obj.promptTokens === 'number' &&\\n\\t\\ttypeof obj.totalTokens === 'number'\\n\\t) {\\n\\t\\taccumulate(obj);\\n\\t\\treturn;\\n\\t}\\n}\\n\\nfunction processExecution(exec) {\\n\\t//const node = nodes.find((n) => console.log(n.name));\\n\\t//const model = node?.parameters?.modelName || node.parameters?.model || node.parameters?.name;\\n\\tfindTokenUsageRecursively(exec);\\n}\\n\\nfunction jsonPath(obj, expr, arg) {\\n   var P = {\\n      resultType: arg && arg.resultType || \\"VALUE\\",\\n      result: [],\\n      normalize: function(expr) {\\n         var subx = [];\\n         return expr.replace(/[\\\\['](\\\\??\\\\(.*?\\\\))[\\\\]']/g, function($0,$1){return \\"[#\\"+(subx.push($1)-1)+\\"]\\";})\\n                    .replace(/'?\\\\.'?|\\\\['?/g, \\";\\")\\n                    .replace(/;;;|;;/g, \\";..;\\")\\n                    .replace(/;$|'?\\\\]|'$/g, \\"\\")\\n                    .replace(/#([0-9]+)/g, function($0,$1){return subx[$1];});\\n      },\\n      asPath: function(path) {\\n         var x = path.split(\\";\\"), p = \\"$\\";\\n         for (var i=1,n=x.length; i<n; i++)\\n            p += /^[0-9*]+$/.test(x[i]) ? (\\"[\\"+x[i]+\\"]\\") : (\\"['\\"+x[i]+\\"']\\");\\n         return p;\\n      },\\n      store: function(p, v) {\\n         if (p) P.result[P.result.length] = P.resultType == \\"PATH\\" ? P.asPath(p) : v;\\n         return !!p;\\n 