Fetch Concept Details	t	[{"typeVersion":2.1,"webhookId":"71e4712a-a335-4158-b5de-af184946d5a3","name":"Webhook","position":[-3552,16],"id":"a833c1d0-15c8-4c75-a219-7cd9f7fc62a4","type":"n8n-nodes-base.webhook","parameters":{"path":"fetch-concept-details","responseMode":"lastNode","options":{},"httpMethod":"POST"}},{"typeVersion":2,"name":"Get Input data","position":[-3136,16],"id":"14ee60ab-cae1-46e0-9068-6d7c3d75ff2e","type":"n8n-nodes-base.code","parameters":{"jsCode":"return {\\n  \\"conceptUris\\": $('Webhook').first().json.body.conceptUris,\\n  \\"originalExtractionResponse\\": $('Webhook').first().json.body.originalExtractionResponse,\\n  \\"batchSize\\": $('Webhook').first().json.body.batchSize,\\n  \\"customConceptProperties\\" : $input.first().json.conceptProperties.filter((conceptProperty) => {return !conceptProperty.startsWith(\\"skos:\\")}),\\n  \\"jwtToken\\": $('Webhook').first().json.headers.authentication.replace(\\"Bearer \\", \\"\\")\\n}"}},{"typeVersion":1.3,"name":"Configuration","position":[-3344,16],"id":"6a0a74c3-1dd2-4abc-bdfe-4e158a47baee","type":"n8n-nodes-base.executeWorkflow","parameters":{"workflowInputs":{"schema":[],"attemptToConvertTypes":false,"matchingColumns":[],"convertFieldsToString":true,"mappingMode":"defineBelow","value":{}},"options":{},"workflowId":{"mode":"list","cachedResultUrl":"/n8n/workflow/HJcJwMTssnY79HWw","__rl":true,"cachedResultName":"Configuration","value":"HJcJwMTssnY79HWw"}}},{"typeVersion":4.2,"credentials":{"httpBasicAuth":{"id":"emxYnbbzTTT6DtWc","name":"PoolParty Credentials"}},"name":"Enrich concepts with Thesaurus data","position":[-2640,-80],"id":"81d28593-8437-47c5-822f-881ca4684fdc","type":"n8n-nodes-base.httpRequest","parameters":{"bodyParameters":{"parameters":[{"name":"concepts","value":"={{ $('Get Input data').first().json.conceptUris.join(',') }}"},{"name":"properties","value":"={{ $('Configuration').first().json.conceptProperties.join(',') }}"}]},"method":"POST","sendBody":true,"options":{},"genericAuthType":"httpBasicAuth","contentType":"form-urlencoded","url":"={{ $('Configuration').item.json.poolPartyServerUrl }}/PoolParty/api/thesaurus/{{ $('Configuration').item.json.poolPartyProjectId }}/concepts","authentication":"genericCredentialType"},"alwaysOutputData":true},{"typeVersion":2,"name":"Prepare concept enrichment","position":[1360,0],"id":"6d6f31cf-17a7-4f73-9809-3e38c11ad8ed","type":"n8n-nodes-base.code","parameters":{"jsCode":"console.log('=== Processing Pipeline Started ===');\\n\\n// ============================================\\n// STEP 1: Validation\\n// ============================================\\n\\nconst originalExtractionResponse = $('Get Input data').first().json.originalExtractionResponse;\\nconst batchData = {\\n  originalExtractionResponse,\\n  projectId: $('Configuration').first().json.poolPartyProjectId\\n};\\n\\nif (!batchData || !batchData.originalExtractionResponse) {\\n  throw new Error('Missing originalExtractionResponse. Batch data not found.');\\n}\\nelse {\\n  console.log('Batch data found:', batchData);\\n}\\n\\nconsole.log('Original extraction concepts:', batchData.originalExtractionResponse.concepts?.length || 0);\\n\\n// ============================================\\n// STEP 2: Build an URI based map of concept details (all extracted concepts)\\n// ============================================\\n\\nconst extractedConceptsDetailsMap = {};\\n\\n$('Enrichment concept results').all().forEach(item => {\\n  // Collect enriched concept data from thesaurus API\\n  if (item.json.uri && item.json.prefLabel) {\\n    extractedConceptsDetailsMap[item.json.uri] = {\\n      // Core labels and definitions\\n      label: item.json.prefLabel,\\n      alternativeLabels: item.json.altLabels || [],\\n      definitions: item.json.definitions || [],\\n      \\n      // Additional context for LLM\\n      scopeNotes: item.json.scopeNotes || [], // Usage guidance\\n      examples: item.json.examples || [], // Example usage\\n      broaders: item.json.broaders || [], // Direct parents\\n      broadersTransitive: item.json.broadersTransitive || [], // Full hierarchy path!\\n      narrowers: item.json.narrowers || [], // Direct children\\n      narrowersTransitive: item.json.narrowersTransitive || [], // Full subtree\\n      relateds: item.json.relateds || [], // Associated concepts\\n      \\n      // Mapping properties for cross-vocabulary linking\\n      exactMatches: item.json.exactMatches || [], // Equivalent concepts\\n      closeMatches: item.json.closeMatches || [], // Similar concepts\\n      \\n      properties: item.json.properties || {} // Custom properties\\n    };\\n  }\\n});\\n\\nconsole.log('✓ Extracted Concepts details map built with', Object.keys(extractedConceptsDetailsMap).length, 'concepts');\\n\\n// ============================================\\n// STEP 3: Build an URI based map of concept details of relations\\n// ============================================\\n\\nconst relationDetailsMap = {};\\n\\n$('Relation concept results').all().forEach(item => {\\n  // Collect enriched concept data from thesaurus API\\n  if (item.json.uri && item.json.prefLabel) {\\n    relationDetailsMap[item.json.uri] = {\\n      // Core labels and definitions\\n      label: item.json.prefLabel,\\n      alternativeLabels: item.json.altLabels || [],\\n      definitions: item.json.definitions || [],\\n      \\n      // Additional context for LLM\\n      scopeNotes: item.json.scopeNotes || [], // Usage guidance\\n      examples: item.json.examples || [], // Example usage\\n    };\\n  }\\n});\\n\\nconsole.log('✓ Relation details map built with', Object.keys(relationDetailsMap).length, 'concepts');\\n\\nreturn {\\n  extractedConceptsDetailsMap,\\n  relationDetailsMap\\n};"}},{"typeVersion":2,"name":"Enrich concepts","position":[1552,0],"id":"9960f123-72ae-480a-a6be-60ff48ed98aa","type":"n8n-nodes-base.code","parameters":{"jsCode":"// ============================================\\n// Process and Enrich Extracted Concepts\\n// ============================================\\n\\nconst llmReadyOutput = {\\n  extractedConcepts: [],\\n  timestamp: new Date().toISOString()\\n};\\n\\nconst originalResponse = $('Get Input data').first().json.originalExtractionResponse;\\nconst extractedConceptsDetailsMap = $input.first().json.extractedConceptsDetailsMap;\\nconst relationDetailsMap = $input.first().json.relationDetailsMap;\\nconst customRelationDetails = $('Custom relation details result').first().json;\\n\\nif (originalResponse.concepts && Array.isArray(originalResponse.concepts)) {\\n  originalResponse.concepts.forEach(concept => {\\n    \\n    // Initialize processed concept structure\\n    const processedConcept = {\\n      // Core identification\\n      uri: concept.uri,\\n      primaryLabel: concept.prefLabels?.en || Object.values(concept.prefLabels || {})[0] || 'Unknown',\\n      alternativeLabels: concept.altLabels?.en || [],\\n      definitions: [],\\n      \\n      // Additional documentation\\n      scopeNotes: [],\\n      examples: [],\\n      \\n      // Context information\\n      category: concept.conceptSchemes?.[0]?.title || 'Uncategorized',\\n      matchingLabels: concept.matchingLabels || [],\\n      matchedAs: concept.matchingLabels?.map(m => m.label) || [],\\n      \\n      // Confidence scoring\\n      score: concept.score || 0,\\n      confidenceLevel: concept.score === 100 ? 'exact match' : \\n                       concept.score >= 80 ? 'high confidence' : \\n                       concept.score >= 60 ? 'medium confidence' : 'low confidence',\\n      \\n      // Semantic relationships\\n      parentConcepts: [],\\n      hierarchyPath: [],        // Full path to root\\n      categories: [],\\n      childConcepts: [],\\n      relatedConcepts: [],\\n      \\n      // Cross-references\\n      equivalentConcepts: [],   // exactMatch from other vocabularies\\n      similarConcepts: [],        // closeMatch from other vocabularies\\n\\n      // Custom attributes and relations (keyed by property)\\n      customProperties: {}\\n    };\\n    \\n    // ============================================\\n    // STEP 4.1: Enrich Seed Concept\\n    // ============================================\\n    \\n    if (concept.uri && extractedConceptsDetailsMap.hasOwnProperty(concept.uri)) {\\n      const seedEnriched = extractedConceptsDetailsMap[concept.uri];\\n      \\n      // Merge definitions\\n      if (seedEnriched.definitions.length > 0) {\\n        processedConcept.definitions = seedEnriched.definitions;\\n      }\\n      \\n      // Add scope notes and examples\\n      if (seedEnriched.scopeNotes.length > 0) {\\n        processedConcept.scopeNotes = seedEnriched.scopeNotes;\\n      }\\n      \\n      if (seedEnriched.examples.length > 0) {\\n        processedConcept.examples = seedEnriched.examples;\\n      }\\n      \\n      // Merge alternative labels (deduplicate)\\n      if (seedEnriched.alternativeLabels.length > 0) {\\n        const allAltLabels = [...processedConcept.alternativeLabels, ...seedEnriched.alternativeLabels];\\n        processedConcept.alternativeLabels = [...new Set(allAltLabels)];\\n      }\\n      \\n      // Build full hierarchy path using transitive broader\\n      /*if (seedEnriched.broaderTransitive.length > 0) {\\n        processedConcept.hierarchyPath = seedEnriched.broaderTransitive\\n          .map(uri => {\\n            const parent = enrichmentMap.get(uri);\\n            return parent ? parent.label : uri;\\n          });\\n      }*/\\n      \\n      // Add cross-vocabulary mappings\\n      if (seedEnriched.exactMatches.length > 0) {\\n        processedConcept.equivalentConcepts = seedEnriched.exactMatches;\\n      }\\n      \\n      if (seedEnriched.closeMatches.length > 0) {\\n        processedConcept.similarConcepts = seedEnriched.closeMatches;\\n      }\\n    \\n      // ============================================\\n      // STEP 4.2: Enrich Broader Concepts (Parents)\\n      // ============================================\\n      \\n      if (seedEnriched.broaders && Array.isArray(seedEnriched.broaders)) {\\n        processedConcept.parentConcepts = seedEnriched.broaders\\n          .map(uri => {\\n            if (relationDetailsMap.hasOwnProperty(uri)) {\\n              const enriched = relationDetailsMap[uri];\\n              return {\\n                uri: uri,\\n                label: enriched.label,\\n                alternativeLabels: enriched.alternativeLabels,\\n                definitions: enriched.definitions,\\n                scopeNotes: enriched.scopeNotes,      \\n                examples: enriched.examples           \\n              };\\n            }\\n            return null;\\n          })\\n          .filter(item => item !== null);\\n      }\\n      \\n      // ============================================\\n      // STEP 4.3: Enrich Concept Schemes (Categories)\\n      // ============================================\\n      \\n      if (concept.conceptSchemes && Array.isArray(concept.conceptSchemes)) {\\n        processedConcept.categories = concept.conceptSchemes\\n          .map(scheme => {\\n            if (relationDetailsMap.hasOwnProperty(scheme.uri)) {\\n              const enriched = relationDetailsMap[scheme.uri];\\n              return {\\n                uri: scheme.uri,\\n                label: enriched.label,\\n                alternativeLabels: enriched.alternativeLabels,\\n                definitions: enriched.definitions,\\n                scopeNotes: enriched.scopeNotes      \\n              };\\n            }\\n            // Fallback to basic scheme info\\n            return {\\n              uri: scheme.uri,\\n              label: scheme.title || 'Unknown Category',\\n              alternativeLabels: [],\\n              definitions: [],\\n              scopeNotes: []\\n            };\\n          });\\n      }\\n\\n      // ============================================\\n      // STEP 4.4: Enrich Narrower Concepts\\n      // ============================================\\n      \\n      if (seedEnriched.narrowers && Array.isArray(seedEnriched.narrowers)) {\\n        processedConcept.childConcepts = seedEnriched.narrowers\\n          .map(uri => {\\n            if (relationDetailsMap.hasOwnProperty(uri)) {\\n              const enriched = relationDetailsMap[uri];\\n              return {\\n                uri: uri,\\n                label: enriched.label,\\n                alternativeLabels: enriched.alternativeLabels,\\n                definitions: enriched.definitions,\\n                scopeNotes: enriched.scopeNotes\\n              };\\n            }\\n            return null;\\n          })\\n          .filter(item => item !== null);\\n      }\\n      \\n      // ============================================\\n      // STEP 4.5: Enrich Related Concepts\\n      // ============================================\\n      \\n      if (seedEnriched.relateds && Array.isArray(seedEnriched.relateds)) {\\n        processedConcept.relatedConcepts = seedEnriched.relateds\\n          .map(uri => {\\n            if (relationDetailsMap.hasOwnProperty(uri)) {\\n              const enriched = relationDetailsMap[uri];\\n              return {\\n                uri: uri,\\n                label: enriched.label,\\n                alternativeLabels: enriched.alternativeLabels,\\n                definitions: enriched.definitions,\\n                scopeNotes: enriched.scopeNotes\\n              };\\n            }\\n            return null;\\n          })\\n          .filter(item => item !== null);\\n      }\\n\\n      // ============================================\\n      // STEP 4.6: Enrich Custom Relations\\n      // ============================================\\n      \\n      if (seedEnriched.properties) {\\n        for (const propertyUri in seedEnriched.properties) {\\n          // Custom relations\\n          if (customRelationDetails.hasOwnProperty(propertyUri) && customRelationDetails[propertyUri].isRelation) {\\n            if (Array.isArray(seedEnriched.properties[propertyUri])) {\\n              processedConcept.customProperties[propertyUri] = seedEnriched.properties[propertyUri]\\n              .map(uri => {\\n                if (relationDetailsMap.hasOwnProperty(uri)) {\\n                  const enriched = relationDetailsMap[uri];\\n                  return {\\n                    uri: uri,\\n                    label: enriched.label,\\n                    alternativeLabels: enriched.alternativeLabels,\\n                    definitions: enriched.definitions,\\n                    scopeNotes: enriched.scopeNotes\\n                  };\\n                }\\n                return null;\\n              })\\n              .filter(item => item !== null);\\n            }\\n          }\\n          // Custom attributes\\n          else {\\n            processedConcept.customProperties[propertyUri] = seedEnriched.properties[propertyUri];\\n          }\\n        }\\n      }\\n    }\\n    \\n    llmReadyOutput.extractedConcepts.push(processedConcept);\\n  });\\n}\\n\\nconsole.log('✓ Processed', llmReadyOutput.extractedConcepts.length, 'concepts');\\n\\nreturn llmReadyOutput;"}},{"typeVersion":2,"name":"Build LLM context text","position":[1824,-304],"id":"88d939a7-15fc-4f32-877f-b9c3ceaaaf24","type":"n8n-nodes-base.code","parameters":{"jsCode":"// ============================================\\n// OUTPUT 1: LLM CONTEXT (for final answer)\\n// ============================================\\n\\nconst llmReadyOutput = $input.first().json;\\n\\nconst contextHeader = `# Knowledge Graph Context\\n\\nThe following concepts were extracted from the user's query and enriched with semantic relationships from our knowledge graph:\\n\\n**Understanding the Semantic Relationships:**\\n- **Preferred Label**: The main/official name for this concept\\n- **Alternative Labels**: Other names, synonyms, or ways this concept is commonly referred to\\n- **Definition**: Formal explanation of what this concept means\\n- **Scope Notes**: Usage guidance and contextual information about when to use this concept\\n- **Examples**: Concrete examples of how this concept is applied\\n- **Matched As**: The exact text from the user's query that triggered this concept\\n- **Confidence**: How confident we are this concept matches the user's intent (exact match = 100%, high = 80-99%, medium = 60-79%, low = <60%)\\n- **Broader Concepts**: More general/parent concepts that this concept belongs to (hierarchical relationship - \\"is-a\\" or \\"part-of\\")\\n- **Hierarchy Path**: Complete path from this concept to the root of the taxonomy\\n- **Categories**: The thematic classification or domain this concept belongs to\\n- **Related Concepts**: Associated concepts that are semantically connected but not hierarchical\\n\\n---\\n\\n## Extracted Concepts:\\n\\n`;\\n\\nconst conceptsText = llmReadyOutput.extractedConcepts.map((concept, index) => {\\n  let text = `### ${index + 1}. ${concept.primaryLabel}`;\\n  \\n  // Add confidence indicator\\n  if (concept.score !== 100) {\\n    text += ` (Confidence: ${concept.confidenceLevel}, ${concept.score}%)`;\\n  }\\n  \\n  // Core definition\\n  if (concept.definitions.length > 0) {\\n    text += `\\\\n**What it means:** ${concept.definitions.join(' ')}`;\\n  }\\n  \\n  // Scope notes for context\\n  if (concept.scopeNotes.length > 0) {\\n    text += `\\\\n**Usage context:** ${concept.scopeNotes.join(' ')}`;\\n  }\\n  \\n  // Examples for clarity\\n  if (concept.examples.length > 0) {\\n    text += `\\\\n**Examples:** ${concept.examples.slice(0, 2).join('; ')}`;\\n  }\\n  \\n  // Alternative names\\n  if (concept.alternativeLabels.length > 0) {\\n    text += `\\\\n**Also known as:** ${concept.alternativeLabels.join(', ')}`;\\n  }\\n  \\n  // Query matching\\n  if (concept.matchedAs.length > 0) {\\n    text += `\\\\n**Matched from query:** \\"${concept.matchedAs.join('\\", \\"')}\\"`;\\n  }\\n  \\n  // Full hierarchy path\\n  if (concept.hierarchyPath.length > 0) {\\n    text += `\\\\n**Taxonomy path:** ${concept.hierarchyPath.join(' → ')} → ${concept.primaryLabel}`;\\n  }\\n  \\n  // Parent concepts (immediate broaders)\\n  if (concept.parentConcepts.length > 0) {\\n    text += `\\\\n**Broader concepts (parent categories):**`;\\n    concept.parentConcepts.forEach(p => {\\n      text += `\\\\n  • ${p.label}`;\\n      if (p.alternativeLabels && p.alternativeLabels.length > 0) {\\n        text += ` (aka: ${p.alternativeLabels.slice(0, 2).join(', ')})`;\\n      }\\n      if (p.definitions && p.definitions.length > 0) {\\n        text += `\\\\n    → ${p.definitions.join(' ')}`;\\n      }\\n      // Scope notes for parents\\n      if (p.scopeNotes && p.scopeNotes.length > 0) {\\n        text += `\\\\n    ℹ️  ${p.scopeNotes[0]}`;\\n      }\\n    });\\n  }\\n  \\n  // Categories (concept schemes)\\n  if (concept.categories.length > 0) {\\n    text += `\\\\n**Belongs to category:**`;\\n    concept.categories.forEach(c => {\\n      text += `\\\\n  • ${c.label}`;\\n      if (c.alternativeLabels && c.alternativeLabels.length > 0) {\\n        text += ` (${c.alternativeLabels.slice(0, 2).join(', ')})`;\\n      }\\n      if (c.definitions && c.definitions.length > 0) {\\n        text += `\\\\n    → ${c.definitions.join(' ')}`;\\n      }\\n    });\\n  }\\n  \\n  // Related concepts\\n  if (concept.relatedConcepts.length > 0) {\\n    text += `\\\\n**Related concepts (semantically connected):**`;\\n    concept.relatedConcepts.forEach(r => {\\n      text += `\\\\n  • ${r.label}`;\\n      if (r.alternativeLabels && r.alternativeLabels.length > 0) {\\n        text += ` (${r.alternativeLabels.slice(0, 2).join(', ')})`;\\n      }\\n      if (r.definitions && r.definitions.length > 0) {\\n        const shortDef = r.definitions[0].length > 150 \\n          ? r.definitions[0].substring(0, 150) + '...' \\n          : r.definitions[0];\\n        text += `\\\\n    → ${shortDef}`;\\n      }\\n    });\\n  }\\n  \\n  // Cross-vocabulary references\\n  if (concept.equivalentConcepts.length > 0) {\\n    text += `\\\\n**Equivalent concepts (exact matches):** ${concept.equivalentConcepts.slice(0, 3).join(', ')}`;\\n  }\\n  \\n  if (concept.similarConcepts.length > 0) {\\n    text += `\\\\n**Similar concepts (close matches):** ${concept.similarConcepts.slice(0, 3).join(', ')}`;\\n  }\\n  \\n  return text;\\n}).join('\\\\n\\\\n');\\n\\nconst llmContextText = contextHeader + conceptsText + `\\n\\n---\\n\\n**How to use this context:**\\nUse the above semantic relationships to better understand what the user is asking about. The broader concepts show the hierarchical context, categories show the domain/topic area, and related concepts show connected ideas. The hierarchy path shows where this concept fits in the overall knowledge structure. When the confidence score is below 100%, consider that the match may be ambiguous and clarify with the user if needed.`;\\n\\nreturn {\\n  llmContextText\\n};"}},{"typeVersion":2,"name":"Create query rewriting context","position":[1824,-160],"id":"7decfc74-c2c2-48d7-b17a-8376059c7995","type":"n8n-nodes-base.code","parameters":{"jsCode":"// ============================================\\n// OUTPUT 2: QUERY REWRITING CONTEXT\\n// ============================================\\n\\nconst llmReadyOutput = $input.first().json;\\n\\nconst queryExpansionTerms = {\\n  primaryTerms: [],\\n  synonyms: new Set(),\\n  broaderContext: new Set(),\\n  relatedTerms: new Set(),\\n  categories: new Set(),\\n  examples: new Set()        // Add examples for context\\n};\\n\\nllmReadyOutput.extractedConcepts.forEach(concept => {\\n  // Only use high-confidence concepts for expansion\\n  if (concept.score >= 60) {\\n    queryExpansionTerms.primaryTerms.push(concept.primaryLabel);\\n    \\n    // Alternative labels as synonyms\\n    concept.alternativeLabels.forEach(alt => queryExpansionTerms.synonyms.add(alt));\\n    \\n    // Broader concepts for context\\n    concept.parentConcepts.forEach(p => {\\n      queryExpansionTerms.broaderContext.add(p.label);\\n      if (p.alternativeLabels) {\\n        p.alternativeLabels.slice(0, 2).forEach(alt => queryExpansionTerms.broaderContext.add(alt));\\n      }\\n    });\\n    \\n    // Add hierarchy path for full context\\n    if (concept.hierarchyPath.length > 0) {\\n      concept.hierarchyPath.forEach(pathLabel => queryExpansionTerms.broaderContext.add(pathLabel));\\n    }\\n    \\n    // Related concepts\\n    concept.relatedConcepts.forEach(r => {\\n      queryExpansionTerms.relatedTerms.add(r.label);\\n    });\\n    \\n    // Categories\\n    concept.categories.forEach(c => {\\n      queryExpansionTerms.categories.add(c.label);\\n    });\\n    \\n    // Add examples for semantic richness\\n    if (concept.examples.length > 0) {\\n      concept.examples.slice(0, 2).forEach(ex => queryExpansionTerms.examples.add(ex));\\n    }\\n  }\\n});\\n\\nreturn {\\n  queryExpansionTerms,\\n  queryRewritingContext: `Query Expansion Terms:\\nPrimary: ${queryExpansionTerms.primaryTerms.join(', ')}\\nSynonyms: ${Array.from(queryExpansionTerms.synonyms).join(', ')}\\nBroader Context: ${Array.from(queryExpansionTerms.broaderContext).join(', ')}\\nCategories: ${Array.from(queryExpansionTerms.categories).join(', ')}\\nRelated: ${Array.from(queryExpansionTerms.relatedTerms).join(', ')}\\nExamples: ${Array.from(queryExpansionTerms.examples).join('; ')}`\\n};\\n"}},{"typeVersion":2,"name":"Build dense vector retrieval queries","position":[1824,0],"id":"7c834225-67bd-4114-b136-4d75312649a2","type":"n8n-nodes-base.code","parameters":{"jsCode":"// ============================================\\n// OUTPUT 3: DENSE VECTOR RETRIEVAL QUERIES\\n// ============================================\\n\\nconst llmReadyOutput = $input.first().json;\\nconst retrievalQueries = [];\\n\\nllmReadyOutput.extractedConcepts.forEach(concept => {\\n  if (concept.score >= 60) {\\n    // Query 1: Primary term + definition\\n    if (concept.definitions.length > 0) {\\n      retrievalQueries.push(`${concept.primaryLabel}: ${concept.definitions[0]}`);\\n    } else {\\n      retrievalQueries.push(concept.primaryLabel);\\n    }\\n    \\n    // Query 2: Primary + broader context\\n    if (concept.parentConcepts.length > 0) {\\n      const broaderLabels = concept.parentConcepts.map(p => p.label).join(' ');\\n      retrievalQueries.push(`${concept.primaryLabel} ${broaderLabels}`);\\n    }\\n    \\n    // Query 3: Synonyms for semantic variation\\n    if (concept.alternativeLabels.length > 0) {\\n      retrievalQueries.push(concept.alternativeLabels.slice(0, 3).join(' '));\\n    }\\n    \\n    // Query 4: Category context\\n    if (concept.categories.length > 0) {\\n      const categoryLabels = concept.categories.map(c => c.label).join(' ');\\n      retrievalQueries.push(`${concept.primaryLabel} ${categoryLabels}`);\\n    }\\n    \\n    // Query 5: Full hierarchy path for context\\n    if (concept.hierarchyPath.length > 0) {\\n      const pathContext = concept.hierarchyPath.slice(-2).join(' ');\\n      retrievalQueries.push(`${concept.primaryLabel} ${pathContext}`);\\n    }\\n    \\n    // Query 6: Examples for practical context\\n    if (concept.examples.length > 0) {\\n      retrievalQueries.push(`${concept.primaryLabel} ${concept.examples[0]}`);\\n    }\\n  }\\n});\\n\\nreturn {\\n  retrievalQueries\\n};"}},{"typeVersion":2,"name":"Keyword extraction","position":[1824,144],"id":"a911c0b8-38f7-4f1f-82b6-50c60dbd435f","type":"n8n-nodes-base.code","parameters":{"jsCode":"const llmReadyOutput = $input.first().json;\\nconst allKeywords = new Set();\\n\\nllmReadyOutput.extractedConcepts.forEach(concept => {\\n  // Primary label\\n  allKeywords.add(concept.primaryLabel);\\n  \\n  // High-value synonyms (limited)\\n  concept.alternativeLabels.slice(0, 3).forEach(alt => allKeywords.add(alt));\\n  \\n  // Broader concepts\\n  concept.parentConcepts.forEach(p => {\\n    allKeywords.add(p.label);\\n  });\\n  \\n  // EAdd hierarchy path terms\\n  if (concept.hierarchyPath.length > 0) {\\n    concept.hierarchyPath.slice(-2).forEach(term => allKeywords.add(term));\\n  }\\n  \\n  // Categories\\n  concept.categories.forEach(c => {\\n    allKeywords.add(c.label);\\n  });\\n});\\n\\nconst keywordList = Array.from(allKeywords);\\n\\nreturn {\\n  keywordList\\n};"}},{"typeVersion":2,"name":"Build UI concepts","position":[1824,304],"id":"d0bfca10-e1ed-44d2-b2c6-7eda380a0e50","type":"n8n-nodes-base.code","parameters":{"jsCode":"// ============================================\\n// OUTPUT 5: ENRICHED CONCEPTS FOR MESSAGE\\n// ============================================\\n\\nconst llmReadyOutput = $input.first().json;\\nconst conceptProperties = $('Configuration').first().json.conceptProperties;\\nconst messageConcepts = [];\\n\\nllmReadyOutput.extractedConcepts.forEach(concept => {\\n  const messageConcept = {\\n    id: concept.uri,\\n    label: concept.primaryLabel,\\n    score: concept.score,\\n    matchingLabels: concept.matchingLabels,\\n    details: {\\n      \\"altLabels\\": conceptProperties.includes(\\"skos:altLabel\\") ? concept.alternativeLabels : null,\\n      \\"definitions\\": conceptProperties.includes(\\"skos:definition\\") ? concept.definitions : null,\\n      \\"scopeNotes\\": conceptProperties.includes(\\"skos:scopeNote\\") ? concept.scopeNotes : null,\\n      \\"examples\\": conceptProperties.includes(\\"skos:example\\") ? concept.examples : null,\\n    },\\n    \\"categories\\": concept.categories,\\n    \\"parentConcepts\\": conceptProperties.includes(\\"skos:broader\\") ? concept.parentConcepts : null,\\n    \\"childConcepts\\": conceptProperties.includes(\\"skos:narrower\\") ? concept.childConcepts : null,\\n    \\"relatedConcepts\\": conceptProperties.includes(\\"skos:related\\") ? concept.relatedConcepts : null,\\n    \\"equivalentConcepts\\": conceptProperties.includes(\\"skos:exactMatch\\") ? concept.equivalentConcepts : null,\\n    \\"similarConcepts\\": conceptProperties.includes(\\"skos:closeMatch\\") ? concept.similarConcepts : null,\\n    \\"customProperties\\": concept.customProperties\\n  };\\n  \\n  messageConcepts.push(messageConcept);\\n});\\n\\n// Return the relation details for all custom relations the user expects to receive.\\nconst customRelationDetails = $('Custom relation details result').first().json;\\nconst customPropertyDetailsRequired = {};\\nfor (const customConceptPropertyUri of $('Get Input data').first().json.customConceptProperties) {\\n  if (customRelationDetails.hasOwnProperty(customConceptPropertyUri)) {\\n    customPropertyDetailsRequired[customConceptPropertyUri] = customRelationDetails[customConceptPropertyUri];\\n  }\\n}\\n\\nreturn {\\n  messageConcepts,\\n  customPropertyDetails: customPropertyDetailsRequired\\n};"}},{"typeVersion":3.2,"name":"Merge outputs","position":[2080,-48],"id":"4b7c4744-112d-4c09-b838-ecaa74392fa4","type":"n8n-nodes-base.merge","parameters":{"numberInputs":5},"alwaysOutputData":true},{"typeVersion":2,"name":"Build output","position":[2496,0],"id":"7366c199-ec9f-4382-84a6-7dc4dc292258","type":"n8n-nodes-base.code","parameters":{"jsCode":"const jsonInput = $input.first().json;\\nconst queryExpansionTerms = jsonInput.queryExpansionTerms;\\n\\nreturn [{\\n  json: {\\n    // For final answer LLM injection\\n    llmContextText: jsonInput.llmContextText,\\n    \\n    // For query rewriting\\n    queryRewritingContext: jsonInput.queryRewritingContext,\\n    \\n    // For dense vector retrieval\\n    retrievalQueries: jsonInput.retrievalQueries,\\n    retrievalQueriesText: jsonInput.retrievalQueries.join('\\\\n'),\\n    \\n    // For keyword/sparse retrieval\\n    keywords: jsonInput.keywordList,\\n    keywordsText: jsonInput.keywordList.join(', '),\\n    \\n    // Structured data (programmatic access)\\n    structuredOutput: $('Enrich concepts').first().json,\\n\\n    // Concepts for the user message\\n    messageConcepts: jsonInput.messageConcepts,\\n\\n    // Details about custom properties the user is interested in\\n    customPropertyDetails: jsonInput.customPropertyDetails,\\n    \\n    // Query expansion object\\n    queryExpansion: {\\n      primary: queryExpansionTerms.primaryTerms,\\n      synonyms: Array.from(queryExpansionTerms.synonyms),\\n      broaderContext: Array.from(queryExpansionTerms.broaderContext),\\n      categories: Array.from(queryExpansionTerms.categories),\\n      related: Array.from(queryExpansionTerms.relatedTerms),\\n      examples: Array.from(queryExpansionTerms.examples)  // ENHANCED\\n    },\\n    \\n    // Statistics and metadata\\n    stats: {\\n      totalConcepts: $('Enrich concepts').first().json.extractedConcepts.length,\\n      enrichedConceptsUsed: Object.keys($('Prepare concept enrichment').first().json.relationDetailsMap).length,\\n      retrievalQueriesGenerated: jsonInput.retrievalQueries.length,\\n      keywordsExtracted: jsonInput.keywordList.length,\\n      timestamp: new Date().toISOString()\\n    }\\n  }\\n}];"}},{"typeVersion":4.2,"credentials":{"httpBasicAuth":{"id":"emxYnbbzTTT6DtWc","name":"PoolParty Credentials"}},"name":"Fetch missing relation details","position":[896,-112],"id":"e2a26b7f-ece8-4697-b967-b66d13aef216","type":"n8n-nodes-base.httpRequest","parameters":{"bodyParameters":{"parameters":[{"name":"concepts","value":"={{ $('Get concept URIs for all relations').item.json.noLabelUris.join(',') }}"},{"name":"properties","value":"skos:prefLabel,skos:altLabel,skos:definition,skos:scopeNote,skos:example"}]},"method":"POST","sendBody":true,"options":{},"genericAuthType":"httpBasicAuth","contentType":"form-urlencoded","url":"={{ $('Configuration').first().json.poolPartyServerUrl }}/PoolParty/api/thesaurus/{{ $('Configuration').first().json.poolPartyProjectId }}/concepts","authentication":"genericCredentialType"},"alwaysOutputData":true},{"typeVersion":2,"name":"Get concept URIs for all relations","position":[448,-16],"id":"57859ae9-fef8-4f76-bc77-8b5c9feceb27","type":"n8n-nodes-base.code","parameters":{"jsCode":"let noLabelUris = [];\\n\\n// Check if data for any custom relation is expected.\\nconst customRelationDetails = $('Custom relation details result').first().json;\\nlet customRelationUris = [];\\nfor (const customConceptPropertyUri of $('Get Input data').first().json.customConceptProperties) {\\n  if (customRelationDetails.hasOwnProperty(customConceptPropertyUri) && customRelationDetails[customConceptPropertyUri].isRelation) {\\n    customRelationUris.push(customConceptPropertyUri);\\n  }\\n}\\nconsole.log(\\"customRelationUris: \\", customRelationUris);\\n\\nfor (const item of $('Enrichment concept results').all()) {\\n  const itemJson = item.json;\\n  \\n  // Check the main SKOS relation properties.\\n  const skosRelations = [\\"broaders\\", \\"narrowers\\", \\"relateds\\"];\\n  for (const skosRelation of skosRelations) {\\n    if (itemJson.hasOwnProperty(skosRelation)) {\\n      noLabelUris = noLabelUris.concat(itemJson[skosRelation]);\\n    }\\n  }\\n\\n  // Check the custom relations.\\n  if (itemJson.hasOwnProperty(\\"properties\\") && itemJson.properties !== null) {\\n    for (const customRelationUri of customRelationUris) {\\n      if (itemJson.properties.hasOwnProperty(customRelationUri)) {\\n        noLabelUris = noLabelUris.concat(itemJson.properties[customRelationUri]);\\n      }\\n    }\\n  }\\n}\\n\\n// Create a unique list of strings.\\nnoLabelUris = [... new Set(noLabelUris)];\\n\\nreturn {\\n  noLabelUris\\n};"}},{"typeVersion":2,"name":"Merge into single object","position":[2272,0],"id":"f2265dd1-5e2c-4831-ab7f-c9652ccd7ac7","type":"n8n-nodes-base.code","parameters":{"jsCode":"let output = {};\\n\\nfor (const item of $input.all()) {\\n  for (const property in item.json) {\\n    output[property] = item.json[property];\\n  }\\n}\\n\\nreturn output;"}},{"typeVersion":2,"name":"Build empty concepts result","position":[-2640,128],"id":"190d4380-3307-40fa-929b-cb883576501d","type":"n8n-nodes-base.code","parameters":{"jsCode":"return {};"}},{