}]]},"Send Output Guardrails message 2":{"main":[[{"node":"PrepareResponse - Success","index":0,"type":"main"}]]},"Build Ex message - Answer Enrich success":{"main":[[{"node":"Send Ex message - Answer Enrich success","index":0,"type":"main"}]]},"Send Follow-ups message":{"main":[[{"node":"LLMUsage-Followups","index":0,"type":"main"}]]},"Build Answer message":{"main":[[{"node":"Send Answer message","index":0,"type":"main"}]]},"Build Follow-ups message":{"main":[[{"node":"Send Follow-ups message","index":0,"type":"main"}]]},"Build Output Guardrails message - not passed 1":{"main":[[{"node":"Send Output Guardrails message 2","index":0,"type":"main"}]]},"Send Ex message - Answer Enrich success":{"main":[[{"node":"Build Answer Concepts message","index":0,"type":"main"}]]},"Build Ex message -  Concept Enrich error":{"main":[[{"node":"Send Ex message - Concept Enrich error","index":0,"type":"main"}]]},"Send Ex message - Out Guardrails passed":{"main":[[{"node":"Build Answer message","index":0,"type":"main"}]]},"LLMUsage-Followups":{"main":[[{"node":"Loop  iteration point","index":0,"type":"main"}]]}}	2026-03-27 08:43:56.482+00	2026-07-12 16:42:24.404+00	{"executionTimeout":120,"availableInMCP":false,"callerPolicy":"workflowsFromSameOwner","timeSavedMode":"fixed","executionOrder":"v1","binaryMode":"separate"}	\N	{"When Executed by Another Workflow":[{"json":{"collectedData":{"vectorHits":[{"score":0.59723455,"metadata":{"x-amz-bedrock-kb-source-uri":"s3://graphwisekh/helpTxt96_flattened/6575a5cd38__poolparty-project.html.txt","AMAZON_BEDROCK_TEXT":"PoolParty Project Abstract PoolParty Project A PoolParty project contains the taxonomy/thesaurus and other project related information. A PoolParty project can include any number of concept schemes, top concepts, and concepts. A PoolParty project is a container that is used to hold one or more concept schemes (thesauri). We recommend that you select the correct settings for a  new  or  existing  thesaurus project. You can also set the  language  and  user group  for a PoolParty project. In PoolParty you can save your project automatically by setting the  Autosave project . Depending on how often you need to save your project, the snapshots of a project is saved at regular intervals without additional user intervention. Create an Empty Project New Project - Languages New Project - User Groups","AMAZON_BEDROCK_METADATA":"{\\"source\\":\\"s3://graphwisekh/helpTxt96_flattened/6575a5cd38__poolparty-project.html.txt\\"}","x-amz-bedrock-kb-data-source-id":"XIY1CD9O3U","id":"606946a3-e607-48f2-ae01-88d8fecc9ee1"},"payload":"PoolParty Project Abstract PoolParty Project A PoolParty project contains the taxonomy/thesaurus and other project related information. A PoolParty project can include any number of concept schemes, top concepts, and concepts. A PoolParty project is a container that is used to hold one or more concept schemes (thesauri). We recommend that you select the correct settings for a  new  or  existing  thesaurus project. You can also set the  language  and  user group  for a PoolParty project. In PoolParty you can save your project automatically by setting the  Autosave project . Depending on how often you need to save your project, the snapshots of a project is saved at regular intervals without additional user intervention. Create an Empty Project New Project - Languages New Project - User Groups","id":"1%3A0%3AgmqCvJgBkyEkd_mB8shD","source":"s3://graphwisekh/helpTxt96_flattened/6575a5cd38__poolparty-project.html.txt"},{"score":0.579096,"metadata":{"x-amz-bedrock-kb-source-uri":"s3://graphwisekh/helpTxt96_flattened/e086d6995d__information-security-practices-and-procedures.html.txt","AMAZON_BEDROCK_TEXT":"PoolParty adheres to industry best practices by implementing data minimization principles, exposing only the data necessary for specific purposes and limiting the duration that sensitive information remains in memory or unencrypted. All externally exposed sensitive data is secured using state-of-the-art cryptographic protection, including password hashing via PBKDF2 and encryption of third-party credentials using AES with configurable key sizes that meet current security standards. PoolParty provides various ways to authenticate users. The default authentication method for the user interface is password-based verification. Administrators can  configure a strong password policy . Customers can also  leverage their existing access management infrastructure and configure single sign-on . Social login and  multi-factor authentication (MFA)  come out of the box. Token-based authentication (OAuth 2.0) is implemented for all PoolParty APIs except for UnifiedViews. PoolParty User Administration Setup Using Keycloak Tip For more information on this subject, refer to the  Information Security Practices and Procedures  white paper. ISO/EIC 27001:2022 ISO/EIC 27701:2019","AMAZON_BEDROCK_METADATA":"{\\"source\\":\\"s3://graphwisekh/helpTxt96_flattened/e086d6995d__information-security-practices-and-procedures.html.txt\\"}","x-amz-bedrock-kb-data-source-id":"XIY1CD9O3U","id":"be561ff2-e9eb-4701-aecb-8b072170fa0d"},"payload":"PoolParty adheres to industry best practices by implementing data minimization principles, exposing only the data necessary for specific purposes and limiting the duration that sensitive information remains in memory or unencrypted. All externally exposed sensitive data is secured using state-of-the-art cryptographic protection, including password hashing via PBKDF2 and encryption of third-party credentials using AES with configurable key sizes that meet current security standards. PoolParty provides various ways to authenticate users. The default authentication method for the user interface is password-based verification. Administrators can  configure a strong password policy . Customers can also  leverage their existing access management infrastructure and configure single sign-on . Social login and  multi-factor authentication (MFA)  come out of the box. Token-based authentication (OAuth 2.0) is implemented for all PoolParty APIs except for UnifiedViews. PoolParty User Administration Setup Using Keycloak Tip For more information on this subject, refer to the  Information Security Practices and Procedures  white paper. ISO/EIC 27001:2022 ISO/EIC 27701:2019","id":"1%3A0%3A3GqCvJgBkyEkd_mBwccv","source":"s3://graphwisekh/helpTxt96_flattened/e086d6995d__information-security-practices-and-procedures.html.txt"},{"score":0.57829684,"metadata":{"x-amz-bedrock-kb-source-uri":"s3://graphwisekh/helpTxt96_flattened/f3e05c9ee3__is-there-a-sharepoint-integration-with-poolparty-.html.txt","AMAZON_BEDROCK_TEXT":"Is There a SharePoint Integration with PoolParty? Abstract Is There a SharePoint Integration with PoolParty? PoolParty is integrated with SharePoint Online. It supports automatic tagging, content classification based on text mining and synchronization of PoolParty taxonomies into SharePoint Term store. High precision of tags is guaranteed by using controlled vocabularies (thesauri) as a basis. You benefit from faceted search, auto-complete and semantic search based on automatically tagged content. Note For more information, visit the PoolParty for SharePoint  website  and  documentation .","AMAZON_BEDROCK_METADATA":"{\\"source\\":\\"s3://graphwisekh/helpTxt96_flattened/f3e05c9ee3__is-there-a-sharepoint-integration-with-poolparty-.html.txt\\"}","x-amz-bedrock-kb-data-source-id":"XIY1CD9O3U","id":"b9aa6e9f-54ea-43ac-8192-1c8bdfd3bc06"},"payload":"Is There a SharePoint Integration with PoolParty? Abstract Is There a SharePoint Integration with PoolParty? PoolParty is integrated with SharePoint Online. It supports automatic tagging, content classification based on text mining and synchronization of PoolParty taxonomies into SharePoint Term store. High precision of tags is guaranteed by using controlled vocabularies (thesauri) as a basis. You benefit from faceted search, auto-complete and semantic search based on automatically tagged content. Note For more information, visit the PoolParty for SharePoint  website  and  documentation .","id":"1%3A0%3AyWqCvJgBkyEkd_mBL8X4","source":"s3://graphwisekh/helpTxt96_flattened/f3e05c9ee3__is-there-a-sharepoint-integration-with-poolparty-.html.txt"},{"score":0.57569504,"metadata":{"x-amz-bedrock-kb-source-uri":"s3://graphwisekh/helpTxt96_flattened/130b22f5b3__poolparty-system-architecture.html.txt","AMAZON_BEDROCK_TEXT":"PoolParty System Architecture 21/03/2025 Abstract PoolParty System Architecture PoolParty Semantic Suite is a Java based application that can run in an Apache Tomcat 9. PoolParty's Frontend is based on JavaScript and WebFrameworks. PoolParty comes with a built-in graph database (GraphDB or RDF4J) that is used for managing the taxonomy, the thesaurus data, and the ontology data. PoolParty uses a built-in Apache Solr server to build entity extraction models and GraphSearch indices. Apache Spark is used to perform machine learning tasks for semantic classification of documents. In addition to or while replacing the built-in graph database, various external graph databases can be connected via PoolParty's Semantic Middleware Configurator. PoolParty offers various features which work with external graph databases. Go to:  PoolParty External Graph Database Support  to see the matrix showing the respective supported features of the market-leading graph databases.","AMAZON_BEDROCK_METADATA":"{\\"source\\":\\"s3://graphwisekh/helpTxt96_flattened/130b22f5b3__poolparty-system-architecture.html.txt\\"}","x-amz-bedrock-kb-data-source-id":"XIY1CD9O3U","id":"d894deba-063e-4f0b-b48f-b75034644d6d"},"payload":"PoolParty System Architecture 21/03/2025 Abstract PoolParty System Architecture PoolParty Semantic Suite is a Java based application that can run in an Apache Tomcat 9. PoolParty's Frontend is based on JavaScript and WebFrameworks. PoolParty comes with a built-in graph database (GraphDB or RDF4J) that is used for managing the taxonomy, the thesaurus data, and the ontology data. PoolParty uses a built-in Apache Solr server to build entity extraction models and GraphSearch indices. Apache Spark is used to perform machine learning tasks for semantic classification of documents. In addition to or while replacing the built-in graph database, various external graph databases can be connected via PoolParty's Semantic Middleware Configurator. PoolParty offers various features which work with external graph databases. Go to:  PoolParty External Graph Database Support  to see the matrix showing the respective supported features of the market-leading graph databases.","id":"1%3A0%3ATGqAvJgBkyEkd_mB08Dc","source":"s3://graphwisekh/helpTxt96_flattened/130b22f5b3__poolparty-system-architecture.html.txt"},{"score":0.57477266,"metadata":{"x-amz-bedrock-kb-source-uri":"s3://graphwisekh/helpTxt96_flattened/otkg (1).part5443.ttl","AMAZON_BEDROCK_TEXT":"rel=\\\\\\"noopener\\\\\\">PoolParty Summit</a>. Spanning two days in a virtual event space, the PoolParty Summit 2023 will explore how PoolParty users have managed to achieve stability and keep their customers happy during turbulent times. Our CTO, Vassil Momtchev will present updates on our products and services with a dedicated technology talk. In addition, we will have a virtual booth where we will meet and greet all attendees.\\n\\nPoolParty Summit 2023 is a great opportunity to connect with other professionals in the field and learn from their experiences. You'll be able to tap into a network of like-minded individuals who share your passion for semantic technology and its potential to transform business.\\n\\nOur CTO, Vassil Momtchev, will deliver a talk about how to deliver business-critical semantic applications with PoolParty and GraphDB 10.  The Pool Party Semantic Suite uses GraphDB as an external RDF database to store all internal applications. In his talk, Vassil will cover the possible integration options from the perspective of the GraphDB database. GraphDB offers many critical features like high availability, data virtualization, powerful search, text mining, etc., that can improve the developer experience of the PoolParty users. Lastly, Vassil will share the high-level vision and the GraphDB product roadmap.\\n\\n</div>\\n</div>\\n</div>\\n</div>\\n</div>\\n</div>\\n</div>\\n</div>\\n</div>\\n</d","AMAZON_BEDROCK_METADATA":"{\\"source\\":\\"s3://graphwisekh/helpTxt96_flattened/otkg (1).part5443.ttl\\"}","x-amz-bedrock-kb-data-source-id":"XIY1CD9O3U","id":"95b7b40f-04c9-42b6-931c-4a5c26d0eb8f"},"payload":"rel=\\\\\\"noopener\\\\\\">PoolParty Summit</a>. Spanning two days in a virtual event space, the PoolParty Summit 2023 will explore how PoolParty users have managed to achieve stability and keep their customers happy during turbulent times. Our CTO, Vassil Momtchev will present updates on our products and services with a dedicated technology talk. In addition, we will have a virtual booth where we will meet and greet all attendees.\\n\\nPoolParty Summit 2023 is a great opportunity to connect with other professionals in the field and learn from their experiences. You'll be able to tap into a network of like-minded individuals who share your passion for semantic technology and its potential to transform business.\\n\\nOur CTO, Vassil Momtchev, will deliver a talk about how to deliver business-critical semantic applications with PoolParty and GraphDB 10.  The Pool Party Semantic Suite uses GraphDB as an external RDF database to store all internal applications. In his talk, Vassil will cover the possible integration options from the perspective of the GraphDB database. GraphDB offers many critical features like high availability, data virtualization, powerful search, text mining, etc., that can improve the developer experience of the PoolParty users. Lastly, Vassil will share the high-level vision and the GraphDB product roadmap.\\n\\n</div>\\n</div>\\n</div>\\n</div>\\n</div>\\n</div>\\n</div>\\n</div>\\n</div>\\n</d","id":"1%3A0%3Abi9N65gBD5J-rYW1c3IE","source":"s3://graphwisekh/helpTxt96_flattened/otkg (1).part5443.ttl"}],"intentClassification":{"chatInput":"temp question","language":"en"},"questionId":"f406924d-239b-4f47-bc03-6cf84eb0b9b3","shortmemory":{"response":""},"concepts":{"conceptEnrichment":{"structuredOutput":{"extractedConcepts":[{"confidenceLevel":"exact match","scopeNotes":[],"similarConcepts":[],"relatedConcepts":[],"uri":"https://vocabulary.graphwise.ai/gwkg/skills/fec40b89-5be8-47ac-b642-f062b2d934c5","hierarchyPath":[],"score":100,"childConcepts":[{"scopeNotes":[],"label":"Recommender system","alternativeLabels":["Building recommenders"],"uri":"https://vocabulary.graphwise.ai/gwkg/skills/b3342f45-9131-4a6b-a209-b6386cb51e97","definitions":[]},{"scopeNotes":[],"label":"PoolParty customer training","alternativeLabels":[],"uri":"https://vocabulary.graphwise.ai/gwkg/skills/03582072-99b9-40e7-916b-ed4dfa1ab2d1","definitions":[]},{"scopeNotes":[],"label":"PoolParty APIs","alternativeLabels":["PoolParty API","Semantic Integrator APIs","Advanced Server APIs","Enterprise Server APIs"],"uri":"https://vocabulary.graphwise.ai/gwkg/skills/f517d518-725f-4e87-a4ab-0147e035b0be","definitions":["Optimize your workplace without having to change to a new system or application. Use PoolParty APIs and ready-made integrations to enhance your systems."]},{"scopeNotes":[],"label":"PoolParty 2nd level support","alternativeLabels":[],"uri":"https://vocabulary.graphwise.ai/gwkg/skills/19004922-52bf-4583-a705-0973ebdfaa74","definitions":[]},{"scopeNotes":[],"label":"PoolParty positioning","alternativeLabels":["PoolParty business value"],"uri":"https://vocabulary.graphwise.ai/gwkg/skills/7f5d43a9-4577-4798-bd01-3a5214092754","definitions":[]},{"scopeNotes":[],"label":"PoolParty upgrades","alternativeLabels":[],"uri":"https://vocabulary.graphwise.ai/gwkg/skills/72fcbd58-06ed-4605-9345-9f1d8aa7056a","definitions":[]},{"scopeNotes":[],"label":"Limitations of PoolParty","alter