ey)) {\\n      itemJson = itemJson[key];\\n    }\\n    else {\\n      return null;\\n    }\\n  }\\n  return itemJson;\\n}\\n\\n/**\\n * Exclude (nullifies) certain properties from the passed-through metadata.\\n * @param itemJson The JSON of the results item containing metadata to exclude properties from\\n * @returns The metadata object with nullified properties\\n */\\nconst buildPassthroughMetadata = function(itemJson) {\\n  const passthroughMetadata = $('Call \\\\'Configuration (sub-workflow)\\\\'').first().json.vectorStoreMetadataPassthrough;\\n\\n  if (passthroughMetadata) {\\n    const metadataKey = presetMapping.source.split(\\".\\")[0];\\n    if (itemJson.hasOwnProperty(metadataKey)) {\\n      const metadata = itemJson[metadataKey];\\n      const excludeProperties = $('Call \\\\'Configuration (sub-workflow)\\\\'').first().json.vectorStoreMetadataExclude;\\n      for (const property of excludeProperties) {\\n        if (metadata.hasOwnProperty(property)) {\\n          metadata[property] = null;\\n        }\\n      }\\n      return metadata;\\n    }\\n  }\\n  \\n  return null;\\n}\\n\\n// Build an array of result documents, independent of the original mapping of the vector store.\\nfor (const item of $input.all()) {\\n  const itemJson = item.json;\\n  const source = getMappedValue(itemJson, presetMapping.source);\\n  const payload = getMappedValue(itemJson, presetMapping.payload);\\n  if (source === null || payload === null) {\\n    throw new Error(\\"Mandatory vector store results property is either not available or null\\");\\n  }\\n  \\n  const doc = {\\n    \\"id\\": getMappedValue(itemJson, presetMapping.id),\\n    \\"source\\": source,\\n    \\"score\\": getMappedValue(itemJson, presetMapping.score),\\n    \\"payload\\": payload,\\n    \\"metadata\\": buildPassthroughMetadata(itemJson)\\n  }\\n  //swconsole.log(doc)\\n  docs.push(doc);\\n}\\n\\nreturn {\\n  \\"vector_hits\\":  docs\\n};"},"typeVersion":2,"name":"Prepare response","position":[1136,0],"id