hate speech, violence, illegal activity encouragement)\\n4. Requests for unrelated external advice (e.g., \\"give me medical advice about X\\" unrelated to system scope)\\n\\nDo NOT flag:\\n- Specific or detailed queries about system data (clients, staff, projects, financials)\\n- Queries you don't recognize or can't verify (assume they're valid internal data)\\n\\nIf the query is about entities/data the system is designed to hold, mark as safe.\\n\\nUser Input: {{ $json.user_message }}\\n\\nRespond with ONLY valid JSON:\\n{\\n  \\"is_safe\\": true,\\n  \\"risk_level\\": \\"low\\",\\n  \\"flags\\": [],\\n  \\"reason\\": \\"Query is appropriate\\"\\n}\\n`;\\n\\n// Value to inject\\nconst chatInput = $('Basic_Validation').first().json.chatInput;\\n\\n// Replace the placeholder\\njson.inputGuardrailsPrompt = inputGuardrailsPrompt.replace(\\n  '{{ $json.user_message }}',\\n  chatInput\\n);\\n\\njson.structuredOutputParserJsonSchema = {\\n  \\"$schema\\": \\"http://json-schema.org/draft-07/schema#\\",\\n  \\"type\\": \\"object\\",\\n  \\"properties\\": {\\n    \\"is_safe\\": {\\n      \\"type\\": \\"boolean\\"\\n    },\\n    \\"risk_level\\": {\\n      \\"type\\": \\"string\\"\\n    },\\n    \\"flags\\": {\\n      \\"type\\": \\"array\\",\\n      \\"items\\": {}\\n    },\\n    \\"reason\\": {\\n      \\"type\\": \\"string\\"\\n    }\\n  },\\n  \\"required\\": [\\n    \\"is_safe\\",\\n    \\"risk_level\\",\\n    \\"flags\\",\\n    \\"reason\\"\\n  ],\\n  \\"additionalProperties\\": false\\n}\\n\\n// Return the same structure as input, with only that change\\nreturn [{ json }];\\n"}},{"typeVersion":1.2,"name":"LLM call","position":[288,-32],"id":"27da4ea0-c32f-45c5-9ae0-5f14518b7d8e","type":"n8n-nodes-base.executeWorkflow","parameters":{"workflowInputs":{"schema":[{"defaultMatch":false,"canBeUsedToMatch":true,"removed":false,"displayName":"prompt","display":true,"id":"prompt","type":"string","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"removed":false,"d