Utils - Write Journey Step Processing	t	[{"parameters":{"workflowInputs":{"values":[{"name":"conversationId"},{"name":"questionId"},{"name":"phase"},{"name":"step"},{"name":"type"},{"name":"value"}]}},"typeVersion":1.1,"name":"When Executed by Another Workflow","position":[0,0],"id":"cb0f55db-6260-4496-b584-d3b9157fe3f5","type":"n8n-nodes-base.executeWorkflowTrigger"},{"parameters":{"jsCode":"const input = $input.first().json;\\n\\nlet fs, path;\\ntry {\\n  fs = require('fs');\\n  path = require('path');\\n} catch (e) {\\n  return [{ json: { written: false, error: `fs/path module unavailable: ${e.message}`, phase: input.phase, step: input.step, file: null } }];\\n}\\n\\nconst BASE_DIR   = '/data/staging/output/journey';\\nconst MAX_STRING = 3000;\\nconst MAX_ARRAY  = 10;\\nconst MAX_DEPTH  = 5;\\n\\nfunction summarize(val, depth) {\\n  depth = depth || 0;\\n  if (val === null || val === undefined) return val;\\n  if (depth >= MAX_DEPTH) return '[max depth reached]';\\n  if (typeof val === 'string') {\\n    return val.length > MAX_STRING\\n      ? val.slice(0, MAX_STRING) + `…[truncated, ${val.length} chars total]`\\n      : val;\\n  }\\n  if (typeof val !== 'object') return val;\\n  if (Array.isArray(val)) {\\n    const out = val.slice(0, MAX_ARRAY).map(v => summarize(v, depth + 1));\\n    if (val.length > MAX_ARRAY) out.push(`…[truncated, ${val.length} items total]`);\\n    return out;\\n  }\\n  const out = {};\\n  for (const k of Object.keys(val)) out[k] = summarize(val[k], depth + 1);\\n  return out;\\n}\\n\\nconst safe = s => String(s || 'unknown').replace(/[^a-zA-Z0-9_-]/g, '_');\\n\\nconst record = {\\n  ts:             new Date().toISOString(),\\n  conversationId: input.conversationId,\\n  questionId:     input.questionId,\\n  phase:          input.phase,\\n  step:           input.step,\\n  type:           input.type,\\n  value:          summarize(input.value, 0),\\n};\\n\\nconst dir      = path.join(BASE_DIR, safe(record.conversationId), safe(record.questionId));\\nconst filePath = path.join(dir, `${safe(record.phase)}-${safe(record.step)}.json`);\\n\\nlet written = false;\\nlet error   = null;\\n\\ntry {\\n  fs.mkdirSync(dir, { recursive: true });\\n  fs.writeFileSync(filePath, JSON.stringify(record, null, 2), 'utf-8');\\n  written = true;\\n} catch (e) {\\n  error = e.message;\\n  console.log(`[journey-write] failed for phase=${input.phase} step=${input.step}: ${e.message}`);\\n}\\n\\nreturn [{ json: { written, error, phase: input.phase, step: input.step, file: filePath } }];\\n"},"typeVersion":2,"name":"Write Journey Step","position":[240,0],"id":"51cd6c96-7d25-4b2e-9524-449b2ff1b724","type":"n8n-nodes-base.code"}]	{"When Executed by Another Workflow":{"main":[[{"node":"Write Journey Step","index":0,"type":"main"}]]}}	2026-07-11 19:49:58.002+00	2026-07-12 17:04:15.43+00	{"executionOrder":"v1","availableInMCP":false,"binaryMode":"separate"}	\N	{}	1dd615a2-d180-41ce-98e6-ef7d80d7e6ff	0	nWwY5o2Cz7m5SbfA	{"templateCredsSetupCompleted":true,"instanceId":"982a83c4fa14b8860ea8391b8f766ad449d7431aac64126d0b9fc936877b58be"}	\N	f	3	\N	1dd615a2-d180-41ce-98e6-ef7d80d7e6ff	[]
Step - Short-term memory - Async	t	[{"typeVersion":2,"name":"Extract Q&A pairs","position":[-1872,400],"id":"ed0d1662-3305-48f7-95b2-cd09880b58ae","type":"n8n-nodes-base.code","parameters":{"jsCode":"const qaList = [];\\n\\nfor(var item of $input.first().json.questions) {\\n   var question =\\"\\";\\n   var answer=\\"\\";\\n\\n  for(var mess of item.messages){\\n     if(mess.messageType == \\"START\\"){\\n       question = mess.payload.question;\\n     }else if(mess.messageType==\\"ANSWER\\"){\\n       answer = mess.payload.answer;\\n     }\\n   }\\n\\n  qaList.push(\\n    {\\n      \\"question\\":question,\\n      \\"answer\\":answer\\n    }\\n  )\\n}\\n\\n\\nreturn qaList;"},"alwaysOutputData":true},{"typeVersion":2.2,"name":"If size is large","position":[-976,400],"id":"97b98402-130a-470a-beee-5684fdedfec6","type":"n8n-nodes-base.if","parameters":{"options":{},"conditions":{"combinator":"and","options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":2},"conditions":[{"leftValue":"={{ $('Calculate size in tokens').item.json.size }}","rightValue":"={{ $('Call \\\\'Configuration (sub-workflow)\\\\'').first().json.shortMemoryMaxUncompressedSizeInTokens }}","id":"816a6694-f3d1-479e-82a1-04f34793b2ed","operator":{"type":"number","operation":"gt"}}]}}},{"typeVersion":2,"name":"Prepare Q&A block","position":[-1680,400],"id":"fe719b45-08e6-4c29-ba62-b727f2df05b3","type":"n8n-nodes-base.code","parameters":{"jsCode":"/* the end goal is to create a string with the following format:\\n  Question: jhahfdshk,\\n  Answer: akshdkjsa;\\n  Question:749879837,\\n  Answer: jskjfjs;\\n*/\\nvar  blockStr=\\"\\";\\n\\nfor (var pair of $('Extract Q&A pairs').all()) {\\n    blockStr += \\"Question:\\"+pair.json.question;  \\n    blockStr += \\",\\\\n\\";\\n    blockStr += \\"Answer:\\"+pair.json.answer;\\n   blockStr += \\";\\\\n\\";\\n}\\n\\nreturn {\\n  \\"qaString\\":blockStr,\\n  \\"newQuestion\\":$('prepare input data').first().json.newQuestion,\\n  \\"sessionId\\":$('prepare input data').first().json.sessionId\\n}"},"alwaysOutputData":true},{"typeVersion":2,"name":"Calculate size in tokens","position":[-1488,400],"id":"925ad93a-f8df-4240-9c13-a5592b51a6ac","type":"n8n-nodes-base.code","parameters":{"jsCode":"var size=0\\n\\n// the size is returned in tokens. The rule of thumb is string size divided by 3 or 4\\nsize = $input.first().json.qaString.length / 3;\\n\\nreturn {\\n  \\"size\\":size\\n};"},"alwaysOutputData":true},{"typeVersion":1.3,"name":"Call 'Compress short memory (sub-workflow)'","position":[-640,224],"id":"7753493f-3638-406d-9f4e-bd9d8e538218","type":"n8n-nodes-base.executeWorkflow","parameters":{"workflowInputs":{"schema":[{"defaultMatch":false,"canBeUsedToMatch":true,"removed":false,"displayName":"qaBlock","display":true,"id":"qaBlock","type":"string","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"removed":false,"displayName":"question","display":true,"id":"question","type":"string","required":false}],"attemptToConvertTypes":false,"matchingColumns":[],"convertFieldsToString":true,"mappingMode":"defineBelow","value":{"question":"={{ $('Prepare Q&A block').item.json.newQuestion }}","qaBlock":"={{ $('Prepare Q&A block').item.json.qaString }}"}},"options":{},"workflowId":{"mode":"list","cachedResultUrl":"/n8n/workflow/b8kENTFolf5BFo89","__rl":true,"cachedResultName":"Utils - Compress short memory","value":"b8kENTFolf5BFo89"}}},{"typeVersion":2,"name":"Prepare response","position":[-416,224],"id":"64792ba3-986c-4cf7-bb88-1620ce3e280b","type":"n8n-nodes-base.code","parameters":{"jsCode":"return {\\n  \\"response\\": $input.first().json.compressedString,\\n  \\"executionId\\": $input.first().json.executionId\\n}"}},{"typeVersion":1,"name":"Sticky Note2","position":[-2816,80],"id":"af6faadf-ef26-4b3d-8ae4-d453572a3473","type":"n8n-nodes-base.stickyNote","parameters":{"width":416,"content":"## Input\\n- **conversationId**: string - The internal UUID of the conversation of the current question\\