\"\\",\\n        \\"alternativeTerms\\": [\\n        ]\\n      },\\n      \\"keySubtopics\\": [\\n      ],\\n      \\"detailedTopics\\": [\\n      ],\\n      \\"relatedConcepts\\": [\\n      ],\\n      \\"allAlternativeTerms\\": [\\n      ]\\n    },\\n    \\"semanticStructure\\": {\\n      \\"hierarchyDepth\\": 0,\\n      \\"hasBroaders\\": false,\\n      \\"hasNarrowers\\": false,\\n      \\"hasRelateds\\": false\\n    },\\n    \\"fullConcepts\\": [\\n    ],\\n    \\"timestamp\\": \\"\\"\\n  }\\n};\\n\\nvar shortMemory = \\n{\\n  \\"response\\": \\"\\"\\n};\\n\\nvar vectorHits = {\\n    \\"vector_hits\\": []\\n  }\\n;\\n\\n\\nvar graphdbMcp = {\\n  \\"grpahdbMCPresponse\\": \\"\\"\\n};\\n\\nfor(var itemInd in items){\\n  var obj = items[itemInd];\\n\\n  var step = obj.json.step;\\n  var type = obj.json.type;\\n  var json = JSON.parse(obj.json.value);\\n\\n  if(\\"success\\".localeCompare(type)==0 && \\"intent\\".localeCompare(step)==0){\\n    intentClassification = json;\\n  }else if(\\"success\\".localeCompare(type)==0 && \\"short-memory\\".localeCompare(step)==0){\\n    shortMemory = json.shortMemory;\\n  }else if(\\"success\\".localeCompare(type)==0 && \\"concept-expansion\\".localeCompare(step)==0){\\n    conceptExpansion = json;\\n  }else if(\\"success\\".localeCompare(type)==0 && \\"vector-search\\".localeCompare(step)==0){\\n    vectorHits = json.vectorSearch;\\n  }else if(\\"success\\".localeCompare(type)==0 && \\"concept-enricher\\".localeCompare(step)==0){\\n    conceptEnrichment = json;\\n  }else if(\\"success\\".localeCompare(type)==0 && \\"graphdb-mcp\\".localeCompare(step)==0){\\n    graphdbMcp = json;\\n  }\\t\\n  \\n}\\n\\nreturn {\\n   \\"intentClassification\\": intentClassification.intentClassification,\\n   \\"vectorHits\\": vectorHits.vector_hits,\\n   \\"shortmemory\\": shortMemory,\\n   \\"concepts\\": conceptEnrichment,\\n   \\"conceptExpansion\\": conceptExpansion,\\n   \\"graphdb\\": graphdbMcp,\\n   \\"question\\": $('When Executed by Ano