.map(x => x.step)\\n    .filter(step => typeof step === \\"string\\" && step.length > 0)\\n);\\n\\n// Collect missing active steps\\nconst missing = Object.values(activeFlags)\\n  .filter(flag => flag?.isActive === true && flag?.stepTag)\\n  .filter(flag => !existingSteps.has(flag.stepTag))\\n  .map(flag => ({\\n    stepName: flag.stepName,\\n    message: flag.message || `Step \\"${flag.stepTag}\\" is missing`,\\n  }));\\n\\nreturn missing.map(item => ({ json: item }));"}},{"typeVersion":2,"name":"Build Ex message - Step has timed out","position":[288,0],"id":"b3ac79c6-aac6-4321-9e5f-1512c56eb434","type":"n8n-nodes-base.code","parameters":{"mode":"runOnceForEachItem","jsCode":"return {     \\n  \\"questionId\\": $('Execute workflow').first().json.questionId,\\n  \\"conversationId\\": $('Execute workflow').first().json.conversationId,\\n  \\"userId\\": $('Execute workflow').first().json.userId,\\n  \\"messageType\\": \\"EXPLAINABILITY\\",\\n  \\"payload\\":{\\n    \\"stepName\\": $json.stepName,\\n    \\"description\\": $json.message,\\n    \\"noticeType\\": \\"ERROR\\"\\n  }\\n};"}},{"typeVersion":4.2,"notesInFlow":false,"name":"Send Ex message - Step has timed out","position":[480,0],"id":"8d8a6780-6c61-4529-a22f-34a0185af3bb","type":"n8n-nodes-base.httpRequest","parameters":{"sendQuery":true,"method":"POST","queryParameters":{"parameters":[{"name":"questionId","value":"={{ $('Execute workflow').first().json.questionId }}"}]},"headerParameters":{"parameters":[{"name":"Accept","value":"application/json"}]},"sendBody":true,"options":{},"body":"={{ JSON.stringify( $json ) }}","sendHeaders":true,"contentType":"raw","url":"={{ $('Execute workflow').first().json.backendSseMessageUrl }}","rawContentType":"application/json"}}]	{"Execute workflow":{"main":[[{"node":"Get all rows for the executionId","index":0,"type":"main"}]]},"Find missing steps":{"main":[[{"node":"Build Ex message - Step has timed out","index":0,"type":"main"}]]},"Build Ex message - Step has timed out":{"