re result","position":[80,-32],"id":"014a7434-d1c8-4940-b49e-07ba3aeed94a","type":"n8n-nodes-base.code","parameters":{"jsCode":"let finalAnswer = $input.first().json.output;\\n\\nif (finalAnswer && typeof finalAnswer === 'string' && finalAnswer.includes('References:')) {\\n  const parts = finalAnswer.split('References:');\\n  const messageBody = parts[0].trim();\\n  const referencesPart = parts[1];\\n\\n  const lines = referencesPart.split('\\\\n');\\n  const uniqueLines = [];\\n  const seenUrls = new Set();\\n\\n  for (let line of lines) {\\n    let cleanLine = line.trim();\\n    \\n    if (cleanLine === '' || cleanLine === '*') continue;\\n\\n    let url = cleanLine\\n      .replace(/^[\\\\s*]+/, '') \\n      .split(' (additional text)')[0]\\n      .split(' (part')[0]\\n      .trim();\\n\\n    if (url !== '' && !seenUrls.has(url)) {\\n      seenUrls.add(url);\\n      uniqueLines.push(`* ${url}`);\\n    }\\n  }\\n\\n  finalAnswer = messageBody + '\\\\n\\\\n**References:**\\\\n' + uniqueLines.join('\\\\n');\\n}\\n\\nreturn {\\n  \\"response\\": finalAnswer,\\n  \\"executionId\\": $('LLM call').first().json.executionId,\\n  \\"question\\": $('When executed by another workflow').first().json.question,\\n};"}},{"typeVersion":1.1,"name":"When executed by another workflow","position":[-1520,-32],"id":"dde15e9a-8cf8-4d74-a9c9-86e5e713440e","type":"n8n-nodes-base.executeWorkflowTrigger","parameters":{"workflowInputs":{"values":[{"name":"question"},{"name":"intent","type":"object"},{"name":"vector_hits","type":"array"},{"name":"shortMemory"},{"name":"sessionId"},{"name":"concepts"},{"name":"grpahdbMCPresponse"}]}}},{"typeVersion":1.3,"onError":"continueErrorOutput","name":"LLM call","position":[-512,-32],"id":"5cc2b738-106a-4cd1-a136-6cfb684db029","type":"n8n-nodes-base.executeWorkflow","parameters":{"workflowInputs":{"schema":[{"defaultMatch":false,"canBeUsedToMatch":true,"displayName":"prompt","display":true,"id":"prompt","type":"string","required":false},{"defaultMatch":