not answer this question based on the provided context and, where relevant, in a second paragraph mention which exact information is missing in the context required to answer the question.\\n\\nContext:\\n{\\n\\"Context of current conversation\\": {{ Prepared shortMemory }},\\n\\"Documents found\\": {{ Vector hits }}\\n\\"Knowledge graph data\\": {{ Knowledge graph data }}\\n\\"Important Concepts\\": {{ Extracted concepts }}\\n}\\n\\nIn cases where the answer to the question can be found in the context and answering the question properly doesn't require a specific structure and no specific sturucture / format of an answer is requested in the question, please structure the answer as follows:\\n1. Main topic/theme (2–3 sentences)\\n2. Key points (bullet list)\\n3. Important details or findings\\n4. Conclusions or recommendations (if any)\\n\\nIf one of the sections doesn't make sense for the given question or content repeats itself in various sections, skip sections as needed.\\n\\n**After the answer, add a \\\\`References:\\\\` section\\\\\\\\n\\nput *each* cited document on a **new line** (use an explicit line-break, not a comma) in **exactly** this format:**\\\\\\\\n`\\n\\nconst shortMemory = $('Prepare data').first().json.shortMemory;\\nconst vectors = $('Prepare data').first().json.vectors;\\nconst mcp = $('Prepare data').first().json.mcp;\\nconst concepts = $('Prepare data').first().json.concepts;\\n\\n\\nsystemMessageTemplate = systemMessageTemplate.replace('{{ Prepared shortMemory }}', shortMemory);\\nsystemMessageTemplate = systemMessageTemplate.replace('{{ Vector hits }}', vectors);\\nsystemMessageTemplate = systemMessageTemplate.replace('{{ Knowledge graph data }}', mcp);\\nsystemMessageTemplate = systemMessageTemplate.replace('{{ Extracted concepts }}', concepts);\\n\\n\\nconst structuredOutputParserJsonSchema = {\\n  \\"$schema\\": \\"http://json-schema.org/draft-07/schema#\\",\\n  \\"type\\": \\"object\\",\\n  \\"properties\\": {\\n    \\"output\\": {\\n      \\"type\\": \\"string\\"\\n    }\\n  },\\n  \\"required\\": [\\n    \\"output\\"\\n  ],\\n     \\"additionalProperties\\": false\\n}\\n\\nreturn { \\"systemMessageTemplate\\" : systemMessageTemplate,\\n         \\"structuredOutputParserJsonSchema\\" : structuredOutputParserJsonSchema\\n       }\\n"}}]	{"Extract answer":{"main":[[{"node":"Prepare result","index":0,"type":"main"}]]},"Prepare result":{"main":[[]]},"Call 'Configuration (sub-workflow)'":{"main":[[{"node":"Prepare data for LLM call","index":0,"type":"main"}]]},"LLM call":{"main":[[{"node":"Extract answer","index":0,"type":"main"}]]},"When executed by another workflow":{"main":[[{"node":"Prepare data","index":0,"type":"main"}]]},"Prepare data":{"main":[[{"node":"Call 'Configuration (sub-workflow)'","index":0,"type":"main"}]]},"Prepare data for LLM call":{"main":[[{"node":"LLM call","index":0,"type":"main"}]]}}	initial_publish	f	Initially publishing the workflow via the conversation API	[]
