ng structure:\\n{\\n    \\"follow_up_questions\\": [\\n        {\\n            \\"question\\": \\"The follow-up question\\",\\n            \\"reasoning\\": \\"Why this question is relevant\\",\\n            \\"topics\\": [\\"List\\", \\"of\\", \\"relevant\\", \\"topics\\"]\\n        }\\n    ]\\n}\\n\\nFocus on technical accuracy and professional communication. Return ONLY the JSON object, with no additional text or explanation.`\\n\\nconst question = $('prepare input data').first().json.question;\\nconst answer = $('prepare input data').first().json.answer;\\n\\nsystemMessageTemplate = systemMessageTemplate.replace('{{ Question }}', question);\\nsystemMessageTemplate = systemMessageTemplate.replace('{{ Answer }}', answer);\\n\\nconst structuredOutputParserJsonSchema = {\\n  \\"$schema\\": \\"http://json-schema.org/draft-07/schema#\\",\\n  \\"type\\": \\"object\\",\\n  \\"properties\\": {\\n    \\"follow_up_questions\\": {\\n      \\"type\\": \\"array\\",\\n      \\"items\\": {\\n        \\"type\\": \\"object\\",\\n        \\"properties\\": {\\n          \\"question\\": {\\n            \\"type\\": \\"string\\"\\n          },\\n          \\"reasoning\\": {\\n            \\"type\\": \\"string\\"\\n          },\\n          \\"topics\\": {\\n            \\"type\\": \\"array\\",\\n            \\"items\\": {\\n              \\"type\\": \\"string\\"\\n            }\\n          }\\n        },\\n        \\"required\\": [\\n          \\"question\\",\\n          \\"reasoning\\",\\n          \\"topics\\"\\n        ],\\n          \\"additionalProperties\\": false\\n      }\\n    }\\n  },\\n  \\"required\\": [\\n    \\"follow_up_questions\\"\\n  ],\\n    \\"additionalProperties\\": false\\n}\\n\\nreturn { \\"systemMessageTemplate\\" : systemMessageTemplate,\\n         \\"structuredOutputParserJsonSchema\\" : structuredOutputParserJsonSchema\\n       }\\n"}}]	{"prepare input data":{"main":[[{"node":"Call 'Configuration (sub-workflow)'","index":0,"type":"main"}]]},"Call 'Configurati