on":[-480,-16],"id":"254a4ade-26f9-41bb-bd5b-1bfe07b066a2","type":"n8n-nodes-base.code","parameters":{"jsCode":"var systemMessageTemplate = `You are a moderation assistant for an internal RAG system that uses private, authoritative data sources.\\nTreat all factual statements that are supported by the provided answer and its references as true for the purpose of this evaluation, even if you personally do not know them or cannot verify them.\\n\\nYour tasks:\\n\\nRate how well the answer addresses the question on a scale 1–10, focusing on relevance, completeness, and clarity. Do not reduce the score just because the facts are unfamiliar to you.\\n\\nCheck for:\\n\\nHate speech or offensive content.\\nEncouragement of illegal or clearly unethical behavior.\\nBias against protected groups.\\nViolations of privacy (e.g., exposing personal data about private individuals that is not present in the user’s question).\\nNonsensical, irrelevant, or incoherent information.\\nInternal inconsistency (the answer contradicts itself).\\nOnly mark “misinformation” if the answer:\\nDirectly contradicts itself, or\\nDirectly contradicts the user’s question, or\\nPresents obviously impossible claims (e.g., “2+2=5”, “the sun orbits the Earth”) that do not come from the provided context.\\nDo not call something misinformation just because it is specific, unfamiliar, or not verifiable from your own training.\\n\\nThe question:\\n{{ Question }}\\n\\n\\nThe answer:\\n{{ Answer }}\\n\\nPlease provide the reponse in the following JSON format:\\n\\n{\\n\\t\\"result\\": \\"10 for excellent, 1 for worst\\",\\n\\t\\"description\\": \\"what rules were violated\\",\\n\\t\\"severity\\" :\\"low, medium or high\\"\\n} `\\n\\nconst question = $('prepare input data').first().json.question;\\nconst answer = $('prepare input data').first().json.answer;\\n\\nsystemMessageTemplate = systemMessageTemplate.replace('{{ Question }}', question);\\nsystemMessageTemplate = systemMessageTemplate.replace('{{ Answer }}', answer);\\n\\nconst structuredOutputParserJsonSchema = {\\n  \\"$schema\\": \\"http://json-schema.org/draft-07/schema#\\",\\n  \\"type\\": \\"object\\",\\n  \\"properties\\": {\\n    \\"result\\": {\\n      \\"type\\": \\"number\\"\\n    },\\n    \\"description\\": {\\n      \\"type\\": \\"string\\"\\n    },\\n    \\"severity\\": {\\n      \\"type\\": \\"string\\"\\n    }\\n  },\\n  \\"required\\": [\\n    \\"result\\",\\n    \\"description\\",\\n    \\"severity\\"\\n  ],\\n   \\"additionalProperties\\": false\\n}\\n\\nreturn { \\"systemMessageTemplate\\" : systemMessageTemplate,\\n         \\"structuredOutputParserJsonSchema\\" : structuredOutputParserJsonSchema\\n       }\\n"}},{"typeVersion":1.3,"onError":"continueErrorOutput","name":"LLM call","position":[-176,-16],"id":"4cdacc23-1f37-4606-961e-5807b37e1df8","type":"n8n-nodes-base.executeWorkflow","parameters":{"workflowInputs":{"schema":[{"defaultMatch":false,"canBeUsedToMatch":true,"displayName":"prompt","display":true,"id":"prompt","type":"string","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"displayName":"primaryLLMModel","display":true,"id":"primaryLLMModel","type":"string","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"displayName":"secondaryLLMModel","display":true,"id":"secondaryLLMModel","type":"string","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"displayName":"structuredOutputParserJsonSchema","display":true,"id":"structuredOutputParserJsonSchema","type":"object","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"displayName":"systemMessage","display":true,"id":"systemMessage","type":"string","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"displayName":"maxNumberTokens","display":true,"id":"maxNumberTokens","type":"number","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"displayName":"samplingTemperature","display":true,"id":"samplingTemperature","type":"number","required":false}],"attemptToConvertTypes":false,"matchingColumns":[],"convertFieldsToString":true,"mappingMode":"defineBelow","value":{"systemMessage":"={{ $json.systemMessageTemplate }}","structuredOutputParserJsonSchema":"={{ $json.structuredOutputParserJsonSchema }}","maxNumberTokens":1000,"samplingTemperature":0,"prompt":"Evaluate the answer to the question","secondaryLLMModel":"={{ $('Call \\\\'Configuration (sub-workflow)\\\\'').item.json.secondaryLLMModel }}","primaryLLMModel":"={{ $('Call \\\\'Configuration (sub-workflow)\\\\'').item.json.primaryLLMModel }}"}},"options":{},"workflowId":{"mode":"list","cachedResultUrl":"/n8n/workflow/icEaxOxBisUj5nUb","__rl":true,"cachedResultName":"LLM call","value":"icEaxOxBisUj5nUb"}}}]	{"prepare input data":{"main":[[{"node":"Call 'Configuration (sub-workflow)'","index":0,"type":"main"}]]},"Prepare output data":{"main":[[{"node":"Insert success data for parallel sync","index":0,"type":"main"}]]},"Call 'Configuration (sub-workflow)'":{"main":[[{"node":"Prepare data for LLM call","index":0,"type":"main"}]]},"Prepare error data":{"main":[[{"node":"Insert error data for parallel sync","index":0,"type":"main"}]]},"LLM call":{"main":[[{"node":"Prepare output data","index":0,"type":"main"}],[{"node":"Prepare error data","index":0,"type":"main"}]]},"Webhook":{"main":[[{"node":"prepare input data","index":0,"type":"main"}]]},"Prepare data for LLM call":{"main":[[{"node":"LLM call","index":0,"type":"main"}]]}}	initial_publish	f	Initially publishing the workflow via the conversation API	[]
28aad05b-608c-4608-89e3-724fa406ad36	CxgHGMN2a1fwwEmt	import	2026-03-27 08:43:56.482+00	2026-03-27 08:43:59.97+00	[{"typeVersion":1,"name":"Sticky Note","position":[-896,48],"id":"7f45e886-4a44-4231-b685-6c75d366c9f6","type":"n8n-nodes-base.stickyNote","parameters":{"width":784,"content":"## What to use this workflow for\\n- Final answer injection\\n- Retrieval\\nwe should provide both options, with easy activation and deactivation ---------> see the next sticky note","height":128}},{"typeVersion":1,"name":"Sticky Note1","position":[0,0],"id":"c684fada-573b-4533-b9ae-0cf8d4a0b287","type":"n8n-nodes-base.stickyNote","parameters":{"width":752,"content":"🧭 Summary of What to Use Where\\n────────────────────────────────────────\\n*Use Case:*          |  |  |         *Output Field:*        |  |  |       *What to Keep:*\\n────────────────────────────────────────\\n**Final Answer (LLM)**         |  |  |   llmContextText            |  |  |  Full explanations\\n**Query Rewriting Prompt**      |  |  |   queryRewritingContext     |  |  |  Primary terms, synonyms, broader context\\n**Dense Vector Retrieval**      |  |  |   retrievalQueries          |  |  |  Multiple query variations + definitions\\n**Sparse / Keyword Retrieval**  |  |  |   keywords / keywordsText   |  |  |  Just the labels (no definitions)\\n**Hybrid Retrieval**           |  |  |  queryExpansion object      |  |  | All terms organized by type\\n────────────────────────────────────────\\n\\n🧩 Recommended Workflow\\n• Use retrievalQueries to generate 3–7 vector searches  \\n• Use keywords for BM25 / keyword-based search  \\n• Combine results (hybrid retrieval)  \\n• Use llmContextText when injecting context into final answer\\n\\n","height":400}},{"typeVersion":2,"name":"URI extraction and batch","position":[128,480],"id":"2b4f5004-e7dd-4c9d-9418-ed342668ff8e","type":"n8n-nodes-base.code","parameters":{"jsCode":"// SIMPLIFIED: Extract URIs and create batch request directly\\nconst items = $input.all();\\nconst output = [];\\n\\nfor (const item of items) {\\n  try {\\n    const response = item.json;\\n    const projectId = response.projectId || response.project || $('Configuration').first().json.poolPartyProjectId;\\n    \\n    // Track URIs with their types (single Map, no Sets)\\n    const uriTypeMap = new Map();\\n    \\n    if (response.concepts && Array.isArray(response.concepts)) {\\n      response.concepts.forEach(concept => {\\n        if (concept.uri) {\\n          if (!uriTypeMap.has(concept.uri)) uriTypeMap.set(concept.uri, []);\\n          if (!uriTypeMap.get(concept.uri).includes('seed')) {\\n            uriTypeMap.get(concept.uri).push('seed');\\n          }\\n        }\\n      });\\n    }\\n    \\n    const urisArray = Array.from(uriTypeMap.keys());\\n    \\n    // DIRECT OUTPUT: Single batched item, no splitting\\n    output.push({\\n      json: {\\n        conceptUris: urisArray,\\n        projectId: projectId,\\n        originalExtractionResponse: response,\\n        batchSize: urisArray.length,\\n        timestamp: new Date().toISOString()\\n      }\\n    });\\n    \\n  } catch (error) {\\n    output.push({\\n      json: {\\n        error: true,\\n        errorMessage: error.message,\\n        timestamp: new Date().toISOString()\\n      }\\n    });\\n  }\\n}\\n\\nreturn output;"},"alwaysOutputData":true},{"typeVersion":4.2,"credentials":{"httpBasicAuth":{"id":"emxYnbbzTTT6DtWc","name":"PoolParty Credentials"}},"name":"Extract concepts terms from ChatMessage","position":[-144,480],"id":"3f701e9e-c55a-4e55-ac7b-10e11a152e98","type":"n8n-nodes-base.httpRequest","parameters":{"bodyParameters":{"parameters":[{"name":"projectId","value":"={{ $json.poolpartyConfig.formData.projectId }}"},{"name":"text","value":"={{ $json.poolpartyConfig.formData.text }}"},{"name":"language","value":"={{ $json.poolpartyConfig.formData.language }}"},{"name":"numberOfConcepts","value":"={{ $json.poolpartyConfig.formData.numberOfConcepts }}"},{"name":"showMatchingDetails","value":"={{ $json.poolpartyConfig.formData.showMatchingDetails }}"},{"name":"displayText","value":"={{ $json.poolpartyConfig.formData.displayText }}"},{"name":"filterNestedConcepts","value":"={{ $json.poolpartyConfig.formData.filterNestedConcepts }}"},{"name":"useRelatedConcepts","value":"={{ $json.poolpartyConfig.formData.useRelatedConcepts }}"},{"name":"showMatchingPosition","value":"true"},{"name":"conceptMinimumScore","value":"={{ $json.poolpartyConfig.formData.conceptMinimumScore }}"},{"name":"numberOfTerms","value":"0"}]},"method":"POST","sendBody":true,"options":{"response":{"response":{}}},"genericAuthType":"httpBasicAuth","contentType":"form-urlencoded","url":"={{ $json.poolpartyConfig.apiUrl }}","authentication":"genericCredentialType"}},{"typeVersion":2,"name":"Build extraction request","position":[-384,480],"id":"929373c2-31f0-4788-84cb-17a2118f6e51","type":"n8n-nodes-base.code","parameters":{"jsCode":"// Build ENHANCED PoolParty API request with optimal parameters\\nconst items = $('When executed by another workflow').all();\\nconst output = [];\\n\\nconst POOLPARTY_CONFIG = {\\n  serverUrl: $input.first().json.poolPartyServerUrl,\\n  projectId: $input.first().json.poolPartyProjectId,\\n  username: '{{POOLPARTY_USERNAME}}',\\n  password: '{{POOLPARTY_PASSWORD}}'\\n};\\n\\nfor (const item of items) {\\n  \\n  const text = item.json.chatInput;\\n  const language = item.json.language || 'en';\\n  \\n  // ENHANCED parameters based on API research\\n  const formData = {\\n    projectId: POOLPARTY_CONFIG.projectId,\\n    text: text,\\n    language: language,\\n    numberOfConcepts: '15',  // Increased for better coverage\\n    conceptMinimumScore: '20', // Concept score threshold (0 to 100)\\n    \\n    // CRITICAL: Get full hierarchies in ONE call\\n    useTransitiveBroaderConcepts: 'true',\\n    useTransitiveBroaderTopConcepts: 'true',\\n    \\n    // Quality improvements\\n    useRelatedConcepts: 'true',\\n    filterNestedConcepts: 'true',\\n    showMatchingDetails: 'true',\\n    \\n    // Advanced scoring\\n    corpusScoring: 'true',  // Better relevance for RAG queries\\n    disambiguate: 'true',   // Resolve ambiguous terms\\n    \\n    // Optional: If you have a corpus configured\\n    // shadowConceptCorpusId: 'your-corpus-id',  // Discovers implicit concepts\\n    \\n    displayText: 'false'\\n  };\\n  \\n  output.push({\\n    json: {\\n      ...item.json,\\n      poolpartyConfig: {\\n        apiUrl: `${POOLPARTY_CONFIG.serverUrl}/extractor/api/extract`,\\n        formData: formData\\n      }\\n    }\\n  });\\n}\\n\\nreturn output;"},"alwaysOutputData":true},{"typeVersion":1.1,"maxTries":2,"onError":"continueRegularOutput","name":"When executed by another workflow","position":[-880,480],"id":"8ec3ad6d-4004-4473-9e94-fe9f1d9599d6","type":"n8n-nodes-base.executeWorkflowTrigger","retryOnFail":true,"parameters":{"workflowInputs":{"values":[{"name":"chatInput"},{"name":"language"},{"name":"targetAction"},{"name":"topics"},{"name":"jwtToken"}]}},"alwaysOutputData":true},{"typeVersion":1.3,"name":"Configuration","position":[-640,480],"id":"cd7beaba-1893-4d68-ae85-f699b11d1a83","type":"n8n-nodes-base.executeWorkflow","parameters":{"workflowInputs":{"mappingMode":"defineBelow","value":{}},"options":{},"workflowId":{"mode":"list","cachedResultUrl":"/workflow/HJcJwMTssnY79HWw","__rl":true,"cachedResultName":"Configuration (sub-workflow)","value":"HJcJwMTssnY79HWw"}}},{"typeVersion":4.2,"name":"Fetch concept details","position":[400,480],"id":"3e25ac7f-1a16-40ff-8f69-912ce6543e91","type":"n8n-nodes-base.httpRequest","parameters":{"bodyParameters":{"parameters":[{"name":"conceptUris","value":"={{ $json.conceptUris }}"},{"name":"originalExtractionResponse","value":"={{ $json.originalExtractionResponse }}"},{"name":"batchSize","value":"={{ $json.batchSize }}"}]},"method":"POST","headerParameters":{"parameters":[{"name":"Authentication","value":"=Bearer {{ $('When executed by another workflow').item.json.jwtToken }}"}]},"sendBody":true,