x[i]+\\"]\\") : (\\"['\\"+x[i]+\\"']\\");\\n         return p;\\n      },\\n      store: function(p, v) {\\n         if (p) P.result[P.result.length] = P.resultType == \\"PATH\\" ? P.asPath(p) : v;\\n         return !!p;\\n      },\\n      trace: function(expr, val, path) {\\n         if (expr) {\\n            var x = expr.split(\\";\\"), loc = x.shift();\\n            x = x.join(\\";\\");\\n            if (val && val.hasOwnProperty(loc))\\n               P.trace(x, val[loc], path + \\";\\" + loc);\\n            else if (loc === \\"*\\")\\n               P.walk(loc, x, val, path, function(m,l,x,v,p) { P.trace(m+\\";\\"+x,v,p); });\\n            else if (loc === \\"..\\") {\\n               P.trace(x, val, path);\\n               P.walk(loc, x, val, path, function(m,l,x,v,p) { typeof v[m] === \\"object\\" && P.trace(\\"..;\\"+x,v[m],p+\\";\\"+m); });\\n            }\\n            else if (/,/.test(loc)) { // [name1,name2,...]\\n               for (var s=loc.split(/'?,'?/),i=0,n=s.length; i<n; i++)\\n                  P.trace(s[i]+\\";\\"+x, val, path);\\n            }\\n            else if (/^\\\\(.*?\\\\)$/.test(loc)) // [(expr)]\\n               P.trace(P.eval(loc, val, path.substr(path.lastIndexOf(\\";\\")+1))+\\";\\"+x, val, path);\\n            else if (/^\\\\?\\\\(.*?\\\\)$/.test(loc)) // [?(expr)]\\n               P.walk(loc, x, val, path, function(m,l,x,v,p) { if (P.eval(l.replace(/^\\\\?\\\\((.*?)\\\\)$/,\\"$1\\"),v[m],m)) P.trace(m+\\";\\"+x,v,p); });\\n            else if (/^(-?[0-9]*):(-?[0-9]*):?([0-9]*)$/.test(loc)) // [start:end:step]  phyton slice syntax\\n               P.slice(loc, x, val, path);\\n         }\\n         else\\n            P.store(path, val);\\n      },\\n      walk: function(loc, expr, val, path, f) {\\n         if (val instanceof Array) {\\n            for (var i=0,n=val.length; i<n; i++)\\n               if (i in val)\\n                  f(i,loc,expr,val,path);\\n         }\\n         else if (typeof val === \\"object\\") {\\n            for (var m in val)\\n               if (val.hasOwnProperty(m))\\n                  f(m,loc,expr,val,path);\\n         }\\n      },\\n      slice: function(loc, expr, val, path) {\\n         if (val instanceof Array) {\\n            var len=val.length, start=0, end=len, step=1;\\n            loc.replace(/^(-?[0-9]*):(-?[0-9]*):?(-?[0-9]*)$/g, function($0,$1,$2,$3){start=parseInt($1||start);end=parseInt($2||end);step=parseInt($3||step);});\\n            start = (start < 0) ? Math.max(0,start+len) : Math.min(len,start);\\n            end   = (end < 0)   ? Math.max(0,end+len)   : Math.min(len,end);\\n            for (var i=start; i<end; i+=step)\\n               P.trace(i+\\";\\"+expr, val, path);\\n         }\\n      },\\n      eval: function(x, _v, _vname) {\\n         try { return $ && _v && eval(x.replace(/@/g, \\"_v\\")); }\\n         catch(e) { throw new SyntaxError(\\"jsonPath: \\" + e.message + \\": \\" + x.replace(/@/g, \\"_v\\").replace(/\\\\^/g, \\"_a\\")); }\\n      }\\n   };\\n\\n   var $ = obj;\\n   if (expr && obj && (P.resultType == \\"VALUE\\" || P.resultType == \\"PATH\\")) {\\n      P.trace(P.normalize(expr).replace(/^\\\\$;/,\\"\\"), obj, \\"$\\");\\n      return P.result.length ? P.result : false;\\n   }\\n} \\n\\n\\n//find all nodes that have\\nvar results = jsonPath(data.data, \\"*...ai_languageModel..\\")\\n\\nfor (var res of results) {\\n  if (typeof res === 'object' && res.tokenUsageEstimate) {\\n\\t\\tconsole.log(\\"Processing:\\"+JSON.stringify(res))\\n        processExecution(res.tokenUsageEstimate)\\n\\t}\\n}\\n\\n// Procesar cada nodo indicado\\n\\nconst executions = data.data?.resultData?.runData;\\n\\n//if (Array.isArray(executions)) {\\n//\\texecutions.forEach((exec) => processExecution(exec));\\n//} else if (typeof executions === 'object') {\\n//\\tprocessExecution(executions);\\n//}\\n\\nreturn [\\n\\t{\\n\\t  totals,\\n\\t  model: models\\n\\t},\\n];\\n"}},{"typeVersion":1.3,"name":"Configuration","position":[-96,384],"id":"9