ality\\"\\n}`\\n\\nconst question = $('prepare input data').first().json.chatInput;\\n\\n\\nsystemMessageTemplate = systemMessageTemplate.replace('{{ Question }}', question);\\n\\nconst structuredOutputParserJsonSchema = {\\n  \\"$schema\\": \\"http://json-schema.org/draft-07/schema#\\",\\n  \\"type\\": \\"object\\",\\n  \\"properties\\": {\\n    \\"chatInput\\": {\\n      \\"type\\": \\"string\\"\\n    },\\n    \\"language\\": {\\n      \\"type\\": \\"string\\"\\n    },\\n    \\"impersonationRole\\": {\\n      \\"type\\": \\"string\\"\\n    },\\n    \\"userPersona\\": {\\n      \\"type\\": \\"string\\"\\n    },\\n    \\"targetAction\\": {\\n      \\"type\\": \\"string\\"\\n    },\\n    \\"topics\\": {\\n      \\"type\\": \\"string\\"\\n    }\\n  },\\n  \\"required\\": [\\n    \\"chatInput\\",\\n    \\"language\\"\\n  ],\\n  \\"additionalProperties\\": false\\n}\\n\\nreturn { \\"systemMessageTemplate\\" : systemMessageTemplate,\\n         \\"structuredOutputParserJsonSchema\\" : structuredOutputParserJsonSchema\\n       }\\n"}}]	{"prepare input data":{"main":[[{"node":"Call 'Configuration (sub-workflow)'","index":0,"type":"main"}]]},"Prepare output data":{"main":[[{"node":"Insert success data for parallel sync","index":0,"type":"main"}]]},"Call 'Configuration (sub-workflow)'":{"main":[[{"node":"Prepare data for LLM call","index":0,"type":"main"}]]},"Prepare error data":{"main":[[{"node":"Insert error data for parallel sync","index":0,"type":"main"}]]},"LLM call":{"main":[[{"node":"Prepare output data","index":0,"type":"main"}],[{"node":"Prepare error data","index":0,"type":"main"}]]},"Webhook":{"main":[[{"node":"prepare input data","index":0,"type":"main"}]]},"Prepare data for LLM call":{"main":[[{"node":"LLM call","index":0,"type":"main"}]]}}	initial_publish	f	Initially publishing the workflow via the conversation API	[]
d778f2d0-425b-4dad-961c-37af2722f027	YL7C5ZQ2kJL7Qvge	import	2026-03-27 08:43:56.482+00	2026-03-27 08:44:00.04+00	[{"typeVersion":1,"name":"Sticky Note1","position":[-1024,-304],"id":"3ade6fc3-3956-4ae6-91c5-9044335b4b08","type":"n8n-nodes-base.stickyNote","parameters":{"width":544,"content":"# PoolParty Concept Expansion\\n## Overview\\nThis sub-workflow performs concept expansion using PoolParty. It takes user chat input (triggered by another workflow), extracts relevant concepts, and then expands these concepts hierarchically to provide a comprehensive semantic context for downstream processing, such as, semantic search, or LLM context enhancement.\\n\\n","height":240}},{"typeVersion":1,"name":"Sticky Note2","position":[224,-832],"id":"2d4514fb-ec6d-4a9d-8604-3543ef592c56","type":"n8n-nodes-base.stickyNote","parameters":{"color":4,"width":320,"content":"## Input Parameters\\nThe workflow accepts the following inputs when invoked:\\n\\n**`chatInput`**\\n- **Type:** String\\n- **Required:** Yes\\n- **Description:** The user's natural language query or message\\n\\n**`language`**\\n- **Type:** String\\n- **Required:** Optional\\n- **Description:** Language code (defaults to 'en')\\n\\n**`targetAction`**\\n- **Type:** String\\n- **Required:** Optional\\n- **Description:** Reserved for future use\\n\\n**`topics`**\\n- **Type:** Any\\n- **Required:** Optional\\n- **Description:** Reserved for future use\\n","height":720}},{"typeVersion":1,"name":"Sticky Note3","position":[1712,-624],"id":"833aff11-4086-4194-8cfb-2018ebb97315","type":"n8n-nodes-base.stickyNote","parameters":{"color":6,"width":320,"content":"## Output Structure\\n\\nThe workflow returns a structured JSON object containing:\\n\\n- **Seed Concepts**: concepts extracted from the initial input\\n- **Expanded Concepts**: Hierarchically organized expanded seed concepts\\n- **Retrieval URIs**: Concept URIs grouped by relevance (exact, primary, secondary, tertiary)\\n- **LLM-Friendly Format**: Structured data optimized for language model context\\n\\n","height":576}},{"typeVersion":1,"name":"Sticky Note4","position":[208,-80],"id":"bf0ec3b3-aa90-4ddd-b3c6-34551a12b7ad","type":"n8n-nodes-base.stickyNote","parameters":{"color":5,"width":368,"content":"#### Configuration required","height":240}},{"typeVersion":1,"name":"Sticky Note5","position":[1296,-288],"id":"ff8a4f83-5b85-4220-8a32-0b4176d21ffb","type":"n8n-nodes-base.stickyNote","parameters":{"color":5,"width":384,"content":"#### Configuration required","height":240}},{"typeVersion":2.1,"webhookId":"88bd9258-8e2b-42d6-8284-9bb154bd0d5f","name":"Webhook","position":[-560,0],"id":"fd2df738-676c-4c53-b4fa-1b3b44b281d3","type":"n8n-nodes-base.webhook","parameters":{"path":"internal/concept-expansion","options":{},"httpMethod":"POST"}},{"typeVersion":2,"name":"prepare input data","position":[-336,0],"id":"16f58ac2-fb67-4fed-b09e-66501727e86d","type":"n8n-nodes-base.code","parameters":{"jsCode":"return {\\n  \\"targetAction\\":  null,\\n  \\"topics\\": null,\\n  \\"chatInput\\":  $input.first().json.body.chatInput,\\n  \\"language\\": $input.first().json.body.language,\\n  \\"executionId\\" : $input.first().json.body.executionId,\\n  \\"stepTag\\": \\"concept-expansion\\"\\n}"}},{"typeVersion":1,"name":"Sticky Note","position":[-400,-208],"id":"dd744463-ed0c-4c46-bc88-0a89ca320cb7","type":"n8n-nodes-base.stickyNote","parameters":{"color":6,"width":224,"content":"## Please keep the name of the node intact - required for error async processing","height":336}},{"typeVersion":1,"name":"Insert success data for parallel sync","position":[2352,0],"id":"1d96a15c-72a0-46ea-bf85-f4bc5081a31d","type":"n8n-nodes-base.dataTable","parameters":{"columns":{"schema":[{"defaultMatch":false,"removed":false,"displayName":"executionId","display":true,"readOnly":false,"id":"executionId","type":"string","required":false},{"defaultMatch":false,"removed":false,"displayName":"step","display":true,"readOnly":false,"id":"step","type":"string","required":