utionId":"={{ $('prepare input data').first().json.executionId }}","isProcessed":false,"step":"={{ $('prepare input data').first().json.stepTag}}","type":"error","value":"={{ JSON.stringify($json) }}"}},"dataTableId":{"mode":"list","cachedResultUrl":"/projects/xFJBxfuIaoygFpGG/datatables/MKjbck0nu6xOvBsi","__rl":true,"cachedResultName":"PARALLEL_SYNC_DATA","value":"VQol99zJXwRSl6hz"},"options":{}}},{"typeVersion":1.3,"name":"Call 'Configuration (sub-workflow)'","position":[-48,0],"id":"3b6d793d-1d9b-4215-8fca-3028362f28a7","type":"n8n-nodes-base.executeWorkflow","parameters":{"workflowInputs":{"mappingMode":"defineBelow","value":{}},"options":{},"workflowId":{"mode":"list","cachedResultUrl":"/workflow/HJcJwMTssnY79HWw","__rl":true,"cachedResultName":"Configuration (sub-workflow)","value":"HJcJwMTssnY79HWw"}}},{"typeVersion":2,"name":"Build extraction request","position":[224,0],"id":"d1b9e714-99e1-4807-a452-bcc0f2866767","type":"n8n-nodes-base.code","parameters":{"jsCode":"// Build PoolParty API request with optimal parameters\\nconst items =[];\\nitems.push($('Webhook').first().json.body);\\n\\nconst output = [];\\n\\nconst PROJECT_ID = $('Call \\\\'Configuration (sub-workflow)\\\\'').first().json.poolPartyProjectId; \\n\\nfor (const item of items) {\\n \\n  const text = item.chatInput;\\n  const language = item.language || 'en';\\n  \\n  // parameters based on API research\\n  const formData = {\\n    projectId: PROJECT_ID,\\n    text: text,\\n    language: language,\\n    numberOfConcepts: '5',  // Increased for better coverage\\n    \\n    //  Get full hierarchies in ONE call\\n    useTransitiveBroaderConcepts: 'true',\\n    useTransitiveBroaderTopConcepts: 'true',\\n    \\n    // Quality improvements\\n    useRelatedConcepts: 'true',\\n    filterNestedConcepts: 'true',\\n    showMatchingDetails: 'true',\\n    \\n    // Advanced scoring\\n    corpusScoring: 'true',  // Better relevance for RAG queries\\n    disambiguate: 'true',   // Resolve ambiguous terms\\n    \\n    displayText: 'false'\\n  };\\n  \\n  output.push({\\n    json: {\\n      ...item.json,\\n      formData: formData\\n    }\\n  });\\n}\\n\\nreturn output;"}},{"typeVersion":4.2,"onError":"continueErrorOutput","credentials":{"httpBasicAuth":{"id":"emxYnbbzTTT6DtWc","name":"PoolParty Credentials"}},"name":"Extract concepts from user query","position":[448,0],"id":"130e93a0-b758-46c1-b6a8-708549cb6e33","type":"n8n-nodes-base.httpRequest","parameters":{"bodyParameters":{"parameters":[{"name":"projectId","value":"={{ $json.formData.projectId }}"},{"name":"text","value":"={{ $json.formData.text }}"},{"name":"language","value":"={{ $json.formData.language }}"},{"name":"numberOfConcepts","value":"={{ $json.formData.numberOfConcepts }}"},{"name":"showMatchingDetails","value":"={{ $json.formData.showMatchingDetails }}"},{"name":"filterNestedConcepts","value":"={{ $json.formData.filterNestedConcepts }}"},{"name":"useRelatedConcepts","value":"={{ $json.formData.useRelatedConcepts }}"},{"name":"disambiguate","value":"={{ $json.formData.disambiguate }}"},{"name":"displayText","value":"={{ $json.formData.displayText }}"},{"name":"useTransitiveBroaderConcepts","value":"={{ $json.formData.useTransitiveBroaderConcepts }}"},{"name":"useTransitiveBroaderTopConcepts","value":"={{ $json.formData.useTransitiveBroaderTopConcepts }}"}]},"method":"POST","sendBody":true,"options":{"response":{"response":{}}},"genericAuthType":"httpBasicAuth","contentType":"form-urlencoded","url":"={{ $('Call \\\\'Configuration (sub-workflow)\\\\'').first().json.poolPartyServerUrl }}/extractor/api/extract","authentication":"genericCredentialType"}},{"typeVersion":2,"name":"Extract seeds to expand","position":[688,0],"id":"1f989ec6-69f9-437c-b68c-3afcb5dd6230","type":"n8n-nodes-base.code","parameters":{"jsCode":"// Extract seed concept URIs from extraction response\\n// Here we take ALL extracted concepts as seed concepts for further expansion\\n// All concepts are given a score of 100 for expansion purposes\\nconst items = $input.all();\\nconst output = [];\\n\\nfor (const item of items) {\\n  try {\\n    const extractionResponse = item.json;\\n    \\n    // Collect seed concept URIs (all concepts with score 100)\\n    const seedConcepts = new Map();\\n    const seedMetadata = new Map();\\n    \\n    if (extractionResponse.concepts && Array.isArray(extractionResponse.concepts)) {\\n      extractionResponse.concepts.forEach(concept => {\\n        // Take ALL extracted concepts and assign score 100 for expansion\\n        if (concept.uri) {\\n          seedConcepts.set(concept.uri, {score: 100});  // Force score to 100\\n          \\n          seedMetadata.set(concept.uri, {\\n            uri: concept.uri,\\n            label: concept.prefLabels?.en || Object.values(concept.prefLabels || {})[0],\\n            altLabels: concept.altLabels?.en || [],\\n            score: 100,  // Force score to 100\\n            originalScore: concept.score,  // Keep original score for reference\\n            matchedAs: concept.matchingLabels?.map(m => m.label) || []\\n          });\\n        }\\n      });\\n    }\\n    \\n    console.log('✓ Extracted seed concepts:', {\\n      totalExtracted: extractionResponse.concepts?.length || 0,\\n      seedsForExpansion: seedConcepts.size\\n    });\\n    \\n    // Validation - need at least one concept to expand\\n    if (seedConcepts.size === 0) {\\n      console.warn('⚠️  No concepts found for expansion');\\n      throw new Error('No concepts extracted from text. Cannot perform expansion.');\\n    }\\n    \\n    output.push({\\n      json: {\\n        // Original config (from extractionConfig parent)\\n        text: extractionResponse.text || extractionResponse.extractionConfig?.formData?.text,\\n        language: extractionResponse.language || extractionResponse.extractionConfig?.formData?.language,\\n        projectId: extractionResponse.projectId || extractionResponse.extractionConfig?.formData?.projectId,\\n        expansionStrategy: extractionResponse.expansionStrategy,\\n        maxDepth: extractionResponse.maxDepth,\\n        maxResults: extractionResponse.maxResults,\\n        \\n        // Extracted seeds (all with score 100)\\n        seedConcepts: Object.fromEntries(seedConcepts),\\n        seedMetadata: Object.fromEntries(seedMetadata),\\n        \\n        // Full extraction response for reference\\n        originalExtraction: extractionResponse,\\n        \\n        timestamp: new Date().toISOString()\\n      }\\n    });\\n    \\n  } catch (error) {\\n    console.error('❌ Seed extraction error:', error.message);\\n    output.push({\\n      json: {\\n        error: true,\\n        errorMessage: error.message,\\n        timestamp: new Date().toISOString()\\n      }\\n    });\\n  }\\n}\\n\\nreturn output;"},"alwaysOutputData":true},{"typeVersion":2.2,"name":"If concepts are found","position":[912,0],"id":"49806c69-6cbf-4513-a6de-68bc0497362c","type":"n8n-nodes-base.if","parameters":{"options":{},"conditions":{"combinator":"and","options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":2},"conditions":[{"leftValue":"={{ $input.first().json.error }}","rightValue":"","id":"d2ee2317-b1d4-424f-9cdc-b00abe860383","operator":{"singleValue":true,"type":"boolean","operation":"notExists"}}]}}},{"typeVersion":2,"name":"Prepare JSON list","position":[1104,-208],"id":"a2837cd8-0fe8-41ee-ae87-7748f27cb25e","type":"n8n-nodes-base.code","parameters":{"jsCode":"var res = []\\nfor(const concept in $('Extract seeds to expand').first().json.seedConcepts){ \\n  res.push({\\n    \\"uri\\": concept,\\n    \\"score\\":$('Extract seeds to expand').first().json.seedConcepts[concept].score\\n  })\\n}\\n\\nreturn res;"},"alwaysOutputData":true},{"typeVersion":2,"name":"Build expansion request","position":[1328,-208],"id":"348d2d0d-08fe-4d8d-8029-2696a1bc826a","type":"n8n-nodes-base.code","parameters":{"jsCode":"var conceptList =  $input.all();\\nvar finalList = [];\\n\\nfor(var concept in conceptList){\\n  finalList.push({\\n    \\"uri\\": conceptList[concept].json.uri,\\n    \\"score\\": conceptList[concept].json.score\\n  });\\n}\\n\\nreturn [{\\n  \\"concepts\\": finalList,\\n  \\"expansionQuery\\": \\"prefix skos:<http://www.w3.org/2004/02/skos/core#>\\\\nselect ?uri ?label ?finalScore\\\\nwhere {\\\\n  ?uri skos:prefLabel ?label . FILTER ( lang(?label) = 'en' ) {\\\\n    select ?uri (MAX(?expansionScore) as ?finalScore) where { VALUES (?x ?inScore)\\\\n      { <inputConcepts> }\\\\n      { BIND(?x AS ?uri) BIND(STRDT('1.00',xsd:float) AS ?distScore) }\\\\n      UNION { ?x skos:narrower ?y . BIND(STRDT('0.8',xsd:float) AS ?distScore) }\\\\n      UNION { ?x skos:narrower/skos:narrower ?y . BIND(STRDT('0.4',xsd:float) AS ?distScore) }\\\\n      UNION { ?x skos:broader/skos:narrower ?y . filter(!sameTerm(?x,?y)) BIND(STRDT('0.2',xsd:float) AS ?distScore) }\\\\n      BIND(IF(BOUND(?y), ?y, ?x) AS ?uri) .\\\\n      BIND(?distScore * ?inScore AS ?expansionScore) . \\\\n    }\\\\n    GROUP BY ?uri order by desc(?finalScore)\\\\n  }\\\\n}\\\\nlimit <numberOfConcepts>\\",\\n  \\"language\\": \\"en\\",\\n  \\"maxNumberOfConcepts\\": 50,\\n  \\"properties\\": [\\n    \\"skos:prefLabel\\",\\n    \\"skos:altLabel\\",\\n    \\"skos:definition\\",\\n    \\"skos:broader\\",\\n    \\"skos:narrower\\",\\n    \\"skos:related\\"\\n  ]\\n}]"},"alwaysOutputData":true},{"typeVersion":2,"name":"Prepare error data","position":[1344,144],"id":"e3259fe8-bd56-47da-9a1a-40a3091d4bc8","type":"n8n-nodes-base.code","parameters":{"jsCode":"return {\\n  \\"executionId\\": $executionId\\n}"}},{"typeVersion":4.2,"onError":"continueErrorOutput","credentials":{"httpBasicAuth":{"id":"emxYnbbzTTT6DtWc","name":"PoolParty Credentials"}},"name":"Expand concepts from user query","position":[1552,-208],"id":"434a921f-6063-433a-a2df-afd6a5b5b9b3","type":"n8n-nodes-base.httpRequest","parameters":{"method":"POST","specifyBody":"json","headerParameters":{"parameters":[{"name":"Accept","value":"application/json"}]},"sendBody":true,"options":{"response":{}},"jsonBody":"={{ JSON.stringify($json) }}","genericAuthType":"httpBasicAuth","sendHeaders":true,"url":"={{ $('Call \\\\'Configuration (sub-workflow)\\\\'').first().json.poolPartyServerUrl }}/PoolParty/api/tagging/{{ $('Call \\\\'Configuration (sub-workflow)\\\\'').first().json.poolPartyProjectId }}/expand","authentication":"genericCredentialType"}},{"typeVersion":2,"name":"Structure expansion results","position":[1776,-208],"id":"bbf69547-c8ef-4c24-8c87-592e414ad729","type":"n8n-nodes-base.code","parameters":{"jsCode":"// Parse and structure expansion results for LLM/retrieval\\nconst items = $input.all();\\n\\n// The response is an ARRAY with one object inside\\nconst responseArray = $input.first().json;\\nconst expansionData = Array.isArray(responseArray) ? responseArray[0] : responseArray;\\n\\nconsole.log('✓ Expansion message:', expansionData.message);\\n\\n// Safely extract expanded concepts\\nconst expandedConcepts = expansionData?.expandedConcepts || [];\\nconsole.log('✓ Total concepts expanded:', expandedConcepts.length);\\n\\n// Validate we have data\\nif (!expandedConcepts || expandedConcepts.length === 0) {\\n  console.warn('⚠️ No expanded concepts found in response');\\n  return {\\n    json: {\\n      error: false,\\n      warning: 'No concepts expanded',\\n      message: expansionData?.message || 'No message',\\n      query: $('prepare input data').first().json.chatInput\\n    }\\n  };\\n}\\n\\n// Get seed concepts from previous node\\nconst seedData = $('Expand concepts from user query').first().json;\\nconst query = $('prepare input data').first().json.chatInput;\\n\\n// Categorize concepts by score\\nconst byScore = {\\n  seeds: expandedConcepts.filter(c => c.score === 100),        // Original extracted concepts\\n  primary: expandedConcepts.filter(c => c.score === 80),       // 1-level narrower\\n  secondary: expandedConcepts.filter(c => c.score === 40),     // 2-level narrower\\n  related: expandedConcepts.filter(c => c.score === 20)        // Siblings/related\\n};\\n\\nconsole.log('📊 Concept distribution:', {\\n  seeds: byScore.seeds.length,\\n  primary: byScore.primary.length,\\n  secondary: byScore.secondary.length,\\n  related: byScore.related.length\\n});\\n\\n// ========================================\\n// 1. RETRIEVAL-OPTIMIZED STRUCTURE\\n// ========================================\\nconst retrievalIndex = {\\n  // Tiered URIs for weighted retrieval\\n  tiers: {\\n    tier1_seeds: byScore.seeds.map(c => ({\\n      uri: c.jsonConcept?.uri,\\n      label: c.jsonConcept?.prefLabel,\\n      weight: 1.0,\\n      altLabels: c.jsonConcept?.altLabels || []\\n    })),\\n    \\n    tier2_primary: byScore.primary.map(c => ({\\n      uri: c.jsonConcept?.uri,\\n      label: c.jsonConcept?.prefLabel,\\n      weight: 0.8,\\n      altLabels: c.jsonConcept?.altLabels || []\\n    })),\\n    \\n    tier3_secondary: byScore.secondary.map(c => ({\\n      uri: c.jsonConcept?.uri,\\n      label: c.jsonConcept?.prefLabel,\\n      weight: 0.5,\\n      altLabels: c.jsonConcept?.altLabels || []\\n    })),\\n    \\n    tier4_related: byScore.related.map(c => ({\\n      uri: c.jsonConcept?.uri,\\n      label: c.jsonConcept?.prefLabel,\\n      weight: 0.3,\\n      altLabels: c.jsonConcept?.altLabels || []\\n    }))\\n  },\\n  \\n  // Flat lists for easy filtering\\n  allURIs: expandedConcepts.map(c => c.jsonConcept?.uri).filter(uri => uri),\\n  seedURIs: byScore.seeds.map(c => c.jsonConcept?.uri).filter(uri => uri),\\n  expandedURIs: [...byScore.primary, ...byScore.secondary, ...byScore.related]\\n    .map(c => c.jsonConcept?.uri)\\n    .filter(uri => uri),\\n  \\n  // Query expansion terms (for full-text search)\\n  queryExpansionTerms: {\\n    primary: [\\n      ...new Set([\\n        ...byScore.seeds.flatMap(c => [c.jsonConcept?.prefLabel, ...(c.jsonConcept?.altLabels || [])]),\\n        ...byScore.primary.flatMap(c => [c.jsonConcept?.prefLabel, ...(c.jsonConcept?.altLabels || [])])\\n      ].filter(Boolean))\\n    ].slice(0, 30),\\n    \\n    secondary: [\\n      ...new Set([\\n        ...byScore.secondary.flatMap(c => [c.jsonConcept?.prefLabel, ...(c.jsonConcept?.altLabels || [])])\\n      ].filter(Boolean))\\n    ].slice(0, 20)\\n  },\\n  \\n  // Relationship graph for traversal\\n  relationships: expandedConcepts.map(c => ({\\n    uri: c.jsonConcept?.uri,\\n    broaders: c.jsonConcept?.broaders || [],\\n    narrowers: c.jsonConcept?.narrowers || [],\\n    related: c.jsonConcept?.relateds || []\\n  }))\\n};\\n\\n// ========================================\\n// 2. LLM CONTEXT STRUCTURE\\n// ========================================\\nconst llmContext = {\\n  // Pre-formatted context string ready for injection\\n  contextString: generateContextString(byScore, query),\\n  \\n  // Structured data for custom formatting\\n  structured: {\\n    query: query,\\n    \\n    // Main concepts from user query\\n    identifiedConcepts: byScore.seeds.map(c => ({\\n      name: c.jsonConcept?.prefLabel,\\n      definition: c.jsonConcept?.definitions?.[0] || 'No definition available',\\n      synonyms: c.jsonConcept?.altLabels || [],\\n      uri: c.jsonConcept?.uri\\n    })),\\n    \\n    // Hierarchical context (narrower/more specific topics)\\n    subtopics: {\\n      immediate: byScore.primary.slice(0, 15).map(c => ({\\n        name: c.jsonConcept?.prefLabel,\\n        synonyms: (c.jsonConcept?.altLabels || []).slice(0, 3),\\n        definition: c.jsonConcept?.definitions?.[0]\\n      })),\\n      \\n      detailed: byScore.secondary.slice(0, 20).map(c => ({\\n        name: c.jsonConcept?.prefLabel,\\n        synonyms: (c.jsonConcept?.altLabels || []).slice(0, 2)\\n      }))\\n    },\\n    \\n    // Related/sibling topics for context\\n    relatedTopics: byScore.related.slice(0, 10).map(c => ({\\n      name: c.jsonConcept?.prefLabel,\\n      synonyms: (c.jsonConcept?.altLabels || []).slice(0, 2)\\n    })),\\n    \\n    // Semantic boundaries (what's broader/out of scope)\\n    broaderContext: extractBroaderContext(byScore.seeds),\\n    \\n    // Stats for understanding scope\\n    scopeMetrics: {\\n      numberOfMainConcepts: byScore.seeds.length,\\n      numberOfSubtopics: byScore.primary.length + byScore.secondary.length,\\n      hierarchyDepth: byScore.secondary.length > 0 ? 2 : byScore.primary.length > 0 ? 1 : 0,\\n      hasRelatedTopics: byScore.related.length > 0\\n    }\\n  }\\n};\\n\\n// ========================================\\n// HELPER FUNCTIONS\\n// ========================================\\n\\nfunction generateContextString(byScore, query) {\\n  let context = `Query: \\"${query}\\"\\\\n\\\\n`;\\n  \\n  // Main concepts\\n  if (byScore.seeds.length > 0) {\\n    context += `Main Concepts:\\\\n`;\\n    byScore.seeds.forEach(c => {\\n      const concept = c.jsonConcept;\\n      context += `- ${concept?.prefLabel}`;\\n      if (concept?.definitions?.[0]) {\\n        context += `: ${concept.definitions[0]}`;\\n      }\\n      if (concept?.altLabels?.length > 0) {\\n        context += ` (Also known as: ${concept.altLabels.slice(0, 3).join(', ')})`;\\n      }\\n      context += `\\\\n`;\\n    });\\n    context += `\\\\n`;\\n  }\\n  \\n  // Key subtopics\\n  if (byScore.primary.length > 0) {\\n    context += `Key Subtopics:\\\\n`;\\n    byScore.primary.slice(0, 10).forEach(c => {\\n      context += `- ${c.jsonConcept?.prefLabel}`;\\n      const alts = c.jsonConcept?.altLabels?.slice(0, 2);\\n      if (alts?.length > 0) {\\n        context += ` (${alts.join(', ')})`;\\n      }\\n      context += `\\\\n`;\\n    });\\n    context += `\\\\n`;\\n  }\\n  \\n  // Detailed topics (if not too many)\\n  if (byScore.secondary.length > 0 && byScore.secondary.length <= 15) {\\n    context += `Detailed Topics:\\\\n`;\\n    byScore.secondary.slice(0, 15).forEach(c => {\\n      context += `- ${c.jsonConcept?.prefLabel}\\\\n`;\\n    });\\n    context += `\\\\n`;\\n  }\\n  \\n  // Related topics\\n  if (byScore.related.length > 0) {\\n    context += `Related Topics: ${byScore.related.slice(0, 8).map(c => c.jsonConcept?.prefLabel).join(', ')}\\\\n`;\\n  }\\n  \\n  return context;\\n}\\n\\nfunction extractBroaderContext(seeds) {\\n  const broaders = new Set();\\n  seeds.forEach(seed => {\\n    const concept = seed.jsonConcept;\\n    if (concept?.broaders) {\\n      concept.broaders.forEach(b => broaders.add(b));\\n    }\\n  });\\n  return Array.from(broaders);\\n}\\n\\n// ========================================\\n// FINAL OUTPUT\\n// ========================================\\n\\nconst output = {\\n  // Metadata\\n  metadata: {\\n    query: query,\\n    language: $('prepare input data').first().json.language || 'en',\\n    timestamp: new Date().toISOString(),\\n    totalConcepts: expandedConcepts.length,\\n    expansionMessage: expansionData.message\\n  },\\n  \\n  // For retrieval systems\\n  retrieval: retrievalIndex,\\n  \\n  // For LLM injection\\n  llm: llmContext,\\n  \\n  // Raw data (if needed for debugging)\\n  raw: {\\n    seedMetadata: seedData?.seedMetadata || {},\\n    allExpandedConcepts: expandedConcepts.map(c => ({\\n      score: c.score,\\n      uri: c.jsonConcept?.uri,\\n      prefLabel: c.jsonConcept?.prefLabel,\\n      altLabels: c.jsonConcept?.altLabels || [],\\n      definitions: c.jsonConcept?.definitions || []\\n    }))\\n  }\\n};\\n\\nconsole.log('✓ Structured output created successfully');\\nconsole.log('📋 Summary:', {\\n  seedConcepts: byScore.seeds.length,\\n  totalURIs: retrievalIndex.allURIs.length,\\n  queryExpansionTerms: retrievalIndex.queryExpansionTerms.primary.length,\\n  contextStringLength: llmContext.contextString.length\\n});\\n\\nreturn [{ json: output }];"},"alwaysOutputData":true},{"typeVersion":2,"name":"Prepare output data","position":[2096,-208],"id":"25dd692c-02e0-460b-87f0-26bb5ea9bf2a","type":"n8n-nodes-base.code","parameters":{"jsCode":"return {\\n  \\"conceptExpansion\\": $('Structure expansion results').first().json,\\n  \\"exec