faultMatch":false,"canBeUsedToMatch":true,"removed":false,"displayName":"phase","display":true,"id":"phase","type":"string","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"removed":false,"displayName":"step","display":true,"id":"step","type":"string","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"removed":false,"displayName":"type","display":true,"id":"type","type":"string","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"removed":false,"displayName":"value","display":true,"id":"value","type":"object","required":false}],"attemptToConvertTypes":false,"matchingColumns":[],"convertFieldsToString":true,"mappingMode":"defineBelow","value":{"conversationId":"={{ $json.conversationId }}","questionId":"={{ $json.questionId }}","phase":"main","step":"turn-start","type":"success","value":"={{ { question: $json.question } }}"}},"options":{}},"typeVersion":1.3,"name":"Journey: Turn Start","position":[-7472,512],"id":"162a2a6b-eadf-4bd4-a103-626f146bc34e","type":"n8n-nodes-base.executeWorkflow","onError":"continueRegularOutput"},{"parameters":{"jsCode":"const fs   = require('fs');\\nconst path = require('path');\\n\\n// This node runs strictly after Journey: Final Answer -- the true last\\n// journey write in Main's own straight-line success path -- and takes its\\n// directory straight from that node's own output. No cross-branch node\\n// references, no dependence on n8n's execution order for sibling branches\\n// inside other sub-workflows: just \\"read whatever *.json files exist in\\n// this one directory, in timestamp order, and render them.\\"\\nconst input = $input.first().json;\\n\\nlet dir = null;\\ntry {\\n  dir = path.dirname(input.file);\\n} catch (e) {}\\n\\nlet written = false;\\nlet error = null;\\nlet reportPath = null;\\nlet stepsFound = 0;\\n\\ntry {\\n  if (!dir) throw new Error('no directory available from Journey: Final Answer output');\\n\\n  const files = fs.readdirSync(dir).filter(f => f.endsWith('.json'));\\n  const records = [];\\n  for (const f of files) {\\n    try {\\n      const raw = fs.readFileSync(path.join(dir, f), 'utf-8');\\n      const parsed = JSON.parse(raw);\\n      records.push({\\n        file: f,\\n        ts: parsed.ts || null,\\n        phase: parsed.phase || '?',\\n        step: parsed.step || f,\\n        type: parsed.type || 'unknown',\\n        value: parsed.value,\\n      });\\n    } catch (e) {\\n      records.push({ file: f, ts: null, phase: '?', step: f, type: 'unreadable', value: { parseError: e.message } });\\n    }\\n  }\\n\\n  records.sort((a, b) => {\\n    if (a.ts && b.ts) return new Date(a.ts) - new Date(b.ts);\\n    if (a.ts) return -1;\\n    if (b.ts) return 1;\\n    return a.file.localeCompare(b.file);\\n  });\\n\\n  stepsFound = records.length;\\n\\n  const lines = [];\\n  lines.push('=== GraphRAG Chatbot Turn Audit Report ===');\\n  lines.push(`Directory: ${dir}`);\\n  lines.push(`Generated: ${new Date().toISOString()}`);\\n  lines.push(`Steps captured: ${records.length}`);\\n  lines.push('');\\n\\n  for (const r of records) {\\n    lines.push(`[${r.phase}-${r.step}]  ts=${r.ts || 'unknown'}  type=${r.type}  (source: ${r.file})`);\\n    try {\\n      lines.push(JSON.stringify(r.value, null, 2));\\n    } catch (e) {\\n      lines.push(`  [could not serialize value: ${e.message}]`);\\n    }\\n    lines.push('');\\n  }\\n\\n  reportPath = path.join(dir, 'report.txt');\\n  fs.writeFileSync(reportPath, lines.join('\\\\n'), 'utf-8');\\n  written = true;\\n} catch (e) {\\n  error = e.message;\\n  try {\\n    if (dir) {\\n      fs.mkdirSync(dir, { recursive: true });\\n      reportPath = path.join(dir, 'report.txt');\\n      fs.writeFileSync(reportPath, `[REPORT GENERATION FAILED: ${e.message}]\\\\n`, 'utf-8');\\n      written = true;\\n    }\\n  } catch (e2) {\\n    error = `${e.message} (fallback write also failed: ${e2.message})`;\\n  }\\n}\\n\\nreturn [{ json: { written, error, file: reportPath, stepsFound } }];\\n"},"typeVersion":2,"name":"Journey: Assemble Final Report","position":[1232,240],"id":"1ca19839-0210-4c24-aa3e-7b9ec4968608","type":"n8n-nodes-base.code","onError":"continueRegularOutput"}]	{"LLM usage - Short Memory":{"main":[[{"node":"UpdateTokenUsage-ShortMemory","index":0,"type":"main"}]]},"Send Input Guardrails message Error":{"main":[[{"node":"Build End message 1","index":0,"type":"main"}]]},"Call 'Short-term memory sync (sub-workflow)'":{"main":[[{"node":"If LLM was used","index":0,"type":"main"}],[{"node":"Build Ex message -  Short Memory error 2","index":0,"type":"main"}]]},"Call 'Parallel - Main'":{"main":[[{"node":"Prepare collected data","index":0,"type":"main"}]]},"Configuration":{"main":[[{"node":"Get Input data","index":0,"type":"main"}]]},"Short memory data":{"main":[[{"node":"Merge short memory","index":0,"type":"main"}]]},"UpdateTokenUsage-GDB":{"main":[[{"node":"Call 'Final Answer (sub-workflow)'","index":0,"type":"main"}]]},"If Input GuardRails OK":{"main":[[{"node":"UpdateTokenUsage-InputGuardrails","index":0,"type":"main"}],[{"node":"Send Input Guardrails message Error","index":0,"type":"main"}]]},"UpdateTokenUsage-MainAnswer":{"main":[[{"node":"Parallel Post Final Answer","index":0,"type":"main"}]]},"Build Ex message - answer error":{"main":[[{"node":"Send Ex message - answer error","index":0,"type":"main"}]]},"Send Ex message - Short Memory success 1":{"main":[[{"node":"Short memory data","index":0,"type":"main"}]]},"Get Input data":{"main":[[{"node":"Build Introspection message - Main Workflow Execution ID","index":0,"type":"main"},{"node":"Journey: Turn Start","index":0,"type":"main"}]]},"Build Ex message -  Short Memory error 2":{"main":[[{"node":"Send Ex message - Short Memory error 2","index":0,"type":"main"}]]},"Build Introspection message - Main Workflow Execution ID":{"main":[[{"node":"Send Introspection message - Execution ID","index":0,"type":"main"}]]},"Build End message ":{"main":[[{"node":"Send End message ","index":0,"type":"main"}]]},"Send m