.split(\\".\\");\\n  for (const key of mappingArray) {\\n    if (itemJson.hasOwnProperty(key)) {\\n      itemJson = itemJson[key];\\n    }\\n    else {\\n      return null;\\n    }\\n  }\\n  return itemJson;\\n}\\n\\n/**\\n * Exclude (nullifies) certain properties from the passed-through metadata.\\n * @param itemJson The JSON of the results item containing metadata to exclude properties from\\n * @returns The metadata object with nullified properties\\n */\\nconst buildPassthroughMetadata = function(itemJson) {\\n  const passthroughMetadata = $('Call \\\\'Configuration (sub-workflow)\\\\'').first().json.vectorStoreMetadataPassthrough;\\n\\n  if (passthroughMetadata) {\\n    const metadataKey = presetMapping.source.split(\\".\\")[0];\\n    if (itemJson.hasOwnProperty(metadataKey)) {\\n      const metadata = itemJson[metadataKey];\\n      const excludeProperties = $('Call \\\\'Configuration (sub-workflow)\\\\'').first().json.vectorStoreMetadataExclude;\\n      for (const property of excludeProperties) {\\n        if (metadata.hasOwnProperty(property)) {\\n          metadata[property] = null;\\n        }\\n      }\\n      return metadata;\\n    }\\n  }\\n  \\n  return null;\\n}\\n\\n// Build an array of result documents, independent of the original mapping of the vector store.\\nfor (const item of $input.all()) {\\n  const itemJson = item.json;\\n  const source = getMappedValue(itemJson, presetMapping.source);\\n  const payload = getMappedValue(itemJson, presetMapping.payload);\\n  if (source === null || payload === null) {\\n    throw new Error(\\"Mandatory vector store results property is either not available or null\\");\\n  }\\n  \\n  const doc = {\\n    \\"id\\": getMappedValue(itemJson, presetMapping.id),\\n    \\"source\\": source,\\n    \\"score\\": getMappedValue(itemJson, presetMapping.score),\\n    \\"payload\\": payload,\\n    \\"metadata\\": buildPassthroughMetadata(itemJson)\\n  }\\n  //swconsole.log(doc)\\n  docs.push(doc);\\n}\\n\\nreturn {\\n  \\"vector_hits\\":  docs\\n};"},"typeVersion":2,"name":"Prepare response","position":[1136,0],"id":"4f8e1a73-161f-44a2-bf71-390c15f227e1","type":"n8n-nodes-base.code","alwaysOutputData":true,"onError":"continueErrorOutput"},{"parameters":{"jsCode":"return {\\n  \\"executionId\\": $executionId\\n}"},"typeVersion":2,"name":"Prepare error data","position":[1344,240],"id":"7b14dcf8-4b48-4f86-9010-55797a3d216d","type":"n8n-nodes-base.code"},{"parameters":{"jsCode":"return {\\n  \\"vectorSearch\\": $('Prepare response').first().json,\\n  \\"executionId\\": $executionId\\n};\\n\\n\\n\\n"},"typeVersion":2,"name":"Prepare output data","position":[1344,0],"id":"7f3d506f-220f-4eb5-a021-99707c1641cc","type":"n8n-nodes-base.code"},{"parameters":{"mode":"load","pineconeIndex":{"mode":"id","__rl":true,"value":"={{ $('Call \\\\'Configuration (sub-workflow)\\\\'').item.json.vectorIndex }}"},"prompt":"={{ $('prepare input data').item.json.question }}","options":{}},"typeVersion":1.3,"name":"Pinecone Vector Store","position":[608,80],"id":"19fab09d-dcb8-41de-875b-17c8ebf689dd","type":"@n8n/n8n-nodes-langchain.vectorStorePinecone","credentials":{"pineconeApi":{"id":"OaeefeP0G9ZN82Dh","name":"PineconeApi account"}}},{"parameters":{"mode":"load","qdrantCollection":{"mode":"id","__rl":true,"value":"={{ $('Call \\\\'Configuration (sub-workflow)\\\\'').item.json.vectorIndex }}"},"prompt":"={{ $('prepare input data').item.json.question }}","options":{}},"typeVersion":1.3,"name":"Qdrant Vector Store","position":[608,704],"id":"ba3e81b3-5bfe-4248-bbb2-3ca01eedd615","type":"@n8n/n8n-nodes-langchain.vectorStoreQdrant","credentials":{"qdrantApi":{"id":"80FrVNNpA2MAjSEx","name":"QdrantApi account"}}},{"parameters":{"mode":"load","weaviateCollection":{"mode":"id","__rl":true,"value":"={{ $('Call \\\\'Configuration (sub-workflow)\\\\'').item.json.vectorIndex }}"},"prompt":"={{ $('prepare input data').item.json.question }}","options":{}},"typeVersion":1.3,"name":"Weaviate Vector Store","position":[608,384],