ap[\\"FollowUps\\"] = $('LLMUsage-Followups').first().json.tokens.totalTokens;\\n}catch(e){}\\n\\n\\nreturn {\\n  \\"status\\":\\"error\\",\\n  \\"map\\": map\\n}"},"typeVersion":2,"name":"PrepareResponse - Error","position":[1008,960],"id":"fa5b2c52-7669-4d8c-8fbf-01cea2c42ed9","type":"n8n-nodes-base.code"},{"parameters":{"assignments":{"assignments":[{"name":"counter","id":"85e0688a-fbc0-4e25-a2ee-22bc601a4558","type":"number","value":0}]},"options":{}},"typeVersion":3.4,"name":"Final parallel counter","position":[-9840,1408],"id":"dffc3244-1ff9-4d2b-9419-38a0451fac2b","type":"n8n-nodes-base.set"},{"parameters":{"content":"# Main Idea\\n\\n## The main idea of this workflow is to start several steps in Async mode. The synchronization of the results is done by using a dataTable PARALLEL_SYNC_DATA.\\n\\n## To start each step we use the approach [WebHook + respond immediately]\\n\\n## To sync all steps we use a combination of [dataTable (for normal execution) + timeout period ]\\n\\n## In case of errors in some steps - they have a special \\"Error Workflow\\" that makes sure the sync data is written to thedataTable","height":464,"width":1104},"typeVersion":1,"name":"Sticky Note4","position":[-10768,784],"id":"f39e3054-310e-4f86-8993-da5b71a70068","type":"n8n-nodes-base.stickyNote"},{"parameters":{"workflowId":{"__rl":true,"value":"nWwY5o2Cz7m5SbfA","mode":"list","cachedResultUrl":"/graphrag/workflows/workflow/nWwY5o2Cz7m5SbfA","cachedResultName":"Utils - Write Journey Step Processing"},"workflowInputs":{"schema":[{"defaultMatch":false,"canBeUsedToMatch":true,"removed":false,"displayName":"conversationId","display":true,"id":"conversationId","type":"string","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"removed":false,"displayName":"questionId","display":true,"id":"questionId","type":"string","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"removed":false,"displayName":"phase","display":true,"id":"phase","type":"string","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"removed":false,"displayName":"step","display":true,"id":"step","type":"string","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"removed":false,"displayName":"type","display":true,"id":"type","type":"string","required":false},{"defaultMatch":false,"canBeUsedToMatch":true,"removed":false,"displayName":"value","display":true,"id":"value","type":"object","required":false}],"attemptToConvertTypes":false,"matchingColumns":[],"convertFieldsToString":true,"mappingMode":"defineBelow","value":{"conversationId":"={{ $('Prepare collected data').first().json.conversationId }}","questionId":"={{ $('Prepare collected data').first().json.questionId }}","phase":"answer","step":"={{ $json.step }}","type":"={{ $json.type }}","value":"={{ $json.value }}"}},"options":{}},"typeVersion":1.3,"name":"Journey: Answer Step","position":[-5168,1744],"id":"9d0143fe-294a-4c4d-9e18-26790c9bc4a3","type":"n8n-nodes-base.executeWorkflow","onError":"continueRegularOutput"},{"parameters":{"jsCode":"const fs   = require('fs');\\nconst path = require('path');\\n\\nconst collected = $('Prepare collected data').first().json;\\nconst conversationId = collected.conversationId;\\nconst questionId     = collected.questionId;\\n\\nconst BASE_DIR = '/data/staging/output/journey';\\nconst safe     = s => String(s || 'unknown').replace(/[^a-zA-Z0-9_-]/g, '_');\\nconst dir      = path.join(BASE_DIR, safe(conversationId), safe(questionId));\\n\\nconst RETRY_DELAY_MS = 300;\\nconst RETRY_MAX_MS   = 5000;\\n\\nfunction sleep(ms) {\\n  return new Promise(resolve => setTimeout(resolve, ms));\\n}\\n\\nasync function readMainFileWithRetry(step) {\\n  const filePath = path.join(dir, `main-${step}.json`);\\n  const deadline = Date.now() + RETRY_MAX_MS;\\n  while (true) {\\n    try {\\n      return JSON.parse(fs.readFileSync(filePath, 'utf-8'));\\n    } catch (e) {\\n      if (Date.now() >= deadline) return null;\\n      await sleep(RETRY_DELAY_MS);\\n    }\\n  }\\n}\\n\\nfunction fmtGuardrail(value) {\\n  if (!value) return '  [no data]';\\n  const status = value.is_safe ? 'PASS' : 'BLOCKED';\\n  const flags = (value.flags && value.flags.length) ? value.flags.join(', ') : 'none';\\n  return [\\n    `  Status: ${status}`,\\n    `  Risk level: ${value.risk_level || 'unknown'}`,\\n    `  Flags: ${flags}`,\\n    `  Reason: ${value.reason || 'n/a'}`,\\n  ].join('\\\\n');\\n}\\n\\nfunction fmtOutputGuardrail(value) {\\n  const r = value && value.result;\\n  if (!r) return '  [no data]';\\n  return [\\n    `  Score: ${r.result}/10 (severity: ${r.severity || 'unknown'})`,\\n    `  Assessment: ${r.description || 'n/a'}`,\\n  ].join('\\\\n');\\n}\\n\\nfunction fmtIntent(value) {\\n  if (!value) return '  [no data]';\\n  if (value.chatInput === 'temp question' && value.intent === undefined) {\\n    return \\"  [NOT AVAILABLE: intent classification result never arrived for this turn -- this is Prepare collected data's hardcoded fallback default, not a real classification]\\";\\n  }\\n  const lines = [];\\n  if (value.intent) lines.push(`  Intent: ${value.intent}`);\\n  if (value.confidence !== undefined) lines.push(`  Confidence: ${value.confidence}`);\\n  if (value.entities) lines.push(`  Entities: ${JSON.stringify(value.entities)}`);\\n  if (lines.length === 0) lines.push('  ' + JSON.stringify(value));\\n  return lines.join('\\\\n');\\n}\\n\\nfunction fmtConceptEnrichment(value) {\\n  const ce = value && value.conceptEnrichment;\\n  if (!ce) return '  [no data]';\\n  const stats = ce.stats || {};\\n  const lines = [];\\n  lines.push(`  Concepts identified: ${stats.totalConcepts ?? '?'} total, ${stats.enrichedConceptsUsed ?? '?'} used for retrieval`);\\n  const concepts = (ce.structuredOutput && ce.structuredOutput.extractedConcepts) || [];\\n  for (const c of concepts) {\\n    const def = (c.definitions && c.definitions[0]) ? ` -- ${c.definitions[0]}` : '';\\n    const parent = (c.parentConcepts && c.parentConcepts[0]) ? ` (parent: ${c.parentConcepts[0].label})` : '';\\n    lines.push(`    - ${c.primaryLabel} [${c.confidenceLevel}, ${c.score}%] ${c.category || ''}${parent}${def}`);\\n  }\\n  const queries = ce.retrievalQueries || [];\\n  if (queries.length) {\\n    lines.push(`  Retrieval queries generated (${queries.length}):`);\\n    for (const q of queries) lines.push(`    - ${q}`);\\n  }\\n  return lines.join('\\\\n');\\n}\\n\\nfunction fmtConceptExpansion(value) {\\n  const er = value && value.expansionResults;\\n  if (!er) return '  [no data]';\\n  const lines = [];\\n  const forLLM = er.forLLM || {};\\n  const mainTopic = forLLM.mainTopic || {};\\n  if (mainTopic.label) {\\n    lines.push(`  Main topic: ${mainTopic.label}${mainTopic.definition ? ' -- ' + mainTopic.definition : ''}`);\\n  }\\n  if (forLLM.keySubtopics && forLLM.keySubtopics.length) {\\n    lines.push(`  Key subtopics: ${forLLM.keySubtopics.map(t => t.label || t).join(', ')}`);\\n  }\\n  if (forLLM.relatedConcepts && forLLM.relatedConcepts.length) {\\n    lines.push(`  Related concepts: ${forLLM.relatedConcepts.map(t => t.label || t).join(', ')}`);\\n  }\\n  if (lines.length === 0) lines.push('  [expansion produced no additional topics for this query]');\\n  return lines.join('\\\\n');\\n}\\n\\nfunction fmtVectorSearch(hits) {\\n  if (!Array.isArray(hits) || hits.length === 0) return '  [no hits]';\\n  const lines = [`  ${hits.length} document(s) retrieved:`];\\n  hits.forEach((hit, i) => {\\n    const meta = hit.metadata || {};\\n    const docName = String(meta.doc_uri || meta.source || hit.source || 'unknown').split('/').pop();\\n    const excerpt = String(meta.text || hit.payload || '').replace(/<br>/g, ' ').replace(/\\\\s+/g, ' ').trim().slice(0, 300);\\n    lines.push(`  ${i + 1}. [score ${(hit.score || 0).toFixed(3)}] ${docName} (chunk ${meta.seq ?? '?'})`);\\n    lines.push(`     \\"${excerpt}${excerpt.length >= 300 ? '...' : ''}\\"`);\\n  });\\n  return lines.join('\\\\n');\\n}\\n\\nfunction fmtGraphdbMcp(value) {\\n  const text = value && value.graphdbMcp && value.graphdbMcp.grpahdbMCPresponse;\\n  if (!text) return '  [no data]';\\n  return text.split('\\\\n').map(l => '  ' + l).join('\\\\n');\\n}\\n\\nfunction fmtShortMemory(value) {\\n  const text = value && value.response;\\n  if (!text) return '  [no summary yet]';\\n  return '  ' + text;\\n}\\n\\nfunction fmtFinalAnswer(value) {\\n  const text = value && value.response;\\n  if (!text) return '  [no data]';\\n  return text.split('\\\\n').map(l => '  ' + l).join('\\\\n');\\n}\\n\\nfunction fmtFollowups(value) {\\n  const list = value && value.followups;\\n  if (!Array.isArray(list) || list.length === 0) return '  [no followups]';\\n  const lines = [];\\n  list.forEach((f, i) => {\\n    lines.push(`  ${i + 1}. ${f.question}`);\\n    if (f.reasoning) lines.push(`     Why: ${f.reasoning}`);\\n    if (f.topics && f.topics.length) lines.push(`     Topics: ${f.topics.join(', ')}`);\\n  });\\n  return lines.join('\\\\n');\\n}\\n\\nconst turnStart       = await readMainFileWithRetry('turn-start');\\nconst inputGuardrails = await readMainFileWithRetry('input-guardrails');\\nconst shortMemory     = await readMainFileWithRetry('short-memory');\\nconst finalAnswer     = await readMainFileWithRetry('final-answer');\\n\\nconst t0 = turnStart ? new Date(turnStart.ts) : null;\\nconst tEnd = finalAnswer ? new Date(finalAnswer.ts) : null;\\nconst totalElapsed = (t0 && tEnd) ? ((tEnd - t0) / 1000).toFixed(2) : 'unknown';\\n\\nconst lines = [];\\nlines.push('=== GraphRAG Chatbot Turn Audit Report ===');\\nlines.push(`Conversation: ${conversationId}`);\\nlines.push(`Question ID:  ${questionId}`);\\nlines.push(`Turn started:  ${turnStart ? turnStart.ts : '[MISSING: main-turn-start]'}`);\\nlines.push(`Turn ended:    ${finalAnswer ? finalAnswer.ts : '[MISSING: main-final-answer]'}`);\\nlines.push(`Total elapsed: ${totalElapsed}s`);\\nlines.push(`Generated:     ${new Date().toISOString()}`);\\nlines.push('');\\n\\nlines.push('[QUESTION]');\\nlines.push(turnStart && turnStart.value && turnStart.value.question ? '  ' + turnStart.value.question : '  [MISSING: main-turn-start]');\\nlines.push('');\\n\\nlines.push('[INPUT GUARDRAILS]');\\nlines.push(inputGuardrails ? fmtGuardrail(inputGuardrails.value) : '  [MISSING: main-input-guardrails]');\\nlines.push('');\\n\\nlines.push('[INTENT CLASSIFICATION]');\\nlines.push(fmtIntent(collected.intentClassification));\\nlines.push('');\\n\\nlines.push('[CONCEPT ENRICHMENT (QUESTION)]');\\nlines.push(fmtConceptEnrichment(collected.concepts));\\nlines.push('');\\n\\nlines.push('[CONCEPT EXPANSION]');\\nlines.push(fmtConceptExpansion(collected.conceptExpansion));\\nlines.push('');\\n\\nlines.push('[VECTOR SEARCH]');\\nlines.push(fmtVectorSearch(collected.vectorHits));\\nlines.push('');\\n\\nlines.push('[GRAPHDB / MCP]');\\nlines.push(fmtGraphdbMcp(collected.graphdb));\\nlines.push('');\\n\\nlines.push('[SHORT-TERM MEMORY]');\\nlines.push(shortMemory ? fmtShortMemory(shortMemory.value) : '  [MISSING: main-short-memory]');\\nlines.push('');\\n\\nlines.push('[FINAL ANSWER]');\\nlines.push(finalAnswer ? fmtFinalAnswer(finalAnswer.value) : '  [MISSING: main-final-answer]');\\nlines.push('');\\n\\nlines.push('--- ANSWER-SIDE PIPELINE (live, from Prepare final data) ---');\\nlines.push('');\\n\\nlet answerItems = [];\\ntry {\\n  answerItems = $('Prepare final data').all().map(i => i.json);\\n} catch (e) {\\n  lines.push(`  [ERROR reading Prepare final data: ${e.message}]`);\\n}\\n\\nconst ANSWER_FORMATTERS = {\\n  'output-guardrails': { title: 'OUTPUT GUARDRAILS', fmt: fmtOutputGuardrail },\\n  'concept-enricher':  { title: 'CONCEPT ENRICHMENT (ANSWER)', fmt: fmtConceptEnrichment },\\n  'followups':         { title: 'FOLLOW-UP QUESTIONS', fmt: fmtFollowups },\\n};\\nconst seenAnswerSteps = new Set();\\nfor (const item of answerItems) {\\n  seenAnswerSteps.add(item.step);\\n  const meta = ANSWER_FORMATTERS[item.step] || { title: item.step, fmt: v => '  ' + JSON.stringify(v) };\\n  lines.push(`[${meta.title}]`);\\n  lines.push(meta.fmt(item.value));\\n  lines.push('');\\n}\\nfor (const key of Object.keys(ANSWER_FORMATTERS)) {\\n  if (!seenAnswerSteps.has(key)) {\\n    lines.push(`[${ANSWER_FORMATTERS[key].title}]`);\\n    lines.push(`  [MISSING: answer-${key}]`);\\n    lines.push('');\\n  }\\n}\\n\\nconst reportText = lines.join('\\\\n');\\nconst reportPath = path.join(dir, 'report.txt');\\n\\nlet written = false;\\nlet error   = null;\\n\\ntry {\\n  fs.mkdirSync(dir, { recursive: true });\\n  fs.writeFileSync(reportPath, reportText, 'utf-8');\\n  written = true;\\n} catch (e) {\\n  error = e.message;\\n  console.log(`[journey-assemble] failed for conversationId=${conversationId} questionId=${questionId}: ${e.message}`);\\n}\\n\\nreturn [{ json: { written, error, file: reportPath } }];\\n"},"typeVersion":2,"name":"Journey: Assemble Report","position":[-1968,1632],"id":"a7158473-9028-4033-84eb-f5ea0e1b0a99","type":"n8n-nodes-base.code","onError":"continueRegularOutput"}]	{"Send Answer Concepts message":{"main":[[{"node":"Loop  iteration point","index":0,"type":"main"}]]},"Loop Over Items":{"main":[[{"node":"PrepareResponse - Success","index":0,"type":"main"},{"node":"Journey: Assemble Report","index":0,"type":"main"}],[{"node":"Switch type","index":0,"type":"main"}]]},"Delete final data for parallel steps":{"main":[[{"node":"Get output guardrails","index":0,"type":"main"}]]},"Configuration":{"main":[[{"node":"Prepare collected data","index":0,"type":"main"}]]},"Activate/Deactivate Answer Concept Details":{"main":[[{"node":"If Answer Concept Details is activated","index":0,"type":"main"}]]},"Get output guardrails":{"main":[[{"node":"LLMUsage-OutputGuardRails","index":0,"type":"main"}]]},"Prepare final data":{"main":[[{"node":"Delete final data for parallel steps","index":0,"type":"main"},{"node":"Journey: Answer Step","index":0,"type":"main"}]]},"Call Output Guardrails Async":{"main":[[{"node":"Increment step counter for short memory step 1