## The main idea of this workflow is to start several steps in Async mode. The synchronization of the results is done by using a dataTable PARALLEL_SYNC_DATA.\\n\\n## To start each step we use the approach [WebHook + respond immediately]\\n\\n## To sync all steps we use a combination of [dataTable (for normal execution) + timeout period ]\\n\\n## In case of errors in some steps - they have a special \\"Error Workflow\\" that makes sure the sync data is written to thedataTable","height":464,"width":1104},"typeVersion":1,"name":"Sticky Note","position":[-7280,-192],"id":"7078d805-5c43-40ef-ba65-1221f9c13ba1","type":"n8n-nodes-base.stickyNote"},{"parameters":{"jsCode":"\\nreturn { \\"questionId\\" : $('When Executed by Another Workflow').first().json.questionId,\\n         \\"conversationId\\" : $('When Executed by Another Workflow').first().json.conversationId,\\n         \\"userId\\" :     $('When Executed by Another Workflow').first().json.userId \\n  }"},"typeVersion":2,"name":"Transfer start variables","position":[1232,-128],"id":"cbd511a9-5ae0-4ed9-b7c3-7a74f481d68a","type":"n8n-nodes-base.code"},{"parameters":{"jsCode":"// Spliced in between Delete data for parallel steps -> Prepare collected data.\\n// Prepare collected data reads its data via named reference to\\n// $('Collect processed data'), NOT via $input -- so this node's own return\\n// value is never consumed by the critical path, and inserting it here\\n// cannot change what Prepare collected data (and therefore Final Answer)\\n// sees. This node only ever writes files as a side effect.\\nlet written = [];\\nlet errors = [];\\n\\ntry {\\n  const trigger = $('When Executed by Another Workflow').first().json;\\n  const conversationId = trigger.conversationId;\\n  const questionId     = trigger.questionId;\\n\\n  const fs   = require('fs');\\n  const path = require('path');\\n  const BASE_DIR = '/data/staging/output/journey';\\n  const safe = s => String(s || 'unknown').replace(/[^a-zA-Z0-9_-]/g, '_');\\n  const dir = path.join(BASE_DIR, safe(conversationId), safe(questionId));\\n\\n  try {\\n    fs.mkdirSync(dir, { recursive: true });\\n  } catch (e) {\\n    errors.push(`mkdir failed: ${e.message}`);\\n  }\\n\\n  const KNOWN_STEPS = ['intent', 'concept-enricher', 'concept-expansion', 'vector-search', 'graphdb-mcp'];\\n\\n  let rows = [];\\n  try {\\n    rows = $('Collect processed data').all();\\n  } catch (e) {\\n    errors.push(`could not read Collect processed data: ${e.message}`);\\n  }\\n\\n  for (const step of KNOWN_STEPS) {\\n    const row = rows.find(r => r.json && r.json.step === step);\\n    if (!row) continue; // step never reported in -- nothing to capture yet\\n    try {\\n      let value = row.json.value;\\n      try { value = JSON.parse(value); } catch (e) { /* already an object */ }\\n      const record = {\\n        ts: new Date().toISOString(),\\n        conversationId,\\n        questionId,\\n        phase: 'question',\\n        step,\\n        type: row.json.type || 'unknown',\\n        value,\\n      };\\n      const filePath = path.join(dir, `question-${step}.json`);\\n      fs.writeFileSync(filePath, JSON.stringify(record, null, 2), 'utf-8');\\n      written.push(step);\\n    } catch (e) {\\n      errors.push(`${step}: ${e.message}`);\\n    }\\n  }\\n} catch (e) {\\n  errors.push(`outer failure: ${e.message}`);\\n}\\n\\nreturn [{ json: { written, errors } }];\\n"},"typeVersion":2,"name":"Journey: Capture Pre-Answer Steps","position":[2400,176],"id":"3f102dd5-97b5-43db-b61f-683cb64a1a2d","type":"n8n-nodes-base.code","onError":"continueRegularOutput"}]	{"Increment step counter for concept enrichment step":{"main":[[{"node":"Call 'PoolParty Concept Enricher (Subworkflow)' Async","index":0,"type":"main"}]]},"Configuration":{"main":[[{"node":"Prepare parallel steps counter","index":0,"type":"main"}]]},"If Concept Expansion is activated":{"main":[[{"node":"Increment step counter for concept expansion step","index":0,"type":"main"}],[{"node":"Activa